@pytest.mark.parametrize(
    ("mutation", "expected_error"),
    [
        ("missing_commit", "full immutable commit_sha"),
        ("wrong_commit", "head_commit must equal commit_sha"),
        ("dirty", "rejects dirty worktree evidence"),
        ("out_of_fence", "contains out-of-fence files"),
        ("wrong_lineage", "implementation_lineage_ref does not match"),
        ("observer_impersonation", "rejects observer impersonation"),
        ("observer_actor", "requires actor_role=mf_sub"),
    ],
)
def test_contract_runtime_worker_commit_proof_rejects_invalid_evidence(
    mutation,
    expected_error,
):
    record, write = _worker_commit_contract_proof()
    actor_role = "mf_sub"
    payload = write["payload"]
    if mutation == "missing_commit":
        write["commit_sha"] = ""
        payload["commit_sha"] = ""
        payload["head_commit"] = ""
        payload["immutable_head_commit"] = ""
        payload["validated_head_commit"] = ""
    elif mutation == "wrong_commit":
        payload["head_commit"] = "b" * 40
    elif mutation == "dirty":
        payload["dirty_files"] = ["agent/governance/server.py"]
    elif mutation == "out_of_fence":
        payload["changed_files"] = [
            "agent/governance/server.py",
            "outside-owned-fence.py",
        ]
        payload["commit_diff_files"] = list(payload["changed_files"])
    elif mutation == "wrong_lineage":
        payload["implementation_lineage_ref"] = (
            "contract-runtime:worker-implementation:sha256:wrong"
        )
    elif mutation == "observer_impersonation":
        payload["observer_impersonation"] = True
    elif mutation == "observer_actor":
        actor_role = "observer"

    errors = _mf_parallel_worker_commit_errors(record, write, actor_role=actor_role)
    assert any(expected_error in error for error in errors)


def test_worker_commit_timeline_alias_only_projects_same_canonical_line():
    lineage = {
        "contract_execution_id": "cex-worker-alias",
        "runtime_context_id": "mfrctx-worker-alias",
        "task_id": "worker-alias-task",
        "stage_id": "worker_implementation",
        "line_id": "worker_implementation",
        "line_instance_id": "runtime_context:mfrctx-worker-alias",
        "evidence_kind": "implementation",
        "implementation_lineage_ref": (
            "contract-runtime:worker-implementation:sha256:canonical"
        ),
        "changed_files": ["agent/governance/server.py"],
        "graph_trace_ids": ["gqt-worker-alias"],
    }
    canonical_line = {
        field: lineage[field]
        for field in (
            "contract_execution_id",
            "runtime_context_id",
            "task_id",
            "stage_id",
            "line_id",
            "line_instance_id",
            "evidence_kind",
        )
    }
    matching_event = {
        "id": 101,
        "payload": {
            "contract_runtime_canonical_line": canonical_line,
            "changed_files": ["agent/governance/server.py"],
            "graph_trace_ids": ["gqt-worker-alias"],
        },
    }
    conflicting_event = {
        "id": 102,
        "payload": {
            "contract_runtime_canonical_line": {
                **canonical_line,
                "line_instance_id": "runtime_context:other",
            },
            "changed_files": ["outside-canonical-line.py"],
            "graph_trace_ids": ["gqt-other-line"],
        },
    }

    assert server._runtime_context_worker_commit_timeline_alias(
        [matching_event],
        implementation_event_ref="timeline:101",
        worker_implementation_lineage=lineage,
    )["status"] == "matching_projection"
    assert server._runtime_context_worker_commit_timeline_alias(
        [matching_event, conflicting_event],
        implementation_event_ref="",
        worker_implementation_lineage=lineage,
    ) == {}
    with pytest.raises(ValidationError, match="does not project the canonical"):
        server._runtime_context_worker_commit_timeline_alias(
            [matching_event, conflicting_event],
            implementation_event_ref="timeline:102",
            worker_implementation_lineage=lineage,
        )


def test_runtime_context_finish_resolves_recorded_commit_and_rejects_later_drift(
    tmp_path,
    monkeypatch,
):
    worktree = tmp_path / "worker-commit-drift"
    worktree.mkdir()
    subprocess.run(["git", "init"], cwd=worktree, check=True, capture_output=True)
    subprocess.run(
        ["git", "config", "user.email", "worker@example.test"],
        cwd=worktree,
        check=True,
    )
    subprocess.run(
        ["git", "config", "user.name", "Worker Commit Test"],
        cwd=worktree,
        check=True,
    )
    owned = worktree / "owned.py"
    owned.write_text("base\n", encoding="utf-8")
    subprocess.run(["git", "add", "owned.py"], cwd=worktree, check=True)
    subprocess.run(["git", "commit", "-m", "base"], cwd=worktree, check=True)
    base_commit = subprocess.run(
        ["git", "rev-parse", "HEAD"],
        cwd=worktree,
        check=True,
        capture_output=True,
        text=True,
    ).stdout.strip()
    owned.write_text("implementation\n", encoding="utf-8")
    subprocess.run(["git", "add", "owned.py"], cwd=worktree, check=True)
    subprocess.run(["git", "commit", "-m", "implementation"], cwd=worktree, check=True)
    worker_commit = subprocess.run(
        ["git", "rev-parse", "HEAD"],
        cwd=worktree,
        check=True,
        capture_output=True,
        text=True,
    ).stdout.strip()
    commit_payload = {
        "runtime_context_id": "mfrctx-drift",
        "task_id": "task-drift",
        "worker_commit_sha": worker_commit,
        "changed_files": ["owned.py"],
        "commit_diff_files": ["owned.py"],
        "commit_parent_sha": base_commit,
        "diff_base_commit": base_commit,
        "owned_files": ["owned.py"],
        "implementation_event_ref": "timeline:202",
        "worker_session_id": "worker-session-drift",
        "graph_trace_ids": ["gqt-drift"],
    }
    monkeypatch.setattr(
        server,
        "_runtime_context_actual_worker_commit_line",
        lambda *_args, **_kwargs: (
            {"line_id": "worker_commit", "commit_sha": worker_commit},
            commit_payload,
        ),
    )
    monkeypatch.setattr(
        server,
        "_runtime_context_contract_requires_worker_commit",
        lambda _conn, contract_execution_id: contract_execution_id == "cex-drift",
    )
    resolution = {
        "schema_version": "runtime_context.contract_execution_resolution.v1",
        "source": "source_backed_contract_runtime_worker_lineage",
        "status": "resolved_source_backed_worker_lineage",
        "contract_execution_id": "cex-drift",
        "fail_closed": False,
    }
    monkeypatch.setattr(
        server,
        "_runtime_context_resolve_contract_execution_identity",
        lambda *_args, **_kwargs: (
            {"contract_execution_id": "cex-drift"},
            resolution,
        ),
    )
    context = SimpleNamespace(
        worktree_path=str(worktree),
        base_commit=base_commit,
        task_id="task-drift",
    )
    kwargs = {
        "project_id": PID,
        "context": context,
        "runtime_context_id": "mfrctx-drift",
        "revision_payload": {},
        "body": {},
        "source": "test.finish",
    }

    projection = server._runtime_context_contract_worker_commit_projection(
        None,
        **kwargs,
    )
    assert projection["worker_commit_sha"] == worker_commit
    assert projection["contract_execution_id"] == "cex-drift"
    assert projection["contract_runtime_execution_resolution"] == resolution

    owned.write_text("dirty after commit\n", encoding="utf-8")
    with pytest.raises(GovernanceError) as dirty:
        server._runtime_context_contract_worker_commit_projection(None, **kwargs)
    assert dirty.value.code == "contract_worker_commit_drift"

    subprocess.run(["git", "add", "owned.py"], cwd=worktree, check=True)
    subprocess.run(["git", "commit", "-m", "later drift"], cwd=worktree, check=True)
    with pytest.raises(GovernanceError) as drift:
        server._runtime_context_contract_worker_commit_projection(None, **kwargs)
    assert drift.value.code == "contract_worker_commit_drift"


def test_same_lane_worker_commit_recovery_requires_bounded_descendant_and_reopens_order(
    tmp_path,
):
    worktree = tmp_path / "same-lane-worker-commit-recovery"
    worktree.mkdir()
    subprocess.run(["git", "init"], cwd=worktree, check=True, capture_output=True)
    subprocess.run(
        ["git", "config", "user.email", "worker@example.test"],
        cwd=worktree,
        check=True,
    )
    subprocess.run(
        ["git", "config", "user.name", "Worker Commit Test"],
        cwd=worktree,
        check=True,
    )
    owned = worktree / "owned.py"
    owned.write_text("base\n", encoding="utf-8")
    subprocess.run(["git", "add", "owned.py"], cwd=worktree, check=True)
    subprocess.run(["git", "commit", "-m", "base"], cwd=worktree, check=True)
    base_commit = subprocess.run(
        ["git", "rev-parse", "HEAD"],
        cwd=worktree,
        check=True,
        capture_output=True,
        text=True,
    ).stdout.strip()
    owned.write_text("implementation\n", encoding="utf-8")
    subprocess.run(["git", "add", "owned.py"], cwd=worktree, check=True)
    subprocess.run(
        ["git", "commit", "-m", "implementation"],
        cwd=worktree,
        check=True,
    )
    worker_commit = subprocess.run(
        ["git", "rev-parse", "HEAD"],
        cwd=worktree,
        check=True,
        capture_output=True,
        text=True,
    ).stdout.strip()
    implementation = {
        "stage_id": "worker_implementation",
        "line_id": "worker_implementation",
        "line_instance_id": "runtime_context:mfrctx-repair",
        "actor_role": "mf_sub",
        "evidence_kind": "implementation",
        "runtime_context_id": "mfrctx-repair",
        "task_id": "task-repair",
        "changed_files": ["owned.py"],
        "graph_trace_ids": ["gqt-repair"],
    }
    record = {
        "contract_execution_id": "cex-repair",
        "contract_id": server.MF_PARALLEL_CONTRACT_ID,
        "runtime_guide": {
            "next_legal_action": {
                "line_id": "worker_finish_time_attestation",
            }
        },
        "completed_lines": [implementation],
    }
    lineage = _worker_implementation_lineage(record, implementation)
    record["completed_lines"].append(
        {
            "stage_id": "worker_commit",
            "line_id": "worker_commit",
            "line_instance_id": "runtime_context:mfrctx-repair",
            "actor_role": "mf_sub",
            "evidence_kind": "worker_commit",
            "runtime_context_id": "mfrctx-repair",
            "task_id": "task-repair",
            "commit_sha": worker_commit,
            "payload": {
                "runtime_context_id": "mfrctx-repair",
                "task_id": "task-repair",
                "worker_commit_sha": worker_commit,
                "changed_files": ["owned.py"],
                "commit_diff_files": ["owned.py"],
                "diff_base_commit": base_commit,
                "owned_files": ["owned.py"],
                "implementation_lineage_ref": lineage[
                    "implementation_lineage_ref"
                ],
                "graph_trace_ids": ["gqt-repair"],
            },
        }
    )
    owned.write_text("bounded repair\n", encoding="utf-8")
    subprocess.run(["git", "add", "owned.py"], cwd=worktree, check=True)
    subprocess.run(
        ["git", "commit", "-m", "bounded repair"],
        cwd=worktree,
        check=True,
    )
    repair_commit = subprocess.run(
        ["git", "rev-parse", "HEAD"],
        cwd=worktree,
        check=True,
        capture_output=True,
        text=True,
    ).stdout.strip()
    context = SimpleNamespace(
        runtime_context_id="mfrctx-repair",
        task_id="task-repair",
        worktree_path=str(worktree),
        base_commit=base_commit,
        owned_files=("owned.py",),
        target_files=("owned.py",),
    )

    recovery = server._runtime_context_same_lane_worker_commit_recovery(
        record,
        context,
    )
    assert recovery["status"] == "eligible"
    assert recovery["recorded_commit_sha"] == worker_commit
    assert recovery["actual_worktree_head_commit"] == repair_commit
    assert recovery["changed_files"] == ["owned.py"]
    assert recovery["append_only_history_preserved"] is True

    reopened = server._runtime_context_row_scoped_finish_head_projection(
        row_scoped_implementation_head_commit=worker_commit,
        current_branch_head_commit=repair_commit,
        contract_worker_commit_required=True,
        canonical_worker_commit_head=worker_commit,
        same_lane_worker_commit_recovery=recovery,
    )
    assert reopened["status"] == "worker_commit_repair_ready"
    assert reopened["next_legal_action"] == "record_worker_commit"

    exact_head = server._runtime_context_row_scoped_finish_head_projection(
        row_scoped_implementation_head_commit=worker_commit,
        current_branch_head_commit=repair_commit,
        contract_worker_commit_required=True,
        canonical_worker_commit_head=repair_commit,
    )
    assert exact_head["status"] == "worker_commit_recorded"
    assert exact_head["next_legal_action"] == (
        "record_finish_time_worker_attestation"
    )

    owned.write_text("dirty widened state\n", encoding="utf-8")
    blocked = server._runtime_context_same_lane_worker_commit_recovery(
        record,
        context,
    )
    assert blocked["status"] == "blocked"
    assert "assigned worktree is dirty" in blocked["errors"]
    stopped = server._runtime_context_row_scoped_finish_head_projection(
        row_scoped_implementation_head_commit=worker_commit,
        current_branch_head_commit=repair_commit,
        contract_worker_commit_required=True,
        canonical_worker_commit_head=worker_commit,
        same_lane_worker_commit_recovery=blocked,
    )
    assert stopped["status"] == "worker_commit_drift_blocked"
    assert stopped["next_legal_action"] == (
        "stop_and_report_worker_commit_drift"
    )


def test_worker_commit_bypass_continuation_preserves_current_candidate_without_pass(monkeypatch):
    candidate_commit, old_commit, base_commit = "b" * 40, "a" * 40, "c" * 40
    runtime_context_id = "mfrctx-worker-commit-bypass"
    task_id = "worker-commit-bypass-task"
    backlog_id = "AC-WORKER-COMMIT-BYPASS-CONTINUATION"
    identity = {"runtime_context_id": runtime_context_id, "task_id": task_id}
    context = SimpleNamespace(
        **identity,
        parent_task_id=backlog_id,
        worktree_path="/worker",
        base_commit=base_commit,
        owned_files=("owned.py",),
    )
    dispatch = {
        "line_id": "observer_dispatch_bounded_workers",
        "payload": {"worker_role": "mf_sub", **identity},
    }
    implementation = {
        "line_id": "worker_implementation",
        "evidence_kind": "implementation",
        "commit_sha": candidate_commit,
        **identity,
        "parent_task_id": backlog_id,
        "payload": {"changed_files": ["owned.py"]},
    }
    bypass = {
        "line_id": "worker_commit",
        "evidence_kind": "contract_line_bypass",
        "status": "waived",
        "no_pass_claim": True,
        "payload": {
            "blocked_evidence_kind": "worker_commit",
            "no_pass_claim": True,
            "evidence_refs": [f"commit:{candidate_commit}"],
        },
    }
    record = {
        "project_id": PID,
        "contract_execution_id": "cex-worker-commit-bypass",
        "contract_id": server.MF_PARALLEL_CONTRACT_ID,
        "completed_lines": [
            dispatch,
            {"line_id": "worker_commit", "commit_sha": old_commit},
            implementation,
            bypass,
        ],
    }
    monkeypatch.setattr(server, "_contract_runtime_contexts_for_dispatch_line", lambda *_a, **_k: [context])
    monkeypatch.setattr(server, "_runtime_context_git_dirty_files", lambda _path: [])
    monkeypatch.setattr(server, "_runtime_context_git_head_commit", lambda _path: candidate_commit)
    monkeypatch.setattr(
        server,
        "_runtime_context_worker_commit_revision_diff",
        lambda *_args, **_kwargs: {
            "parent_commit": base_commit,
            "base_commit": base_commit,
            "changed_files": ["owned.py"],
        },
    )
    policy = {"enabled": True, "candidate_commit_path": "commit_sha", "line_ids": ["worker_commit"]}
    definition = {"system_layer": {"graph_binding_policy": {"candidate_commit_evidence_policy": policy}}}
    monkeypatch.setattr(server, "_contract_runtime_definition_for_record", lambda _record: definition)
    authority = server._contract_runtime_worker_commit_bypass_continuation_authority(
        None, project_id=PID, record=record, request=bypass
    )

    assert authority["server_derived"] is authority["db_verified"] is True
    assert authority["no_pass_claim"] is True
    assert authority["commit_sha"] == candidate_commit
    assert authority["changed_files"] == ["owned.py"]
    assert authority["diff_base_commit"] == base_commit
    assert server._contract_runtime_server_candidate_commit(None, project_id=PID, record=record) == candidate_commit

    forged = json.loads(json.dumps(record))
    forged["completed_lines"][-1]["payload"]["evidence_refs"] = [f"commit:{'f' * 40}"]
    assert server._contract_runtime_worker_commit_bypass_continuation_authority(
        None, project_id=PID, record=forged, request=forged["completed_lines"][-1]
    ) == {}
    assert server._contract_runtime_server_candidate_commit(None, project_id=PID, record=forged) == old_commit


