def test_contract_runtime_worker_implementation_preserves_top_level_lineage_proof():
    record = {
        "project_id": PID,
        "backlog_id": "AC-WORKER-IMPLEMENTATION-LINEAGE",
        "contract_execution_id": "cex-worker-implementation-lineage",
        "definition_hash": _fake_sha("worker-implementation-definition"),
        "instruction_bundle_hash": _fake_sha("worker-implementation-instructions"),
        "execution_state": {"execution_state_revision": 4},
        "runtime_guide": {
            "runtime_guide_hash": _fake_sha("worker-implementation-guide"),
            "next_legal_action": {
                "stage_id": "worker_implementation",
                "line_id": "worker_implementation",
                "evidence_kind": "implementation",
            },
        },
    }
    body = {
        "changed_files": ["agent/governance/server.py"],
        "graph_trace_ids": ["gqt-worker-implementation-lineage"],
        "payload": {
            "runtime_context_id": "mfrctx-worker-implementation-lineage",
            "task_id": "worker-implementation-lineage-task",
        },
    }

    write = server._contract_runtime_line_write_body(
        record,
        body,
        actor_role="mf_sub",
    )

    assert write["changed_files"] == body["changed_files"]
    assert write["graph_trace_ids"] == body["graph_trace_ids"]
    assert write["payload"]["changed_files"] == body["changed_files"]
    assert write["payload"]["graph_trace_ids"] == body["graph_trace_ids"]

    with pytest.raises(ValidationError) as missing:
        server._contract_runtime_line_write_body(
            record,
            {"payload": body["payload"]},
            actor_role="mf_sub",
        )
    assert missing.value.details["missing_proof_fields"] == [
        "changed_files",
        "graph_trace_ids",
    ]
    assert missing.value.details["timeline_evidence_backfill_allowed"] is False

    with pytest.raises(ValidationError, match="conflicts with payload.changed_files"):
        server._contract_runtime_line_write_body(
            record,
            {
                **body,
                "payload": {
                    **body["payload"],
                    "changed_files": ["agent/governance/task_timeline.py"],
                },
            },
            actor_role="mf_sub",
        )


def test_contract_runtime_line_write_body_preserves_safe_qa_evidence_only():
    record = {
        "project_id": PID,
        "backlog_id": "AC-QA-LINE-WRITE-BRIDGE",
        "contract_execution_id": "cex-qa-line-write-bridge",
        "definition_hash": _fake_sha("qa-line-write-bridge-definition"),
        "instruction_bundle_hash": _fake_sha("qa-line-write-bridge-instructions"),
        "execution_state": {"execution_state_revision": 3},
        "runtime_guide": {
            "runtime_guide_hash": _fake_sha("qa-line-write-bridge-guide"),
            "next_legal_action": {
                "stage_id": "qa",
                "line_id": "qa_independent_verification",
                "evidence_kind": "independent_verification",
            },
        },
    }
    safe_evidence = {
        "status": "passed",
        "verdict": "pass",
        "verification": {"result": "passed"},
        "tests": [{"name": "focused", "status": "passed"}],
        "test_results": {"passed": 15, "failed": 0},
        "changed_files": ["agent/governance/server.py"],
        "owned_changed_files": ["agent/governance/server.py"],
        "graph_trace_ids": ["gqt-qa-line-write-bridge"],
        "graph_query_trace_ids": ["gqt-qa-line-write-bridge"],
        "db_verified": True,
        "query_source": "qa",
        "query_purpose": "independent_verification",
    }

    write = server._contract_runtime_line_write_body(
        record,
        {
            **safe_evidence,
            "payload": {"decision": "PASS"},
            "session_token": "raw-worker-token-must-not-persist",
            "qa_session_token": "raw-qa-token-must-not-persist",
            "route_token": {"token": "raw-route-token-must-not-persist"},
            "governance_token": "raw-governance-token-must-not-persist",
        },
        actor_role="qa",
    )

    for field, expected in safe_evidence.items():
        assert write[field] == expected
    assert write["payload"] == {"decision": "PASS"}
    assert {
        "session_token",
        "qa_session_token",
        "route_token",
        "governance_token",
    }.isdisjoint(write)


