def _direct_fix_graph_trace_payload(
    *,
    actor_role: str,
    trace_id: str,
    target_project_root: str,
    backlog_id: str = "",
    contract_execution_id: str = "",
    runtime_context_id: str = "",
    task_id: str = "",
    parent_task_id: str = "",
    candidate_commit_sha: str = "",
) -> dict:
    query_source = {
        "observer": "observer",
        "mf_sub": "mf_subagent",
        "qa": "qa",
    }[actor_role]
    query_purpose = {
        "observer": "observer_scope_build",
        "mf_sub": "subagent_context_build",
        "qa": "independent_verification",
    }[actor_role]
    evidence = {
        "schema_version": "direct_fix_graph_trace_db_evidence.v1",
        "db_verified": True,
        "trace_ids": [trace_id],
        "verified_trace_ids": [trace_id],
        "query_source": query_source,
        "query_purpose": query_purpose,
        "target_project_root": target_project_root,
    }
    if actor_role == "qa":
        candidate_commit = candidate_commit_sha or hashlib.sha1(
            trace_id.encode("utf-8")
        ).hexdigest()
        graph_basis_decision = (
            graph_query_trace.bounded_qa_graph_basis_decision(
                "exact_candidate_snapshot",
                {
                    "canonical_head_commit": candidate_commit,
                    "base_commit_sha": candidate_commit,
                    "candidate_commit_sha": candidate_commit,
                    "canonical_head_relation": "candidate",
                },
            )
        )
        evidence.update(
            {
                "source": "graph_query_traces",
                "project_id": PID,
                "backlog_id": backlog_id,
                "contract_execution_id": contract_execution_id,
                "task_id": task_id,
                "qa_session_id": "ses-qa",
                "qa_principal": "qa",
                "missing_trace_ids": [],
                "identity_mismatches": [],
                "graph_basis": "exact_candidate_snapshot",
                "graph_basis_decision": graph_basis_decision,
                "graph_basis_decision_hash": server.stable_sha256(
                    graph_basis_decision
                ),
                "canonical_base_snapshot_id": f"full-{trace_id}",
                "base_commit_sha": candidate_commit,
                "candidate_commit_sha": candidate_commit,
                "changed_files": [],
                "candidate_diff_hash": (
                    "sha256:" + hashlib.sha256(b"").hexdigest()
                ),
                "changed_files_source": "server_exact_candidate_snapshot",
                "root_identity_hash": _fake_sha(f"{trace_id}:root"),
                "query_root_identity_hash": _fake_sha(
                    f"{trace_id}:query-root"
                ),
                "canonical_project_identity_hash": _fake_sha(
                    f"{trace_id}:canonical-root"
                ),
                "repository_identity_hash": _fake_sha(
                    f"{trace_id}:repository"
                ),
            }
        )
    if actor_role == "mf_sub":
        evidence.update(
            {
                "worker_role": "mf_sub",
                "runtime_context_id": runtime_context_id,
                "task_id": task_id,
                "parent_task_id": parent_task_id,
            }
        )
    return {
        "schema_version": "direct_fix_graph_context.v1",
        "graph_trace_ids": [trace_id],
        "graph_trace_evidence": evidence,
    }


