def _activate_basic_graph(
    conn,
    snapshot_id: str = "full-query-test",
    *,
    project_id: str = PID,
    commit_sha: str = "head",
) -> None:
    snapshot = store.create_graph_snapshot(
        conn,
        project_id,
        snapshot_id=snapshot_id,
        commit_sha=commit_sha,
        snapshot_kind="full",
        graph_json=_graph(),
    )
    store.index_graph_snapshot(
        conn,
        project_id,
        snapshot["snapshot_id"],
        nodes=_graph()["deps_graph"]["nodes"],
        edges=_graph()["deps_graph"]["edges"],
    )
    store.activate_graph_snapshot(conn, project_id, snapshot["snapshot_id"])
    conn.commit()


def _record_test_current_full_reconcile_authority(
    conn,
    *,
    backlog_id: str,
    task_id: str,
    contract_execution_id: str,
    runtime_context_id: str,
    target_project_root: str,
    snapshot_id: str,
    commit_sha: str,
    qa_graph_trace_id: str,
    qa_commit_sha: str,
) -> dict[str, Any]:
    common_payload = {
        "contract_execution_id": contract_execution_id,
        "runtime_context_id": runtime_context_id,
        "task_id": task_id,
    }
    runtime_scope = {
        "project_id": PID,
        "backlog_id": backlog_id,
        "contract_execution_id": contract_execution_id,
        "runtime_context_id": runtime_context_id,
        "task_id": task_id,
    }
    qa_event = task_timeline.record_event(
        conn,
        project_id=PID,
        backlog_id=backlog_id,
        task_id=task_id,
        event_type="independent_verification.completed",
        event_kind="independent_verification",
        phase="verification",
        actor="qa:current-full-fixture",
        status="passed",
        commit_sha=qa_commit_sha,
        payload={
            **common_payload,
            "verified_commit": qa_commit_sha,
            "candidate_commit_sha": qa_commit_sha,
            "graph_trace_ids": [qa_graph_trace_id],
            "graph_query_trace_ids": [qa_graph_trace_id],
        },
    )
    merge_event = task_timeline.record_event(
        conn,
        project_id=PID,
        backlog_id=backlog_id,
        task_id=task_id,
        event_type="merge.live",
        event_kind="merge",
        phase="merge",
        actor="observer:current-full-fixture",
        status="passed",
        commit_sha=commit_sha,
        payload={**common_payload, "merge_commit": commit_sha},
    )
    reconcile_event = task_timeline.record_event(
        conn,
        project_id=PID,
        backlog_id=backlog_id,
        task_id=task_id,
        event_type="graph.reconcile",
        event_kind="reconcile",
        phase="reconcile",
        actor="observer:current-full-fixture",
        status="passed",
        commit_sha=commit_sha,
        payload={**common_payload, "reconcile_mode": "current_full"},
    )
    event_times = (
        (qa_event, "2026-07-11T01:00:00Z"),
        (merge_event, "2026-07-11T01:01:00Z"),
        (reconcile_event, "2026-07-11T01:02:00Z"),
    )
    for event, created_at in event_times:
        conn.execute(
            "UPDATE task_timeline_events SET created_at = ? WHERE id = ?",
            (created_at, int(event["id"])),
        )
        event["created_at"] = created_at
    store.record_current_full_reconcile_provenance(
        conn,
        project_id=PID,
        snapshot_id=snapshot_id,
        target_commit_sha=commit_sha,
        request_id=f"req-{contract_execution_id}",
        request_started_at=str(merge_event["created_at"]),
        route_evidence={
            "schema_version": "graph_current_full_reconcile.route_evidence.v1",
            "authenticated_role": "observer",
            "authentication_source": "test_protected_entrypoint",
            "raw_route_token_persisted": False,
            "protected_action": "graph_current_full_reconcile",
            "contract_execution_id": contract_execution_id,
            "runtime_context_id": runtime_context_id,
            "task_id": task_id,
            "route_token_scope": {
                "project_id": PID,
                "backlog_id": backlog_id,
                "task_id": task_id,
                "runtime_context_id": runtime_context_id,
            },
            "runtime_context_scope": {
                **runtime_scope,
                "source": "parallel_branch_runtime_context",
                "server_derived": True,
            },
        },
        runtime_context_scope=runtime_scope,
        reconcile_event_id=int(reconcile_event["id"]),
        reconcile_event_created_at=str(reconcile_event["created_at"]),
    )
    state = store.current_full_reconcile_state(
        conn,
        PID,
        commit_sha,
        qa_event_id=int(qa_event["id"]),
        qa_event_created_at=str(qa_event["created_at"]),
        merge_event_id=int(merge_event["id"]),
        merge_event_created_at=str(merge_event["created_at"]),
        reconcile_event_id=int(reconcile_event["id"]),
        reconcile_event_created_at=str(reconcile_event["created_at"]),
        expected_task_id=task_id,
        expected_runtime_context_id=runtime_context_id,
        reconcile_task_id=task_id,
        reconcile_runtime_context_id=runtime_context_id,
        allow_taskless=True,
    )
    assert state["db_verified"] is True
    return {
        **state,
        "source": "graph_snapshot_store.current_full_reconcile_state",
        "db_verified": True,
        "live_verified": True,
        "canonical_head_verified": True,
        "active_snapshot_verified": True,
        "graph_reconciled": True,
        "project_id": PID,
        "backlog_id": backlog_id,
        "contract_execution_id": contract_execution_id,
        "runtime_context_id": runtime_context_id,
        "task_id": task_id,
        "target_project_root": target_project_root,
        "merged_commit_sha": commit_sha,
        "reconciled_commit_sha": commit_sha,
        "canonical_head_commit": commit_sha,
        "qa_source_ref": f"timeline:{qa_event['id']}",
        "merge_source_ref": f"timeline:{merge_event['id']}",
        "merge_projection_verified": True,
        "reconcile_source_ref": f"timeline:{reconcile_event['id']}",
    }


def _append_authenticated_qa_verification(
    conn,
    *,
    backlog_id: str,
    task_id: str,
    commit_sha: str,
    snapshot_id: str,
    principal_id: str = "qa:direct-main",
    verification: dict[str, Any] | None = None,
) -> dict:
    _activate_basic_graph(conn, snapshot_id, commit_sha=commit_sha)
    qa_scope_binding_ref = server._qa_scope_binding_ref(
        project_id=PID,
        backlog_id=backlog_id,
        task_id=task_id,
        commit_sha=commit_sha,
    )
    qa_scope = [
        f"backlog:{backlog_id}",
        f"task:{task_id}",
        f"commit:{commit_sha}",
        qa_scope_binding_ref,
    ]
    qa_session = server.role_service.register(
        conn,
        principal_id,
        PID,
        "qa",
        scope=qa_scope,
    )
    conn.commit()
    qa_graph_ctx = _ctx_with_role(
        {"project_id": PID},
        "qa",
        method="POST",
        body={
            "snapshot_id": "active",
            "tool": "query_schema",
            "query_source": "qa",
            "query_purpose": "independent_verification",
            "backlog_id": backlog_id,
            "task_id": task_id,
            "commit_sha": commit_sha,
        },
    )
    qa_graph_ctx._session.update(
        {
            "session_id": qa_session["session_id"],
            "principal_id": principal_id,
            "scope": qa_scope,
        }
    )
    qa_graph = server.handle_graph_governance_query(qa_graph_ctx)
    qa_timeline_ctx = _ctx_with_role(
        {"project_id": PID},
        "qa",
        method="POST",
        body={
            "backlog_id": backlog_id,
            "task_id": task_id,
            "event_type": "qa.independent_verification",
            "event_kind": "independent_verification",
            "phase": "qa",
            "status": "passed",
            "actor": principal_id,
            "commit_sha": commit_sha,
            "verification": verification
            or {
                "tests_run": ["pytest -q agent/tests/test_graph_governance_api.py"],
                "diff_check": {"unexpected_files": []},
                "live_regression": {"status": "passed"},
            },
            "payload": {
                "graph_trace_ids": [qa_graph["trace_id"]],
                "observer_impersonation": False,
            },
        },
    )
    qa_timeline_ctx._session = dict(qa_graph_ctx._session)
    return server.handle_task_timeline_append(qa_timeline_ctx)


def _graph_with_dependency() -> dict:
    graph = _graph("L7.1")
    graph["deps_graph"]["nodes"].append(
        {
            "id": "L7.2",
            "layer": "L7",
            "title": "Dependency Node",
            "kind": "service_runtime",
            "primary": ["agent/governance/dependency.py"],
            "secondary": [],
            "test": [],
            "metadata": {"subsystem": "governance"},
        }
    )
    graph["deps_graph"]["edges"].append(
        {
            "source": "L7.1",
            "target": "L7.2",
            "edge_type": "depends_on",
            "direction": "dependency",
            "evidence": {"source": "test-dependency"},
        }
    )
    return graph


def test_graph_governance_asset_impact_reminders_api_lists_events_and_resolves(conn):
    first = asset_impact.record_asset_impact_detected(
        conn,
        project_id=PID,
        asset_kind="doc",
        asset_path="docs/dev/proposal.md",
        node_id="L7.1",
        node_title="Feature Node",
        commit_sha="c1",
        snapshot_id="s1",
        actor="scope-reconcile",
    )
    second = asset_impact.record_asset_impact_detected(
        conn,
        project_id=PID,
        asset_kind="doc",
        asset_path="docs/dev/proposal.md",
        node_id="L7.1",
        node_title="Feature Node",
        commit_sha="c2",
        snapshot_id="s2",
        actor="scope-reconcile",
    )
    conn.commit()

    queue = server.handle_graph_governance_asset_impact_reminders(
        _ctx(
            {"project_id": PID},
            query={"asset_kind": "doc", "status": "pending"},
        )
    )

    assert queue["ok"] is True
    assert queue["count"] == 1
    assert queue["summary"]["open_event_count"] == 2
    assert "waived" in queue["action_catalog"]["resolution_kinds"]
    reminder = queue["reminders"][0]
    assert reminder["open_event_ids"] == [
        first["event"]["id"],
        second["event"]["id"],
    ]

    history = server.handle_graph_governance_asset_impact_reminder_events(
        _ctx({"project_id": PID, "reminder_id": reminder["reminder_id"]})
    )
    assert history["ok"] is True
    assert history["reminder"]["reminder_id"] == reminder["reminder_id"]
    assert [event["event_type"] for event in history["events"]] == [
        asset_impact.EVENT_IMPACT_DETECTED,
        asset_impact.EVENT_IMPACT_DETECTED,
    ]

    resolved = server.handle_graph_governance_asset_impact_reminder_resolve(
        _ctx(
            {"project_id": PID, "reminder_id": reminder["reminder_id"]},
            method="POST",
            body={
                "resolution_kind": "keep_unchanged",
                "note": "Reviewed in Review Queue.",
                "actor": "dashboard-user",
            },
        )
    )

    assert resolved["ok"] is True
    assert resolved["resolution"]["covers_event_ids"] == reminder["open_event_ids"]
    assert resolved["reminder"]["status"] == asset_impact.STATUS_RECORDED
    resolution_events = [
        event for event in resolved["events"]
        if event["event_type"] == asset_impact.EVENT_RESOLUTION_RECORDED
    ]
    assert len(resolution_events) == 1
    assert resolution_events[0]["actor"] == "dashboard-user"
    assert resolution_events[0]["evidence"]["note"] == "Reviewed in Review Queue."

    resolved_history = server.handle_graph_governance_asset_impact_reminder_events(
        _ctx({"project_id": PID, "reminder_id": reminder["reminder_id"]})
    )
    assert resolved_history["reminder"]["status"] == asset_impact.STATUS_RECORDED
    assert [
        event["event_type"] for event in resolved_history["events"]
    ] == [
        asset_impact.EVENT_IMPACT_DETECTED,
        asset_impact.EVENT_IMPACT_DETECTED,
        asset_impact.EVENT_RESOLUTION_RECORDED,
    ]

    after = server.handle_graph_governance_asset_impact_reminders(
        _ctx(
            {"project_id": PID},
            query={"asset_kind": "doc", "status": "pending"},
        )
    )
    assert after["count"] == 0


def test_graph_governance_asset_inbox_relation_drift_and_proposal_contract(conn):
    graph = _graph("L7.runtime")
    graph["deps_graph"]["nodes"][0]["title"] = "Runtime Service"
    snapshot = store.create_graph_snapshot(
        conn,
        PID,
        snapshot_id="asset-inbox-drift",
        commit_sha="c-drift",
        snapshot_kind="scope",
        graph_json=graph,
        file_inventory=[
            {
                "path": "docs/runtime.md",
                "file_kind": "doc",
                "scan_status": "secondary_attached",
                "graph_status": "attached",
                "attached_node_ids": ["L7.runtime"],
                "mapped_node_ids": ["L7.runtime"],
                "file_hash": "sha256:doc",
            },
            {
                "path": "docs/orphan.md",
                "file_kind": "doc",
                "scan_status": "orphan",
                "graph_status": "unmapped",
                "file_hash": "sha256:orphan",
            },
            {
                "path": "config/runtime.yaml",
                "file_kind": "config",
                "scan_status": "pending_decision",
                "graph_status": "pending_decision",
                "candidate_node_id": "L7.runtime",
                "file_hash": "sha256:config",
            },
        ],
    )
    store.index_graph_snapshot(
        conn,
        PID,
        snapshot["snapshot_id"],
        nodes=graph["deps_graph"]["nodes"],
        edges=[],
    )
    asset_impact.record_asset_impact_detected(
        conn,
        project_id=PID,
        asset_kind="doc",
        asset_path="docs/runtime.md",
        node_id="L7.runtime",
        node_title="Runtime Service",
        commit_sha="c-drift",
        snapshot_id=snapshot["snapshot_id"],
        actor="scope-reconcile",
    )
    conn.commit()

    inbox = server.handle_graph_governance_snapshot_asset_inbox(
        _ctx({"project_id": PID, "snapshot_id": snapshot["snapshot_id"]})
    )

    by_path = {item["path"]: item for item in inbox["items"]}
    assert inbox["ok"] is True
    runtime_doc = by_path["docs/runtime.md"]
    assert runtime_doc["asset_status"] == "impact_pending"
    assert runtime_doc["drift"]["state"] == "suspected"
    assert runtime_doc["drift"]["source"] == "asset_impact_reminder"
    assert runtime_doc["mount_relations"][0]["status"] == "impact_pending"
    assert runtime_doc["mount_relations"][0]["impact_reminder_id"]
    assert "resolve_drift" in runtime_doc["recommended_actions"]

    orphan = by_path["docs/orphan.md"]
    assert orphan["asset_status"] == "doc_unbound"
    assert orphan["mount_relations"][0]["status"] == "unbound"

    config = by_path["config/runtime.yaml"]
    assert config["asset_status"] == "config_pending_decision"
    assert config["mount_relations"][0]["status"] == "candidate"
    assert "write_governance_hint" not in config["batch_eligible_actions"]


def test_backlog_close_response_includes_asset_drift_summary_for_changed_orphan_doc(conn, monkeypatch):
    graph = _graph("L7.external_protocol")
    graph["deps_graph"]["nodes"][0]["title"] = "External Protocol MCP"
