        assert auth["x_gov_token"]["header"] == "X-Gov-Token"
        assert auth["x_gov_token"]["role_required"] == "mf_sub"
        for field_name, expected_value in expected.items():
            if field_name in {
                "method",
                "path",
                "facade_status",
                "auth_session_token_location",
            }:
                continue
            actual_value = interface[field_name]
