    rows = conn.execute(
        """
        SELECT COUNT(*) AS count FROM graph_snapshots
        WHERE project_id=? AND parent_snapshot_id=?
        """,
        (PID, snapshot["snapshot_id"]),
    ).fetchone()
    assert rows["count"] == 0


