def test_qa_candidate_overlay_rejects_wrong_repository_root(tmp_path):
    canonical = create_parallel_fixture_project(
        tmp_path,
        name="qa-overlay-canonical-repository",
    )
    unrelated = create_parallel_fixture_project(
        tmp_path,
        name="qa-overlay-unrelated-repository",
    )
    subprocess.run(
        ["git", "checkout", "-b", "candidate-wrong-root"],
        cwd=canonical.root,
        check=True,
        capture_output=True,
        text=True,
    )
    (canonical.root / "src/candidate.py").write_text(
        "def candidate_entry():\n"
        "    return True\n",
        encoding="utf-8",
    )
    subprocess.run(
        ["git", "add", "src/candidate.py"],
        cwd=canonical.root,
        check=True,
        capture_output=True,
        text=True,
    )
    subprocess.run(
        ["git", "commit", "-m", "wrong root candidate"],
        cwd=canonical.root,
        check=True,
        capture_output=True,
        text=True,
    )
    candidate_commit = batch_jobs.git_commit(canonical.root)
    subprocess.run(
        ["git", "checkout", "main"],
        cwd=canonical.root,
        check=True,
        capture_output=True,
        text=True,
    )

    with pytest.raises(server._QACandidateOverlayError) as exc:
        server._qa_candidate_diff_context(
            unrelated.root,
            project_id=PID,
            canonical_project_root=canonical.root,
            base_commit_sha=canonical.main_head,
            candidate_commit_sha=candidate_commit,
        )
    assert exc.value.reason == "query_root_repository_mismatch"


def test_qa_role_assignment_derives_exact_candidate_scope_binding(conn):
    backlog_id = "AC-QA-ROLE-SCOPE"
    task_id = "qa-role-scope-task"
    commit_sha = "9" * 40

    status, result = server.handle_role_assign(
        _ctx_with_role(
            {},
            "coordinator",
            method="POST",
            body={
                "project_id": PID,
                "principal_id": "qa:lovelace",
                "role": "qa",
                "scope": ["read:graph"],
                "backlog_id": backlog_id,
                "task_id": task_id,
                "commit_sha": commit_sha,
            },
        )
    )

    assert status == 201
    assert result["scope"] == [
        "read:graph",
        f"backlog:{backlog_id}",
        f"task:{task_id}",
        f"commit:{commit_sha}",
        server._qa_scope_binding_ref(
            project_id=PID,
            backlog_id=backlog_id,
            task_id=task_id,
            commit_sha=commit_sha,
        ),
    ]
    stored = conn.execute(
        "SELECT scope_json FROM sessions WHERE session_id = ?",
        (result["session_id"],),
    ).fetchone()
    assert json.loads(stored["scope_json"]) == result["scope"]


def test_qa_role_assignment_rejects_caller_authority_and_refreshes_scope(conn):
    principal_id = "qa:noether"
    first = {
        "project_id": PID,
        "principal_id": principal_id,
        "role": "qa",
        "scope": ["read:graph"],
        "backlog_id": "AC-QA-FIRST",
        "task_id": "qa-first-task",
        "commit_sha": "1" * 40,
    }
    _, registered = server.handle_role_assign(
        _ctx_with_role({}, "coordinator", method="POST", body=first)
    )

    forged = dict(first)
    forged["scope"] = [
        "backlog:AC-FORGED",
        "task:forged-task",
        f"commit:{'f' * 40}",
        "qa_scope:sha256:caller-controlled",
    ]
    with pytest.raises(ValidationError, match="server-derived"):
        server.handle_role_assign(
            _ctx_with_role({}, "coordinator", method="POST", body=forged)
        )

    missing_tuple = dict(first)
    missing_tuple.pop("commit_sha")
    with pytest.raises(ValidationError, match="full commit_sha") as exc:
        server.handle_role_assign(
            _ctx_with_role({}, "coordinator", method="POST", body=missing_tuple)
        )
    compatibility = exc.value.details["mcp_tool_schema_compatibility"]
    assert exc.value.details["missing_fields"] == ["commit_sha"]
    assert exc.value.details["diagnostic"] == "stale_client_or_wrong_call"
    assert compatibility["server_tool_schema_version"] == MCP_TOOL_SCHEMA_VERSION
    assert compatibility["minimum_client_tool_schema_version"] == (
        MCP_TOOL_SCHEMA_VERSION
    )
    assert compatibility["refresh_action"] == "restart_or_refresh_mcp_session"
    assert compatibility["http_fallback"]["path"] == "/api/role/assign"

    second = {
        **first,
        "scope": ["read:graph", "run:tests"],
        "backlog_id": "AC-QA-SECOND",
        "task_id": "qa-second-task",
        "commit_sha": "2" * 40,
    }
    _, refreshed = server.handle_role_assign(
        _ctx_with_role({}, "coordinator", method="POST", body=second)
    )

    assert refreshed["session_id"] == registered["session_id"]
    assert refreshed["scope"] == [
        "read:graph",
        "run:tests",
        "backlog:AC-QA-SECOND",
        "task:qa-second-task",
        f"commit:{'2' * 40}",
        server._qa_scope_binding_ref(
            project_id=PID,
            backlog_id="AC-QA-SECOND",
            task_id="qa-second-task",
            commit_sha="2" * 40,
        ),
    ]
    stored = conn.execute(
        "SELECT scope_json FROM sessions WHERE session_id = ?",
        (registered["session_id"],),
    ).fetchone()
    assert json.loads(stored["scope_json"]) == refreshed["scope"]


def test_bounded_qa_session_rejects_scope_impersonation_and_non_qa_actions(conn):
    backlog_id = "AC-BOUNDED-QA-REJECTIONS"
    task_id = "bounded-qa-rejections-task"
    commit_sha = "b" * 40
    _activate_basic_graph(
        conn,
        "full-query-bounded-qa-rejections",
        commit_sha=commit_sha,
    )
    base_body = {
        "snapshot_id": "active",
        "tool": "query_schema",
        "query_source": "qa",
        "query_purpose": "independent_verification",
        "backlog_id": backlog_id,
        "task_id": task_id,
        "commit_sha": commit_sha,
    }

    with pytest.raises(GovernanceError) as non_qa:
        server.handle_graph_governance_query(
            _ctx_with_role(
                {"project_id": PID},
                "observer",
                method="POST",
                body=base_body,
            )
        )
    assert non_qa.value.code == "qa_session_required"

    wrong_scope = _ctx_with_role(
        {"project_id": PID},
        "qa",
        method="POST",
        body=base_body,
    )
    wrong_scope._session["scope"] = [
        f"backlog:{backlog_id}",
        f"task:{task_id}",
        f"commit:{'c' * 40}",
    ]
    with pytest.raises(GovernanceError) as scope_violation:
        server.handle_graph_governance_query(wrong_scope)
    assert scope_violation.value.code == "qa_session_scope_violation"

    impersonating = _ctx_with_role(
        {"project_id": PID},
        "qa",
        method="POST",
        body={**base_body, "on_behalf_of": "observer:parent"},
    )
    impersonating._session["scope"] = [
        f"backlog:{backlog_id}",
        f"task:{task_id}",
        f"commit:{commit_sha}",
    ]
    with pytest.raises(GovernanceError) as impersonation:
        server.handle_graph_governance_query(impersonating)
    assert impersonation.value.code == "qa_observer_impersonation_forbidden"

    qa_implementation = _ctx_with_role(
        {"project_id": PID},
        "qa",
        method="POST",
        body={
            "backlog_id": backlog_id,
            "task_id": task_id,
            "event_type": "implementation",
            "event_kind": "implementation",
            "phase": "implementation",
            "actor": "qa-principal",
            "status": "passed",
            "commit_sha": commit_sha,
            "payload": {"changed_files": ["agent/governance/server.py"]},
        },
    )
    qa_implementation._session["scope"] = [
        f"backlog:{backlog_id}",
        f"task:{task_id}",
        f"commit:{commit_sha}",
    ]
    with pytest.raises(GovernanceError) as action_not_allowed:
        server.handle_task_timeline_append(qa_implementation)
    assert action_not_allowed.value.code == "qa_session_action_not_allowed"


def test_bounded_qa_graph_query_rejects_stale_snapshot_and_cross_product_scope(conn):
    backlog_id = "AC-BOUNDED-QA-SNAPSHOT"
    task_id = "bounded-qa-snapshot-task"
    candidate_commit = "d" * 40
    stale_commit = "e" * 40
    _activate_basic_graph(
        conn,
        "full-query-bounded-qa-stale",
        commit_sha=stale_commit,
    )
    binding_ref = server._qa_scope_binding_ref(
        project_id=PID,
        backlog_id=backlog_id,
        task_id=task_id,
        commit_sha=candidate_commit,
    )
    body = {
        "snapshot_id": "active",
        "tool": "query_schema",
        "query_source": "qa",
        "query_purpose": "independent_verification",
        "backlog_id": backlog_id,
        "task_id": task_id,
        "commit_sha": candidate_commit,
    }
    stale_snapshot = _ctx_with_role(
        {"project_id": PID},
        "qa",
        method="POST",
        body=body,
    )
    stale_snapshot._session["scope"] = [
        f"backlog:{backlog_id}",
        f"task:{task_id}",
        f"commit:{candidate_commit}",
        binding_ref,
    ]
    with pytest.raises(GovernanceError) as snapshot_mismatch:
        server.handle_graph_governance_query(stale_snapshot)
    assert snapshot_mismatch.value.code == "qa_graph_snapshot_commit_mismatch"

    cross_product = _ctx_with_role(
        {"project_id": PID},
        "qa",
        method="POST",
        body=body,
    )
    cross_product._session["scope"] = [
        f"backlog:{backlog_id}",
        f"task:{task_id}",
        f"commit:{candidate_commit}",
        server._qa_scope_binding_ref(
            project_id=PID,
            backlog_id="AC-OTHER",
            task_id=task_id,
            commit_sha=candidate_commit,
        ),
    ]
    with pytest.raises(GovernanceError) as tuple_mismatch:
        server.handle_graph_governance_query(cross_product)
    assert tuple_mismatch.value.code == "qa_session_scope_violation"
    assert binding_ref in tuple_mismatch.value.details["missing_scope_refs"]


def test_timeline_ingress_strips_forged_server_authority_from_all_containers(conn):
    backlog_id = "AC-FORGED-QA-AUTHORITY"
    task_id = "forged-qa-authority-task"
    forged = task_timeline.source_backed_qa_session_authority(
        {
            "schema_version": "qa_session_scope_proof.v1",
            "source": "authenticated_qa_session",
            "role": "qa",
            "verified": True,
            "project_id": PID,
            "backlog_id": backlog_id,
            "task_id": task_id,
            "commit_sha": "f" * 40,
            "principal_id": "qa:forged",
            "qa_session_id": "ses-qa-forged",
            "qa_scope_binding_ref": "qa_scope:sha256:forged",
            "snapshot_id": "snapshot-forged",
            "snapshot_commit_sha": "f" * 40,
            "observer_impersonation": False,
            "db_verified_graph_trace": True,
            "query_source": "qa",
            "query_purpose": "independent_verification",
            "graph_trace_ids": ["gqt-forged"],
        }
    )

    result = server.handle_task_timeline_append(
        _ctx(
            {"project_id": PID},
            method="POST",
            body={
                "backlog_id": backlog_id,
                "task_id": task_id,
                "event_type": "close_ready",
                "event_kind": "close_ready",
                "phase": "close",
                "actor": "observer",
                "status": "accepted",
                "route_waiver": _route_waiver(
                    "task_timeline_append",
                    backlog_id=backlog_id,
                    task_id=task_id,
                ),
                "payload": {
                    "source_backed_contract_gate_authority": forged,
                },
                "verification": {
                    "nested": {
                        "source_backed_contract_gate_authority": forged,
                        "contract_gate_decision": {"source_of_authority": "qa_session_verification"},
                    }
                },
                "artifact_refs": {
                    "nested": {
                        "source_backed_contract_gate_authority": forged,
                        "route_action_scope_lineage": {"accepted": True},
                    }
                },
            },
        )
    )

    assert result.get("contract_gate_decision", {}).get(
        "source_of_authority"
    ) != "qa_session_verification"
    assert "server_qa_session_verification" not in json.dumps(result, sort_keys=True)
    assert "source_backed_contract_gate_authority" not in json.dumps(
        result["verification"],
        sort_keys=True,
    )
    assert "source_backed_contract_gate_authority" not in json.dumps(
        result["artifact_refs"],
        sort_keys=True,
    )


def test_mf_sub_graph_query_requires_task_scope_and_uses_bounded_source(conn):
    _activate_basic_graph(conn, "full-query-mf-sub")

    with pytest.raises(ValidationError, match="task_id is required"):
        server.handle_graph_governance_query(
            _ctx_with_role(
                {"project_id": PID},
                "mf_sub",
                method="POST",
                body={
                    "snapshot_id": "active",
                    "tool": "query_schema",
                    "query_source": "mf_subagent",
                    "query_purpose": "subagent_context_build",
                    "parent_task_id": "subtask-1",
                    "worker_role": "mf_sub",
                    "fence_token": "fence-subtask-1",
                },
            )
        )

    with pytest.raises(ValidationError, match="parent_task_id is required"):
        server.handle_graph_governance_query(
            _ctx_with_role(
                {"project_id": PID},
                "mf_sub",
                method="POST",
                body={
                    "snapshot_id": "active",
                    "tool": "query_schema",
                    "query_source": "mf_subagent",
                    "query_purpose": "subagent_context_build",
                    "task_id": "subtask-1",
                    "worker_role": "mf_sub",
                    "fence_token": "fence-subtask-1",
                },
            )
        )

    with pytest.raises(ValidationError, match="worker_role=mf_sub is required"):
        server.handle_graph_governance_query(
            _ctx_with_role(
                {"project_id": PID},
                "mf_sub",
                method="POST",
                body={
                    "snapshot_id": "active",
                    "tool": "query_schema",
                    "query_source": "mf_subagent",
                    "query_purpose": "subagent_context_build",
                    "task_id": "subtask-1",
                    "parent_task_id": "parent-task-1",
                    "fence_token": "fence-subtask-1",
                },
            )
        )

    with pytest.raises(ValidationError, match="fence_token is required"):
        server.handle_graph_governance_query(
            _ctx_with_role(
                {"project_id": PID},
                "mf_sub",
                method="POST",
                body={
                    "snapshot_id": "active",
                    "tool": "query_schema",
                    "query_source": "mf_subagent",
                    "query_purpose": "subagent_context_build",
                    "task_id": "subtask-1",
                    "parent_task_id": "parent-task-1",
                    "worker_role": "mf_sub",
                },
            )
        )

    with pytest.raises(server.GovernanceError) as unsupported_purpose:
        server.handle_graph_governance_query(
            _ctx_with_role(
                {"project_id": PID},
                "mf_sub",
                method="POST",
                body={
                    "snapshot_id": "active",
                    "tool": "query_schema",
                    "query_source": "mf_subagent",
                    "query_purpose": "observer_private_context",
                    "task_id": "subtask-1",
                    "parent_task_id": "parent-task-1",
                    "worker_role": "mf_sub",
                    "fence_token": "fence-subtask-1",
                },
            )
        )
    assert unsupported_purpose.value.code == (
        "unsupported_mf_subagent_graph_query_purpose"
    )

    upsert_branch_context(
        conn,
        BranchTaskRuntimeContext(
            project_id=PID,
            task_id="subtask-1",
            root_task_id="parent-task-1",
            stage_task_id="subtask-1",
            worker_id="mf-worker-1",
            branch_ref="refs/heads/codex/subtask-1",
            status="worktree_ready",
            fence_token="fence-subtask-1",
        ),
    )
    conn.commit()

    queried = server.handle_graph_governance_query(
        _ctx_with_role(
            {"project_id": PID},
            "mf_sub",
            method="POST",
            body={
                "snapshot_id": "active",
                "tool": "query_schema",
                "query_source": "mf_subagent",
                "query_purpose": "subagent_context_build",
                "task_id": "subtask-1",
                "parent_task_id": "parent-task-1",
                "worker_role": "mf_sub",
                "fence_token": "fence-subtask-1",
            },
        )
    )

    assert queried["ok"] is True
    assert "mf_subagent" in queried["result"]["query_sources"]
    fetched = server.handle_graph_governance_query_trace_get(
        _ctx_with_role(
            {"project_id": PID, "trace_id": queried["trace_id"]},
            "mf_sub",
        )
    )
    assert fetched["trace"]["query_source"] == "mf_subagent"
    assert fetched["trace"]["parent_task_id"] == "parent-task-1"


def test_mf_sub_graph_query_resolves_runtime_context_and_route_identity(
    conn,
    tmp_path,
):
    _activate_basic_graph(conn, "full-query-mf-sub-runtime-context")
    target_root = tmp_path / "target-runtime-context"
    target_root.mkdir()
    context = upsert_branch_context(
        conn,
        BranchTaskRuntimeContext(
            project_id=PID,
            governance_project_id=PID,
            target_project_id=PID,
            target_project_root=str(target_root),
            task_id="worker-runtime-context",
            root_task_id="parent-runtime-context",
            backlog_id="AC-RUNTIME-CONTEXT-GRAPH-QUERY",
            stage_task_id="worker-runtime-context",
            worker_id="worker-runtime-context",
            worker_slot_id="worker-runtime-context",
            branch_ref="refs/heads/codex/worker-runtime-context",
            status="worktree_ready",
            fence_token="fence-runtime-context",
            session_token_hash=mf_subagent_session_token_hash(
                "session-runtime-context"
            ),
        ),
    )
    route_identity = {
        "route_id": "route-runtime-context",
        "route_context_hash": "sha256:route-runtime-context",
        "prompt_contract_id": "rprompt-runtime-context",
        "prompt_contract_hash": "sha256:prompt-runtime-context",
        "route_token_ref": "rtok-runtime-context",
        "visible_injection_manifest_hash": "sha256:visible-runtime-context",
    }
    append_branch_contract_revision(
        conn,
        context,
        revision_id="crev-runtime-context-graph-query",
        payload={"target_files": ["agent/governance/server.py"]},
        route_identity=route_identity,
    )
    conn.commit()

    body = {
        "snapshot_id": "active",
        "tool": "query_schema",
        "query_source": "mf_subagent",
        "query_purpose": "subagent_context_build",
        "runtime_context_id": context.runtime_context_id,
        "fence_token": "fence-runtime-context",
        "session_token": "session-runtime-context",
        "target_project_root": str(target_root),
        **route_identity,
    }
    with pytest.raises(GovernanceError) as missing_read_receipt:
        server.handle_graph_governance_query(
            _ctx_with_role(
                {"project_id": PID},
                "mf_sub",
                method="POST",
                body=body,
            )
        )
    assert missing_read_receipt.value.code == "runtime_context_sequence_incomplete"
    assert missing_read_receipt.value.details["next_legal_action"] == (
        "submit_mf_subagent_read_receipt"
    )
    assert missing_read_receipt.value.details["recoverable"] is True
    assert missing_read_receipt.value.details["diagnostics"]["expected"][
        "target_project_root"
    ] == str(target_root)
    read_recovery = missing_read_receipt.value.details
    assert read_recovery["actionable_payloads"]["runtime_context_id"] == (
        context.runtime_context_id
    )
    assert read_recovery["actionable_payloads"]["worker_slot_id"] == (
        "worker-runtime-context"
    )
    assert read_recovery["actionable_payloads"]["route_token_ref"] == (
        "rtok-runtime-context"
    )
    assert read_recovery["actionable_payloads"]["endpoints"][
        "runtime_context_read_receipts"
    ]["tool"] == "submit_mf_subagent_read_receipt"
    receipt_skeleton = read_recovery["read_receipt_facade_payload_skeleton"]
    assert receipt_skeleton["path"].endswith(
        f"/runtime-contexts/{context.runtime_context_id}/read-receipts"
    )
    assert receipt_skeleton["body"]["session_token"].startswith("<read from env:")
    assert receipt_skeleton["body"]["fence_token"].startswith("<read from env:")
    assert receipt_skeleton["top_level_body_required"] is True
    assert receipt_skeleton["copy_safe_body"] == receipt_skeleton["body"]
    assert "nested_payload_only_identity" in receipt_skeleton["forbidden_shapes"]
    assert (
        "worktree_path_as_target_project_root_for_write_facades"
        in receipt_skeleton["forbidden_shapes"]
    )
    assert receipt_skeleton["field_pointers"]["top_level_post_json"].endswith(
        "copy_safe_body"
    )
    assert receipt_skeleton["copy_safe_body"]["task_id"] == "worker-runtime-context"
    assert receipt_skeleton["copy_safe_body"]["worker_id"] == "worker-runtime-context"
    assert receipt_skeleton["copy_safe_body"]["worker_slot_id"] == (
        "worker-runtime-context"
    )
    for field, value in route_identity.items():
        assert receipt_skeleton["copy_safe_body"][field] == value
        assert field in receipt_skeleton["required_fields"]
    assert receipt_skeleton["payload"]["target_project_root"] == str(target_root)
    assert "session-runtime-context" not in json.dumps(
        read_recovery,
        sort_keys=True,
    )
    assert "fence-runtime-context" not in json.dumps(read_recovery, sort_keys=True)

    read_receipt = task_timeline.record_event(
        conn,
        project_id=PID,
        task_id="worker-runtime-context",
        backlog_id="AC-RUNTIME-CONTEXT-GRAPH-QUERY",
        event_type="mf_subagent_read_receipt",
        event_kind="mf_subagent_read_receipt",
        phase="startup_read_receipt",
        status="ok",
        payload={
            "runtime_context_id": context.runtime_context_id,
            "task_id": "worker-runtime-context",
            "parent_task_id": "parent-runtime-context",
            "read_receipt_hash": "sha256:read-runtime-context",
        },
    )
    conn.commit()
    with pytest.raises(GovernanceError) as missing_startup:
        server.handle_graph_governance_query(
            _ctx_with_role(
                {"project_id": PID},
                "mf_sub",
                method="POST",
                body=body,
            )
        )
    assert missing_startup.value.code == "runtime_context_sequence_incomplete"
    assert missing_startup.value.details["next_legal_action"] == (
        "record_mf_subagent_startup"
    )
    startup_skeleton = missing_startup.value.details[
        "startup_facade_payload_skeleton"
    ]
    assert startup_skeleton["legacy_tool"] == "parallel_branch_startup"
    assert startup_skeleton["path"].endswith(
        f"/runtime-contexts/{context.runtime_context_id}/startup"
    )
    assert "actual_host_worker_id" in startup_skeleton[
        "required_real_worker_identity_fields"
    ]
    assert "host_startup_id" in startup_skeleton[
        "required_real_worker_identity_fields"
    ]
    assert "host_session_id" in startup_skeleton[
        "required_real_worker_identity_fields"
    ]
    assert startup_skeleton["body"]["worker_session_id"] == (
        "<actual worker-owned session id>"
    )
    assert startup_skeleton["body"]["target_project_root"] == str(target_root)
    assert missing_startup.value.details["actionable_payloads"]["endpoints"][
        "runtime_context_startup"
    ]["tool"] == "record_mf_subagent_startup"

    task_timeline.record_event(
        conn,
        project_id=PID,
        task_id="worker-runtime-context",
        backlog_id="AC-RUNTIME-CONTEXT-GRAPH-QUERY",
        event_type="mf_subagent.startup",
        event_kind="mf_subagent_startup",
        phase="startup_gate",
        status="passed",
        payload={
            "mf_subagent_startup_gate": {
                "runtime_context_id": context.runtime_context_id,
                "task_id": "worker-runtime-context",
                "parent_task_id": "parent-runtime-context",
                "fence_token_present": True,
                "status": "passed",
                "actual_startup_recorded": True,
                "actual_cwd": str(target_root),
                "actual_git_root": str(target_root),
                "worktree_path": str(target_root),
                "worker_role": "mf_sub",
                "worker_id": "worker-runtime-context",
                "read_receipt_event_id": read_receipt["id"],
                "read_receipt_hash": "sha256:read-runtime-context",
                **route_identity,
            }
        },
    )
    conn.commit()
    queried = server.handle_graph_governance_query(
        _ctx_with_role(
            {"project_id": PID},
            "mf_sub",
            method="POST",
            body=body,
        )
    )

    assert queried["ok"] is True
    fetched = server.handle_graph_governance_query_trace_get(
        _ctx_with_role(
            {"project_id": PID, "trace_id": queried["trace_id"]},
            "mf_sub",
        )
    )
    trace = fetched["trace"]
    assert trace["query_source"] == "mf_subagent"
    assert trace["runtime_context_id"] == context.runtime_context_id
    assert trace["task_id"] == "worker-runtime-context"
    assert trace["parent_task_id"] == "parent-runtime-context"
    assert trace["worker_role"] == "mf_sub"
    assert trace["graph_query_identity"]["fence_token_redacted"] is True
    assert "session-runtime-context" not in json.dumps(trace, sort_keys=True)

    with pytest.raises(GovernanceError) as mismatched_task:
        server.handle_graph_governance_query(
            _ctx_with_role(
                {"project_id": PID},
                "mf_sub",
                method="POST",
                body={**body, "task_id": "other-runtime-task"},
            )
        )
    assert mismatched_task.value.code == "fence_invalidated_or_unknown"
    assert mismatched_task.value.details["reason"] == "runtime_context_task_mismatch"

    with pytest.raises(GovernanceError) as mismatched_route:
        server.handle_graph_governance_query(
            _ctx_with_role(
                {"project_id": PID},
                "mf_sub",
                method="POST",
                body={**body, "route_context_hash": "sha256:wrong-route"},
            )
        )
    assert mismatched_route.value.code == "fence_invalidated_or_unknown"
    assert mismatched_route.value.details["reason"] == "route_identity_mismatch"
    assert mismatched_route.value.details["route_identity_mismatches"] == [
        {
            "field": "route_context_hash",
            "expected": "sha256:route-runtime-context",
            "actual": "sha256:wrong-route",
        }
    ]


def test_runtime_context_current_state_and_guide_expose_session_token_lease(
    conn,
    tmp_path,
):
    target_root = tmp_path / "runtime-lease-current"
    target_root.mkdir()
    context = upsert_branch_context(
        conn,
        BranchTaskRuntimeContext(
            project_id=PID,
            governance_project_id=PID,
            target_project_id=PID,
            target_project_root=str(target_root),
            task_id="worker-runtime-lease",
            root_task_id="parent-runtime-lease",
            backlog_id="AC-RUNTIME-LEASE-CURRENT",
            stage_task_id="worker-runtime-lease",
            worker_id="worker-runtime-lease",
            worker_slot_id="worker-runtime-lease",
            branch_ref="refs/heads/codex/worker-runtime-lease",
            status=STATE_WORKTREE_READY,
            fence_token="fence-runtime-lease",
            session_token_hash=mf_subagent_session_token_hash("runtime-lease-token"),
            lease_id="lease-runtime-current",
            lease_expires_at="2999-01-01T00:00:00Z",
        ),
    )
    route_identity = {
        "route_id": "route-runtime-lease",
        "route_context_hash": "sha256:route-runtime-lease",
        "prompt_contract_id": "rprompt-runtime-lease",
        "prompt_contract_hash": "sha256:prompt-runtime-lease",
        "route_token_ref": "rtok-runtime-lease",
        "visible_injection_manifest_hash": "sha256:visible-runtime-lease",
    }
    append_branch_contract_revision(
        conn,
        context,
        revision_id="crev-runtime-lease",
        payload={"target_files": ["agent/governance/server.py"]},
        route_identity=route_identity,
    )
    conn.commit()
    query = {
        "parent_task_id": "parent-runtime-lease",
        "fence_token": "fence-runtime-lease",
        "session_token": "runtime-lease-token",
        "target_project_root": str(target_root),
        "view": "all",
    }

    current = server.handle_graph_governance_parallel_branch_runtime_context_current_state(
        _ctx_with_role(
            {"project_id": PID, "runtime_context_id": context.runtime_context_id},
            "mf_sub",
            query=query,
        )
    )
    worker_view = current["runtime_context_service"]["views"]["worker_view"]

    assert current["session_token_lease"]["lease_id"] == "lease-runtime-current"
    assert current["session_token_lease"]["expired"] is False
    assert current["session_token_lease"]["raw_session_token_persisted"] is False
    assert worker_view["session_token_lease"] == current["session_token_lease"]
    graph_payload = worker_view["graph_query_identity"]["payload_shape"]
    assert graph_payload["runtime_context_id"] == context.runtime_context_id
    assert graph_payload["target_project_root"] == str(target_root)
    assert graph_payload["project_root"] == str(target_root)
    assert graph_payload["repo_root"] == str(target_root)
    assert graph_payload["route_identity"]["route_token_ref"] == "rtok-runtime-lease"
    current_qa_guide = current["executable_contract"][
        "independent_verification_runtime"
    ]
    assert current_qa_guide["role"] == "qa"
    assert current_qa_guide["raw_route_token_required"] is False
    current_plan = current_qa_guide["verification_plan"]
    assert current_plan["default_strategy"] == (
        "focused_then_guarded_full_suite_if_required"
    )
    assert current_plan["focused"]["required"] is True
    assert current_plan["full_suite"]["required_by_default"] is False
    assert current_plan["full_suite"]["single_process_agent_tests_default"] is False
