def test_runtime_context_qa_guide_scopes_verification_and_full_suite_caveat() -> None:
    target_files = [
        "agent/governance/server.py",
        "agent/governance/contracts/runtime.py",
        "agent/governance/contract_state_runtime.py",
        "agent/governance/mcp_server.py",
        "agent/tests/test_contract_runtime.py",
        "agent/tests/test_graph_governance_api.py",
        "agent/tests/test_parallel_branch_runtime.py",
        "agent/tests/test_mcp_server_stdio.py",
    ]
    expected_target_files = [
        "agent/governance/server.py",
        "agent/governance/contracts/runtime.py",
        "agent/governance/contract_state_runtime.py",
        "agent/governance/mcp_server.py",
        "agent/tests/test_contract_runtime_min_path.py",
        "agent/tests/test_graph_governance_api.py",
        "agent/tests/test_parallel_branch_runtime.py",
        "agent/tests/test_mcp_server_stdio.py",
    ]
    expected_test_files = [
        "agent/tests/test_contract_runtime_min_path.py",
        "agent/tests/test_graph_governance_api.py",
        "agent/tests/test_parallel_branch_runtime.py",
        "agent/tests/test_mcp_server_stdio.py",
    ]
    expected_focused_command = (
        "PYTHONDONTWRITEBYTECODE=1 python -m pytest -p no:cacheprovider "
        + " ".join(expected_test_files)
    )

    guide = server._runtime_context_qa_verification_guide(
        project_id=PID,
        runtime_context_id="mfrctx-qa-scoped",
        task_id="mf-batch:row:2",
        backlog_id="AC-QA-SCOPED-VERIFICATION-FULL-SUITE-GUIDE-20260706",
        parent_task_id="mf-batch-parent",
        target_project_root="/tmp/qa-scoped",
        route_identity={
            "route_id": "route-qa-scoped",
            "route_context_hash": "sha256:qa-scoped",
            "prompt_contract_id": "rprompt-qa-scoped",
            "prompt_contract_hash": "sha256:qa-scoped-prompt",
            "route_token_ref": "rtok-qa-scoped",
            "visible_injection_manifest_hash": "sha256:qa-scoped-visible",
        },
        target_files=target_files,
    )

    plan = guide["verification_plan"]
    assert plan["schema_version"] == "runtime_context.qa_scoped_verification_plan.v1"
    assert plan["target_files"] == expected_target_files
    assert plan["scoped_test_files"] == expected_test_files
    assert plan["suggested_test_files"] == [
        "agent/tests/test_contract_runtime_min_path.py"
    ]
    assert plan["replacement_test_files"] == [
        "agent/tests/test_contract_runtime_min_path.py"
    ]
    assert plan["focused"]["commands"] == [expected_focused_command]
    assert plan["focused"]["commands"] != [plan["full_suite"]["command"]]
    assert plan["full_suite"]["required_by_default"] is False
    assert plan["full_suite"]["default_hard_close_gate"] is False
    assert plan["full_suite"]["single_process_agent_tests_default"] is False
    assert plan["full_suite"]["sharded_plan"]["preferred"] is True
    assert plan["full_suite"]["sharded_plan"]["shard_count"] == 4
    assert all(
        "<agent/tests shard " in command
        for command in plan["full_suite"]["sharded_plan"]["commands"]
    )
    assert plan["full_suite"]["guardrails"]["timeout_seconds_per_shard"] == 900
    assert (
        plan["full_suite"]["guardrails"][
            "stop_on_runaway_without_marking_source_failure"
        ]
        is True
    )
    linked_reporting = guide["linked_bypass_diagnostic_reporting"]
    assert linked_reporting["applicable"] is False
    assert linked_reporting["normal_qa_graph_requirements_unchanged"] is True
    assert "copy_safe_provenance_shape" not in linked_reporting

    append_evidence = guide["append_evidence"]
    assert append_evidence["status_policy"] == {
        "close_satisfying": [
            "accepted",
            "ok",
            "pass",
            "passed",
            "succeeded",
            "success",
        ],
        "persisted_audit_only": ["blocked", "fail", "failed", "rejected"],
        "missing_or_unknown": "rejected",
        "passing_status_required_for_close": True,
    }
    assert append_evidence["failed_audit_body"]["status"] == "failed"
    assert append_evidence["safe_retry"] == {
        "scope": "authenticated_qa_exact_authority",
        "same_authority_returns_existing_event": True,
        "conflicting_status_actor_commit_or_authority_deduplicated": False,
        "intended_for_ambiguous_timeout_retry": True,
    }
    assert append_evidence["reverification_policy"] == {
        "cache_scope": "request_local_success_only",
        "identical_review_context_reverified_once_per_request": True,
        "every_trace_identity_and_scope_still_verified": True,
        "failed_reverification_cached": False,
        "historical_descendant_overlay_audit_only": True,
        "historical_descendant_overlay_close_satisfying": False,
        "historical_pass_requires_stronger_provenance": True,
    }
    assert append_evidence["credential_scrub_policy"] == {
        "applied_before_authority_projection": True,
        "containers": ["payload", "verification", "artifact_refs"],
        "key_matching": "case_and_separator_normalized_exact_denylist",
        "recursive": True,
        "raw_credential_field_classes": [
            "authorization",
            "api_key",
            "cookie",
            "password_or_secret",
            "qa_or_governance_or_worker_token",
        ],
        "copy_safe_refs_hashes_and_provenance_preserved": True,
    }
    assert append_evidence["route_token_ref_body"]["verification"][
        "verification_plan"
    ]["focused_commands"] == [expected_focused_command]
    assert append_evidence["qa_child_route_token_ref_body"]["verification"][
        "verification_plan"
    ]["full_suite_required_by_default"] is False
    assert "test_contract_runtime.py" not in json.dumps(guide, sort_keys=True)

    caveat_body = append_evidence["focused_pass_with_full_suite_caveat_body"]
    assert caveat_body["status"] == "passed"
    assert caveat_body["payload"]["focused_verification"]["commands"] == [
        expected_focused_command
    ]
    caveat = caveat_body["verification"]["full_suite_caveat"]
    assert caveat["schema_version"] == (
        "runtime_context.qa_full_suite_environment_caveat.v1"
    )
    assert caveat["classifies_source_row_failure"] is False
    assert caveat["focused_pass_remains_valid"] is True
    assert {
        "attempted_command",
        "shard_id_or_full_suite",
        "elapsed_seconds",
        "last_progress_at",
        "resource_observation",
        "focused_tests_passed",
    }.issubset(set(caveat["required_fields"]))


def test_runtime_context_session_token_reissue_endpoint_audits_and_rotates(
    conn,
    tmp_path,
):
    target_root = tmp_path / "runtime-token-reissue"
    target_root.mkdir()
    context = upsert_branch_context(
        conn,
        BranchTaskRuntimeContext(
            project_id=PID,
            governance_project_id=PID,
            target_project_id=PID,
            target_project_root=str(target_root),
            task_id="worker-runtime-reissue",
            root_task_id="parent-runtime-reissue",
            backlog_id="AC-RUNTIME-TOKEN-REISSUE",
            stage_task_id="worker-runtime-reissue",
            worker_id="worker-runtime-reissue",
            worker_slot_id="slot-runtime-reissue",
            branch_ref="refs/heads/codex/worker-runtime-reissue",
            status=STATE_WORKTREE_READY,
            fence_token="fence-runtime-reissue",
            session_token_hash=mf_subagent_session_token_hash("old-runtime-token"),
            lease_id="lease-runtime-expired",
            lease_expires_at="2000-01-01T00:00:00Z",
        ),
    )
    conn.commit()
    result = server.handle_graph_governance_runtime_context_session_token_reissue(
        _ctx_with_role(
            {"project_id": PID, "runtime_context_id": context.runtime_context_id},
            "mf_sub",
            method="POST",
            body={
                "task_id": "worker-runtime-reissue",
                "parent_task_id": "parent-runtime-reissue",
                "fence_token": "fence-runtime-reissue",
                "session_token": "old-runtime-token",
                "target_project_root": str(target_root),
                "ttl_seconds": 999999,
                "now_iso": "2026-06-16T12:00:00Z",
            },
        )
    )

    assert result["ok"] is True
    assert result["ttl_seconds"] == 28800
    assert result["session_token_persisted"] is False
    assert result["session_token_lease"]["lease_remaining_ttl_seconds"] == 28800
    assert str(result["audit_event_ref"]).startswith("timeline:")
    new_token = result["session_token"]
    saved = get_branch_context(conn, PID, "worker-runtime-reissue")
    assert saved is not None
    assert saved.session_token_hash == mf_subagent_session_token_hash(new_token)
    events = task_timeline.list_events(
        conn,
        PID,
        backlog_id="AC-RUNTIME-TOKEN-REISSUE",
        event_kind="mf_subagent_session_token_reissue",
    )
    assert len(events) == 1
    serialized_event = json.dumps(events[0], sort_keys=True)
    assert "old-runtime-token" not in serialized_event
    assert new_token not in serialized_event

    with pytest.raises(GovernanceError) as wrong_token:
        server.handle_graph_governance_runtime_context_session_token_reissue(
            _ctx_with_role(
                {"project_id": PID, "runtime_context_id": context.runtime_context_id},
                "mf_sub",
                method="POST",
                body={
                    "task_id": "worker-runtime-reissue",
                    "parent_task_id": "parent-runtime-reissue",
                    "fence_token": "fence-runtime-reissue",
                    "session_token": "wrong-runtime-token",
                    "target_project_root": str(target_root),
                },
            )
        )
    assert wrong_token.value.code == "fence_invalidated_or_unknown"


def test_runtime_context_worker_guide_missing_auth_points_to_initial_join_before_lineage(
    conn,
    tmp_path,
):
    target_root = tmp_path / "runtime-auth-missing"
    target_root.mkdir()
    context = upsert_branch_context(
        conn,
        BranchTaskRuntimeContext(
            project_id=PID,
            governance_project_id=PID,
            target_project_id=PID,
            target_project_root=str(target_root),
            task_id="worker-auth-missing",
            root_task_id="parent-auth-missing",
            backlog_id="AC-RUNTIME-AUTH-MISSING",
            stage_task_id="worker-auth-missing",
            worker_id="worker-auth-missing",
            worker_slot_id="slot-auth-missing",
            branch_ref="refs/heads/codex/worker-auth-missing",
            status=STATE_WORKTREE_READY,
            fence_token="fence-auth-missing",
            session_token_hash=mf_subagent_session_token_hash("auth-missing-token"),
        ),
    )
    conn.commit()

    with pytest.raises(GovernanceError) as blocked:
        server.handle_graph_governance_parallel_branch_runtime_context_worker_guide(
            _ctx_with_role(
                {"project_id": PID, "runtime_context_id": context.runtime_context_id},
                "mf_sub",
                query={
                    "parent_task_id": "parent-auth-missing",
                    "session_token_ref": runtime_context_session_token_ref(context),
                    "target_project_root": str(target_root),
                },
            )
        )

    assert blocked.value.code == "fence_invalidated_or_unknown"
    details = blocked.value.details
    assert details["diagnostics"]["reason"] == "worker_auth_material_missing"
    assert details["next_legal_action"] == (
        "request_runtime_context_initial_join_host_envelope"
    )
    submission = details["actionable_payloads"][
        "session_token_initial_join_submission"
    ]
    assert submission["action"] == "request_runtime_context_initial_join_host_envelope"
    assert submission["missing_lineage"] == [
        "mf_subagent_read_receipt",
        "mf_subagent_startup",
    ]
    assert submission["security_boundary"]["session_token_ref_alone_authorizes_writes"] is False
    capacity_guidance = details["actionable_payloads"]["capacity_fallback_guidance"]
    assert capacity_guidance["official_fallback_options"] == [
        "reuse_existing_idle_subagent_same_runtime_envelope",
        "queue_dispatch_until_capacity_available",
        "stop_and_record_capacity_blocker",
    ]
    assert capacity_guidance["preserve_runtime_identity"][
        "runtime_context_id"
    ] == context.runtime_context_id
    assert capacity_guidance["preserve_runtime_identity"]["task_id"] == (
        "worker-auth-missing"
    )
    assert capacity_guidance["preserve_runtime_identity"]["parent_task_id"] == (
        "parent-auth-missing"
    )
    assert "observer_authored_mf_sub_evidence" in capacity_guidance[
        "forbidden_shortcuts"
    ]
    assert "raw_token_persistence" in capacity_guidance["forbidden_shortcuts"]
    assert "change_runtime_identity_to_work_around_capacity" in capacity_guidance[
        "forbidden_shortcuts"
    ]


