def test_runtime_context_initial_join_accepts_registry_verified_superseded_ref_two_hop(
    conn,
    tmp_path,
):
    target_root = tmp_path / "runtime-token-initial-join-superseded-two-hop"
    target_root.mkdir()
    worker_task_id = "worker-runtime-initial-join-superseded-two-hop"
    parent_task_id = "parent-runtime-initial-join-superseded-two-hop"
    backlog_id = "AC-RUNTIME-TOKEN-INITIAL-JOIN-SUPERSEDED-TWO-HOP"
    request_now = datetime.now(timezone.utc)
    context = upsert_branch_context(
        conn,
        BranchTaskRuntimeContext(
            project_id=PID,
            governance_project_id=PID,
            target_project_id=PID,
            target_project_root=str(target_root),
            task_id=worker_task_id,
            root_task_id=parent_task_id,
            backlog_id=backlog_id,
            stage_task_id=worker_task_id,
            worker_id=worker_task_id,
            worker_slot_id="slot-runtime-initial-join-superseded-two-hop",
            branch_ref=(
                "refs/heads/codex/worker-runtime-initial-join-superseded-two-hop"
            ),
            status=STATE_WORKTREE_READY,
            fence_token="fence-runtime-initial-join-superseded-two-hop",
        ),
    )
    original = observer_route_context.issue_observer_write_route_context(
        project_id=PID,
        backlog_id=backlog_id,
        task_id=parent_task_id,
        target_files=["agent/governance/server.py"],
        allowed_actions=["task_timeline_append"],
        now=request_now,
        evidence_refs=["test:superseded-two-hop-original"],
    )
    original_ref = original["route_token_ref"]
    observer_route_context.persist_route_token_ref(
        conn,
        project_id=PID,
        route_token_ref=original_ref,
        token=original["route_token"],
    )
    original_identity = {
        field: original["route_token"][field]
        for field in (
            "route_id",
            "route_context_hash",
            "prompt_contract_id",
            "prompt_contract_hash",
            "visible_injection_manifest_hash",
        )
    }
    original_identity["route_token_ref"] = original_ref
    append_branch_contract_revision(
        conn,
        context,
        revision_id="crev-runtime-initial-join-superseded-two-hop",
        route_identity=original_identity,
        payload={"route_identity": original_identity},
    )

    # Supersede the runtime's expected ref.  That direct successor is
    # deliberately not projected into the runtime contract, reproducing a
    # resumed worker whose expected ref can no longer be renewed.
    observer_route_context.renew_route_token_ref(
        conn,
        project_id=PID,
        route_token_ref=original_ref,
        backlog_id=backlog_id,
        task_id=parent_task_id,
        allowed_actions=["task_timeline_append"],
        target_files=["agent/governance/server.py"],
        ttl_hours=48.0,
        now=request_now,
        evidence_refs=["test:supersede-runtime-expected-ref"],
    )

    widened_status, widened = server.handle_observer_route_context_issue(
        _ctx(
            {"project_id": PID},
            method="POST",
            body={
                "caller_role": "observer",
                "backlog_id": backlog_id,
                "task_id": parent_task_id,
                "target_files": ["agent/governance/server.py"],
                "allowed_actions": [
                    "task_timeline_append",
                    "backlog_close",
                ],
                "parent_route_identity": original_identity,
            },
        )
    )
    assert widened_status == 409
    assert widened["error"] == (
        "route_token_ref_allowed_actions_widening_refused"
    )
    assert widened["fail_closed"] is True

    issued = server.handle_observer_route_context_issue(
        _ctx(
            {"project_id": PID},
            method="POST",
            body={
                "caller_role": "observer",
                "backlog_id": backlog_id,
                "task_id": parent_task_id,
                "target_files": ["agent/governance/server.py"],
                "owned_files": ["agent/governance/server.py"],
                "allowed_actions": ["task_timeline_append"],
                "evidence_refs": ["test:same-scope-reissue"],
                "parent_route_identity": original_identity,
            },
        )
    )
    assert issued["ok"] is True
    child_ref = issued["route_token_ref"]
    child = observer_route_context.resolve_route_token_ref(
        conn,
        project_id=PID,
        route_token_ref=child_ref,
        backlog_id=backlog_id,
        task_id=parent_task_id,
        now=request_now,
    )
    assert child is not None
    reissue_proof = child["route_lineage"]["same_scope_reissue_proof"]
    assert reissue_proof == {
        "schema_version": "route_token_ref_same_scope_reissue_proof.v1",
        "status": "reissued_from_superseded",
        "source": "issue_observer_write_route_context",
        "previous_route_token_ref": original_ref,
        "route_token_ref": child_ref,
        "scope": {
            "project_id": PID,
            "backlog_id": backlog_id,
            "task_id": parent_task_id,
        },
        "caller_role": "observer",
        "allowed_actions": ["task_timeline_append"],
        "target_files": ["agent/governance/server.py"],
        "owned_files": ["agent/governance/server.py"],
        "scope_widened": False,
        "registry_verified": True,
        "raw_route_token_persisted": False,
        "raw_session_token_persisted": False,
    }

    renewed = observer_route_context.renew_route_token_ref(
        conn,
        project_id=PID,
        route_token_ref=child_ref,
        backlog_id=backlog_id,
        task_id=parent_task_id,
        allowed_actions=["task_timeline_append"],
        target_files=["agent/governance/server.py"],
        owned_files=["agent/governance/server.py"],
        ttl_hours=48.0,
        now=request_now,
        evidence_refs=["test:renew-reissued-child-with-active-observer"],
    )
    renewed_ref = renewed["route_token_ref"]
    renewed_identity = {
        field: renewed["route_identity"][field]
        for field in (
            "route_id",
            "route_context_hash",
            "prompt_contract_id",
            "prompt_contract_hash",
            "visible_injection_manifest_hash",
        )
    }
    renewed_identity["route_token_ref"] = renewed_ref

    result = server.handle_graph_governance_runtime_context_session_token_initial_join(
        _ctx_with_role(
            {"project_id": PID, "runtime_context_id": context.runtime_context_id},
            "coordinator",
            method="POST",
            body={
                "task_id": worker_task_id,
                "parent_task_id": parent_task_id,
                "target_project_root": str(target_root),
                **renewed_identity,
                "reason": (
                    "host adapter uses registry-verified two-hop recovery for "
                    "the superseded runtime route ref"
                ),
                "ttl_seconds": 1200,
                "now_iso": request_now.isoformat().replace("+00:00", "Z"),
            },
        )
    )

    assert result["ok"] is True
    assert result["status"] == "session_token_initial_join_issued"
    renewed_summary = result["route_lineage"]["renewed_route_token_ref"]
    assert renewed_summary["renewed_from"] == original_ref
    assert renewed_summary["recovery_mode"] == (
        "superseded_ref_same_scope_two_hop"
    )
    assert renewed_summary["reissued_route_token_ref"] == child_ref
    assert renewed_summary["renewal_chain"] == [
        original_ref,
        child_ref,
        renewed_ref,
    ]
    assert result["route_lineage"]["route_lineage"][
        "same_scope_reissue_proof"
    ] == reissue_proof
    assert result["session_token"] not in json.dumps(
        task_timeline.list_events(
            conn,
            PID,
            backlog_id=backlog_id,
            event_kind="observer_command",
        ),
        sort_keys=True,
    )


def test_runtime_context_session_token_rejoin_audits_host_envelope_without_ref_only_write(
    conn,
    tmp_path,
):
    target_root = tmp_path / "runtime-token-rejoin"
    target_root.mkdir()
    context = upsert_branch_context(
        conn,
        BranchTaskRuntimeContext(
            project_id=PID,
            governance_project_id=PID,
            target_project_id=PID,
            target_project_root=str(target_root),
            task_id="worker-runtime-rejoin",
            root_task_id="parent-runtime-rejoin",
            backlog_id="AC-RUNTIME-TOKEN-REJOIN",
            stage_task_id="worker-runtime-rejoin",
            worker_id="worker-runtime-rejoin",
            worker_slot_id="slot-runtime-rejoin",
            branch_ref="refs/heads/codex/worker-runtime-rejoin",
            status=STATE_WORKTREE_READY,
            fence_token="fence-runtime-rejoin",
            session_token_hash=mf_subagent_session_token_hash("lost-runtime-token"),
        ),
    )
    route_identity = {
        "route_id": "route-runtime-rejoin-current",
        "route_context_hash": _fake_sha("route-runtime-rejoin-current"),
        "prompt_contract_id": "rprompt-runtime-rejoin-current",
        "prompt_contract_hash": _fake_sha("prompt-runtime-rejoin-current"),
        "visible_injection_manifest_hash": _fake_sha("visible-runtime-rejoin-current"),
        "route_token_ref": "rtok-runtime-rejoin-current",
    }
    append_branch_contract_revision(
        conn,
        context,
        revision_id="crev-runtime-rejoin-current",
        contract_version="direct_fix.v1",
        payload={"route_identity": route_identity},
        route_identity=route_identity,
        route_evidence_type="observer_route_token_ref",
        actor="observer",
        now_iso="2026-06-21T17:55:00Z",
    )
    task_timeline.record_event(
        conn,
        project_id=PID,
        task_id="worker-runtime-rejoin",
        backlog_id="AC-RUNTIME-TOKEN-REJOIN",
        event_type="mf_subagent.read_receipt",
        event_kind="mf_subagent_read_receipt",
        phase="read_receipt",
        status="accepted",
        actor="slot-runtime-rejoin",
        payload={
            "runtime_context_id": context.runtime_context_id,
            "task_id": "worker-runtime-rejoin",
            "parent_task_id": "parent-runtime-rejoin",
            "worker_slot_id": "slot-runtime-rejoin",
            "read_receipt_hash": "sha256:runtime-rejoin-read",
        },
    )
    task_timeline.record_event(
        conn,
        project_id=PID,
        task_id="worker-runtime-rejoin",
        backlog_id="AC-RUNTIME-TOKEN-REJOIN",
        event_type="mf_subagent.startup",
        event_kind="mf_subagent_startup",
        phase="startup",
        status="accepted",
        actor="slot-runtime-rejoin",
        payload={
            "runtime_context_id": context.runtime_context_id,
            "task_id": "worker-runtime-rejoin",
            "parent_task_id": "parent-runtime-rejoin",
            "worker_role": "mf_sub",
            "worker_session_id": "slot-runtime-rejoin",
            "filer_principal": "slot-runtime-rejoin",
            "session_token_evidence_type": "server_verified",
        },
    )
    conn.commit()

    with pytest.raises(GovernanceError) as guide_blocked:
        server.handle_graph_governance_parallel_branch_runtime_context_worker_guide(
            _ctx_with_role(
                {"project_id": PID, "runtime_context_id": context.runtime_context_id},
                "mf_sub",
                query={
                    "parent_task_id": "parent-runtime-rejoin",
                    "session_token_ref": runtime_context_session_token_ref(context),
                    "target_project_root": str(target_root),
                },
            )
        )
    assert guide_blocked.value.code == "fence_invalidated_or_unknown"
    assert guide_blocked.value.details["next_legal_action"] == (
        "request_runtime_context_rejoin_host_envelope"
    )
    assert "session_token_rejoin_submission" in (
        guide_blocked.value.details["actionable_payloads"]
    )
    assert "session_token_initial_join_submission" not in (
        guide_blocked.value.details["actionable_payloads"]
    )

    result = server.handle_graph_governance_runtime_context_session_token_rejoin(
        _ctx_with_role(
            {"project_id": PID, "runtime_context_id": context.runtime_context_id},
            "coordinator",
            method="POST",
            body={
                "task_id": "worker-runtime-rejoin",
                "parent_task_id": "parent-runtime-rejoin",
                "target_project_root": str(target_root),
                "reason": "host worker session lost raw auth env after resume",
                "ttl_seconds": 1200,
                "now_iso": "2026-06-21T18:00:00Z",
            },
        )
    )

    assert result["ok"] is True
    assert result["status"] == "session_token_rejoin_issued"
    assert result["session_token"]
    assert result["fence_token"] == "fence-runtime-rejoin"
    assert result["route_identity"] == route_identity
    assert result["host_envelope"]["route_identity"] == route_identity
    assert result["host_envelope"]["runtime_context_id"] == context.runtime_context_id
    assert result["raw_tokens_persisted_to_timeline"] is False
    saved = get_branch_context(conn, PID, "worker-runtime-rejoin")
    assert saved is not None
    assert saved.session_token_hash == mf_subagent_session_token_hash(
        result["session_token"]
    )
    assert runtime_context_session_token_ref(saved) == result["session_token_ref"]
    events = task_timeline.list_events(
        conn,
        PID,
        backlog_id="AC-RUNTIME-TOKEN-REJOIN",
        event_kind="observer_command",
    )
    rejoin_events = [
        event
        for event in events
        if (event.get("payload") or {}).get("action")
        == "runtime_context_session_token_rejoin"
    ]
    assert len(rejoin_events) == 1
    rejoin_payload = rejoin_events[0]["payload"]
    assert rejoin_payload["caller_role"] == "observer"
    assert rejoin_payload["worker_role"] == "mf_sub"
    assert rejoin_payload["meta_contract_gate"]["role"] == "observer"
    assert rejoin_payload["meta_contract_gate"]["action"] == "observer_command"
    assert rejoin_payload["host_envelope_returned"] is True
    assert rejoin_payload["route_identity"] == route_identity
    serialized_event = json.dumps(rejoin_events[0], sort_keys=True)
    assert result["session_token"] not in serialized_event
    assert "fence-runtime-rejoin" not in serialized_event

    with pytest.raises(GovernanceError) as ref_only_write:
        server.handle_graph_governance_runtime_context_finish_time_worker_attestation(
            _ctx(
                {"project_id": PID, "runtime_context_id": context.runtime_context_id},
                method="POST",
                body={
                    "task_id": "worker-runtime-rejoin",
                    "parent_task_id": "parent-runtime-rejoin",
                    "session_token_ref": result["session_token_ref"],
                    "target_project_root": str(target_root),
                    "test_results": {"status": "passed", "commands": ["true"]},
                },
            )
        )
    assert ref_only_write.value.code == "fence_invalidated_or_unknown"
    assert ref_only_write.value.details["diagnostics"]["reason"] == (
        "worker_auth_material_missing"
    )


def test_runtime_context_session_token_rejoin_accepts_contract_runtime_only_worker_sequence(
    conn,
    tmp_path,
):
    backlog_id = "AC-RUNTIME-REJOIN-CONTRACT-SEQUENCE"
    target_root = tmp_path / "runtime-rejoin-contract-sequence"
    target_root.mkdir()
    successor, context = _setup_mf_parallel_contract_runtime_worker_dispatch(
        conn,
        backlog_id=backlog_id,
        task_id="runtime-rejoin-contract-parent",
        worker_task_id="runtime-rejoin-contract-worker",
        fence_token="fence-runtime-rejoin-contract",
        token="lost-runtime-rejoin-contract-token",
        target_project_root=str(target_root),
        worktree_path=str(target_root),
    )
    runtime = server._contract_runtime(conn)
    identity = {
        "runtime_context_id": context.runtime_context_id,
        "task_id": context.task_id,
        "parent_task_id": backlog_id,
        "worker_role": "mf_sub",
        "worker_id": context.worker_id,
        "worker_slot_id": context.worker_slot_id,
    }
    for stage_id, line_id, evidence_kind in (
        ("worker_read", "worker_read_runtime_guide", "read_receipt"),
        ("worker_startup", "worker_startup", "mf_subagent_startup"),
    ):
        runtime.current_guide(
            successor["contract_execution_id"],
            actor_role="mf_sub",
        )
        record = runtime.store.get(successor["contract_execution_id"])
        write = server._contract_runtime_write_from_record(
            record,
            actor_role="mf_sub",
            stage_id=stage_id,
            line_id=line_id,
            evidence_kind=evidence_kind,
        )
        write.update(identity)
        write["payload"] = dict(identity)
        accepted = runtime.submit_line_write(
            successor["contract_execution_id"],
            write,
            actor_role="mf_sub",
        )
        assert accepted["ok"] is True

    startup_events_before = task_timeline.list_events(
        conn,
        PID,
        backlog_id=backlog_id,
        event_kind="mf_subagent_startup",
    )
    assert startup_events_before == []
    route_identity = {
        "route_id": f"route-{context.task_id}",
        "route_context_hash": f"sha256:route-{context.task_id}",
        "prompt_contract_id": f"rprompt-{context.task_id}",
        "prompt_contract_hash": f"sha256:prompt-{context.task_id}",
        "route_token_ref": f"rtok-{context.task_id}",
        "visible_injection_manifest_hash": f"sha256:visible-{context.task_id}",
    }
    guide = (
        server.handle_graph_governance_parallel_branch_runtime_context_worker_guide(
            _ctx_with_role(
                {
                    "project_id": PID,
                    "runtime_context_id": context.runtime_context_id,
                },
                "mf_sub",
                query={
                    "parent_task_id": backlog_id,
                    "fence_token": context.fence_token,
                    "session_token": "lost-runtime-rejoin-contract-token",
                    "target_project_root": str(target_root),
                },
            )
        )
    )
    rejoin_copy_safe_body = guide["actionable_payloads"][
        "session_token_rejoin_submission"
    ]["copy_safe_body"]
    assert rejoin_copy_safe_body["contract_execution_id"] == (
        successor["contract_execution_id"]
    )

    with pytest.raises(GovernanceError) as unrelated_contract:
        server.handle_graph_governance_runtime_context_session_token_rejoin(
            _ctx_with_role(
                {
                    "project_id": PID,
                    "runtime_context_id": context.runtime_context_id,
                },
                "coordinator",
                method="POST",
                body={
                    "task_id": context.task_id,
                    "parent_task_id": backlog_id,
                    "contract_execution_id": "cex-unrelated-runtime-rejoin",
                    "target_project_root": str(target_root),
                    "reason": "reject an unrelated child contract alias",
                    **route_identity,
                },
            )
        )
    assert unrelated_contract.value.code == (
        "runtime_context_rejoin_contract_execution_id_mismatch"
    )
    assert unrelated_contract.value.details["expected_contract_execution_id"] == (
        successor["contract_execution_id"]
    )

    result = server.handle_graph_governance_runtime_context_session_token_rejoin(
        _ctx_with_role(
            {"project_id": PID, "runtime_context_id": context.runtime_context_id},
            "coordinator",
            method="POST",
            body={
                "task_id": context.task_id,
                "parent_task_id": backlog_id,
                "contract_execution_id": successor["contract_execution_id"],
                "target_project_root": str(target_root),
                "reason": "same worker lost host auth after ContractRuntime startup",
                "ttl_seconds": 1200,
                "now_iso": "2026-07-15T06:00:00Z",
                **route_identity,
            },
        )
    )

    assert result["ok"] is True
    assert result["status"] == "session_token_rejoin_issued"
    assert result["route_identity"] == route_identity
    assert result["route_identity_source"] == "resolved_active_route_token_ref"
    assert result["raw_tokens_persisted_to_timeline"] is False
    audit_events = task_timeline.list_events(
        conn,
        PID,
        backlog_id=backlog_id,
        event_kind="observer_command",
    )
    rejoin_payload = next(
        event["payload"]
        for event in audit_events
        if (event.get("payload") or {}).get("action")
        == "runtime_context_session_token_rejoin"
    )
    sequence = rejoin_payload["contract_runtime_worker_sequence"]
    assert sequence["ordered"] is True
    assert sequence["startup_ref"].startswith("contract_runtime:")
    assert rejoin_payload["startup_event_ref"] == ""
    assert rejoin_payload["effective_startup_ref"] == sequence["startup_ref"]
    assert task_timeline.list_events(
        conn,
        PID,
        backlog_id=backlog_id,
        event_kind="mf_subagent_startup",
    ) == []
    serialized_audit = json.dumps(rejoin_payload, sort_keys=True)
    assert result["session_token"] not in serialized_audit
    assert result["fence_token"] not in serialized_audit


def test_runtime_context_session_token_rejoin_rebinds_superseded_route_ref(
    conn,
    tmp_path,
):
    target_root = tmp_path / "runtime-token-rejoin-route-rebind"
    target_root.mkdir()
    context = upsert_branch_context(
        conn,
        BranchTaskRuntimeContext(
            project_id=PID,
            governance_project_id=PID,
            target_project_id=PID,
            target_project_root=str(target_root),
            task_id="worker-runtime-rejoin-route-rebind",
            root_task_id="parent-runtime-rejoin-route-rebind",
            backlog_id="AC-RUNTIME-TOKEN-REJOIN-ROUTE-REBIND",
            stage_task_id="worker-runtime-rejoin-route-rebind",
            worker_id="worker-runtime-rejoin-route-rebind",
            worker_slot_id="slot-runtime-rejoin-route-rebind",
            branch_ref="refs/heads/codex/worker-runtime-rejoin-route-rebind",
            status=STATE_WORKTREE_READY,
            fence_token="fence-runtime-rejoin-route-rebind",
            session_token_hash=mf_subagent_session_token_hash(
                "lost-runtime-rejoin-route-rebind"
            ),
        ),
    )
    old_issue = observer_route_context.issue_observer_write_route_context(
        project_id=PID,
        backlog_id=context.backlog_id,
        task_id=context.task_id,
        target_files=["agent/governance/server.py"],
        allowed_actions=["task_timeline_append"],
        ttl_hours=8,
        evidence_refs=["timeline:runtime-rejoin-route-rebind-old"],
    )
    observer_route_context.persist_route_token_ref(
        conn,
        project_id=PID,
        route_token_ref=old_issue["route_token_ref"],
        token=old_issue["route_token"],
    )
    old_route_identity = {
        "route_id": old_issue["route_id"],
        "route_context_hash": old_issue["route_context_hash"],
        "prompt_contract_id": old_issue["prompt_contract_id"],
        "prompt_contract_hash": old_issue["route_token"]["prompt_contract_hash"],
        "visible_injection_manifest_hash": old_issue[
            "visible_injection_manifest_hash"
        ],
        "route_token_ref": old_issue["route_token_ref"],
    }
    append_branch_contract_revision(
        conn,
        context,
        revision_id="crev-runtime-rejoin-route-rebind-old",
        contract_version="direct_fix.v1",
        payload={"route_identity": old_route_identity},
        route_identity=old_route_identity,
        route_evidence_type="observer_route_token_ref",
        actor="observer",
        now_iso="2026-07-05T00:00:00Z",
    )
    assert observer_route_context.supersede_route_token_ref(
        conn,
        project_id=PID,
        route_token_ref=old_issue["route_token_ref"],
    )
    fresh_issue = observer_route_context.issue_observer_write_route_context(
        project_id=PID,
        backlog_id=context.backlog_id,
        task_id=context.task_id,
        target_files=["agent/governance/server.py"],
        allowed_actions=["task_timeline_append"],
        ttl_hours=9,
        evidence_refs=["timeline:runtime-rejoin-route-rebind-fresh"],
        parent_route_identity={
            **old_route_identity,
            "selected_project": PID,
            "selected_backlog_id": context.backlog_id,
        },
        parent_route_token_ref=old_issue["route_token_ref"],
    )
    observer_route_context.persist_route_token_ref(
        conn,
        project_id=PID,
        route_token_ref=fresh_issue["route_token_ref"],
        token=fresh_issue["route_token"],
    )
    fresh_route_identity = {
        "route_id": fresh_issue["route_id"],
        "route_context_hash": fresh_issue["route_context_hash"],
        "prompt_contract_id": fresh_issue["prompt_contract_id"],
        "prompt_contract_hash": fresh_issue["route_token"]["prompt_contract_hash"],
        "visible_injection_manifest_hash": fresh_issue[
            "visible_injection_manifest_hash"
        ],
        "route_token_ref": fresh_issue["route_token_ref"],
    }
    for event_kind, event_type, phase in (
        ("mf_subagent_read_receipt", "mf_subagent.read_receipt", "read_receipt"),
        ("mf_subagent_startup", "mf_subagent.startup", "startup"),
    ):
        task_timeline.record_event(
            conn,
            project_id=PID,
            task_id=context.task_id,
            backlog_id=context.backlog_id,
            event_type=event_type,
            event_kind=event_kind,
            phase=phase,
            status="accepted",
            actor=context.worker_slot_id,
            payload={
                "runtime_context_id": context.runtime_context_id,
                "task_id": context.task_id,
                "parent_task_id": context.root_task_id,
                "worker_role": "mf_sub",
                "worker_slot_id": context.worker_slot_id,
                "worker_session_id": context.worker_slot_id,
                "session_token_evidence_type": "server_verified",
            },
        )
    conn.commit()

    with pytest.raises(GovernanceError) as stale_rejoin:
        server.handle_graph_governance_runtime_context_session_token_rejoin(
            _ctx_with_role(
                {"project_id": PID, "runtime_context_id": context.runtime_context_id},
                "coordinator",
                method="POST",
                body={
                    "task_id": context.task_id,
                    "parent_task_id": context.root_task_id,
                    "target_project_root": str(target_root),
                    "reason": "host worker session lost raw auth env after resume",
                    **old_route_identity,
                    "route_token_ref": old_issue["route_token_ref"],
                },
            )
        )
    assert stale_rejoin.value.code == "runtime_context_rejoin_route_token_ref_invalid"
    assert stale_rejoin.value.details["route_token_ref_error_code"] == (
        "route_token_ref_not_active"
    )

    result = server.handle_graph_governance_runtime_context_session_token_rejoin(
        _ctx_with_role(
            {"project_id": PID, "runtime_context_id": context.runtime_context_id},
            "coordinator",
            method="POST",
            body={
                "task_id": context.task_id,
                "parent_task_id": context.root_task_id,
                "target_project_root": str(target_root),
                "reason": "host worker session lost raw auth env after resume",
                "ttl_seconds": 1200,
                **fresh_route_identity,
                "route_token_ref": fresh_issue["route_token_ref"],
            },
        )
    )

    assert result["ok"] is True
    assert result["route_identity_source"] == "resolved_active_route_token_ref"
    assert result["route_identity_rebound"] is True
    assert result["route_identity"] == fresh_route_identity
    assert result["previous_route_identity"] == old_route_identity
    assert result["host_envelope"]["route_identity"] == fresh_route_identity
    assert result["host_envelope"]["route_identity_source"] == (
        "resolved_active_route_token_ref"
    )
    assert result["raw_tokens_persisted_to_timeline"] is False
    latest_revision = get_latest_branch_contract_revision(
        conn,
        PID,
        context.runtime_context_id,
    )
    assert latest_revision is not None
    assert {
        field: latest_revision.route_identity[field]
        for field in fresh_route_identity
    } == fresh_route_identity
    assert latest_revision.route_evidence_type == (
        "resolved_active_route_token_ref_rejoin"
    )
    assert {
        field: latest_revision.route_gate[field]
        for field in fresh_route_identity
    } == fresh_route_identity
    assert latest_revision.payload["route_token_ref_renewal"] == {
        "schema_version": "runtime_context.route_token_ref_renewal_revision.v1",
        "status": "accepted_at_rejoin",
        "previous_route_token_ref": old_issue["route_token_ref"],
        "route_token_ref": fresh_issue["route_token_ref"],
        "registry_verified": True,
    }
    assert result["route_contract_revision_id"] == latest_revision.revision_id
    assert result["host_envelope"]["route_contract_revision_id"] == (
        latest_revision.revision_id
    )
    graph_context = validate_mf_subagent_graph_query_identity(
        conn,
        project_id=PID,
        runtime_context_id=context.runtime_context_id,
        task_id=context.task_id,
        parent_task_id=context.root_task_id,
        worker_role="mf_sub",
        fence_token=result["fence_token"],
        session_token=result["session_token"],
        target_project_root=str(target_root),
        route_identity=fresh_route_identity,
    )
    assert graph_context.task_id == context.task_id

    implementation = server.handle_graph_governance_runtime_context_implementation_evidence(
        _ctx_with_role(
            {"project_id": PID, "runtime_context_id": context.runtime_context_id},
            "mf_sub",
            method="POST",
            body={
                "parent_task_id": context.root_task_id,
                "fence_token": result["fence_token"],
                "session_token": result["session_token"],
                "target_project_root": str(target_root),
                **fresh_route_identity,
                "route_token_ref": fresh_issue["route_token_ref"],
                "changed_files": ["agent/governance/server.py"],
                "tests": [{"command": "pytest -q", "status": "passed"}],
                "payload": {
                    "worker_role": "mf_sub",
                    "summary": "fresh route ref after rejoin",
                },
            },
        )
    )
    assert implementation["ok"] is True
    assert implementation["route_token_gate"]["route_token_ref"] == (
        fresh_issue["route_token_ref"]
    )
    stored = conn.execute(
        "SELECT payload_json FROM task_timeline_events WHERE id = ?",
        (implementation["timeline_event"]["id"],),
    ).fetchone()
    payload = json.loads(stored["payload_json"])
    assert payload["route_token_ref"] == fresh_issue["route_token_ref"]
    assert payload["parent_route_lineage"]["route_token_ref"] == (
        fresh_issue["route_token_ref"]
    )
    assert payload["child_route_lineage"]["route_token_ref"] == (
        fresh_issue["route_token_ref"]
    )
    assert payload["parent_route_lineage_repair"]["status"] == (
        "stale_parent_lineage_ignored_for_ref_resolved_current_route"
    )


def test_runtime_context_session_token_rejoin_reopens_validated_worker_after_failed_qa(
    conn,
    tmp_path,
):
    target_root = tmp_path / "runtime-token-rejoin-failed-qa"
    target_root.mkdir()
    context = upsert_branch_context(
        conn,
        BranchTaskRuntimeContext(
            project_id=PID,
            governance_project_id=PID,
            target_project_id=PID,
            target_project_root=str(target_root),
            task_id="worker-runtime-rejoin-failed-qa",
            root_task_id="parent-runtime-rejoin-failed-qa",
            backlog_id="AC-RUNTIME-TOKEN-REJOIN-FAILED-QA",
            stage_task_id="worker-runtime-rejoin-failed-qa",
            worker_id="worker-runtime-rejoin-failed-qa",
            worker_slot_id="slot-runtime-rejoin-reviewfail",
            branch_ref="refs/heads/codex/worker-runtime-rejoin-failed-qa",
            status=STATE_VALIDATED,
            fence_token="fence-runtime-rejoin-failed-qa",
            session_token_hash=mf_subagent_session_token_hash("lost-runtime-token"),
            attempt=1,
            retry_round=0,
        ),
    )
    task_timeline.record_event(
        conn,
        project_id=PID,
        task_id=context.task_id,
        backlog_id=context.backlog_id,
        event_type="mf_subagent.read_receipt",
        event_kind="mf_subagent_read_receipt",
        phase="read_receipt",
        status="accepted",
        actor=context.worker_slot_id,
        payload={
            "runtime_context_id": context.runtime_context_id,
            "task_id": context.task_id,
            "parent_task_id": context.root_task_id,
            "worker_role": "mf_sub",
            "worker_slot_id": context.worker_slot_id,
            "read_receipt_hash": "sha256:runtime-rejoin-failed-qa-read",
        },
    )
    task_timeline.record_event(
        conn,
        project_id=PID,
        task_id=context.task_id,
        backlog_id=context.backlog_id,
        event_type="mf_subagent.startup",
        event_kind="mf_subagent_startup",
        phase="startup",
        status="accepted",
        actor=context.worker_slot_id,
        payload={
            "runtime_context_id": context.runtime_context_id,
            "task_id": context.task_id,
            "parent_task_id": context.root_task_id,
            "worker_role": "mf_sub",
            "worker_session_id": context.worker_slot_id,
            "filer_principal": context.worker_slot_id,
            "session_token_evidence_type": "server_verified",
        },
    )
    task_timeline.record_event(
        conn,
        project_id=PID,
        task_id=context.task_id,
        backlog_id=context.backlog_id,
        event_type="independent_verification.completed",
        event_kind="independent_verification",
        phase="verification",
        status="failed",
        actor="independent-qa",
        payload={
            "runtime_context_id": context.runtime_context_id,
            "task_id": context.task_id,
            "reviewer_role": "independent_qa",
            "requirement_id": "independent_verification_lane",
            "findings": [{"title": "default reminder is on"}],
        },
        verification={
            "requirement_id": "independent_verification_lane",
            "result": "failed",
            "acceptance_failed": [2],
        },
    )
    conn.commit()

    result = server.handle_graph_governance_runtime_context_session_token_rejoin(
        _ctx_with_role(
            {"project_id": PID, "runtime_context_id": context.runtime_context_id},
            "coordinator",
            method="POST",
            body={
                "task_id": context.task_id,
                "parent_task_id": context.root_task_id,
                "target_project_root": str(target_root),
                "reason": "failed independent QA requires worker revision after resume",
                "now_iso": "2999-01-01T00:00:00Z",
            },
        )
    )

    assert result["ok"] is True
    assert result["status"] == "session_token_rejoin_issued"
    assert result["reopen_for_revision"] is True
    assert result["previous_status"] == STATE_VALIDATED
    assert result["current_status"] == STATE_WORKTREE_READY
    assert result["attempt"] == 2
    assert result["retry_round"] == 1
    saved = get_branch_context(conn, PID, context.task_id)
    assert saved is not None
    assert saved.status == STATE_WORKTREE_READY
    assert saved.last_recovery_action == "mf_subagent_failed_qa_revision_rejoin_issued"
    revision_marker = server._runtime_context_failed_qa_revision_rejoin_marker(
        conn=conn,
        context=saved,
        runtime_context_id=saved.runtime_context_id,
        timeline_events=task_timeline.list_events(
            conn,
            PID,
            task_id=saved.task_id,
            backlog_id=saved.backlog_id,
            limit=1000,
        ),
    )
    assert revision_marker["source"] == "accepted_runtime_context_rejoin_event"
    assert revision_marker["runtime_context_id"] == saved.runtime_context_id
    assert revision_marker["task_id"] == saved.task_id
    assert revision_marker["revision_event_ref"].startswith("timeline:")
    assert revision_marker["evidence_backfill"] is False

    current = server.handle_graph_governance_parallel_branch_runtime_context_current_state(
        _ctx_with_role(
            {"project_id": PID, "runtime_context_id": context.runtime_context_id},
            "mf_sub",
            query={
                "parent_task_id": context.root_task_id,
                "fence_token": result["fence_token"],
                "session_token": result["session_token"],
                "target_project_root": str(target_root),
                "view": "all",
            },
        )
    )
    action_plan = current["executable_contract"]
    assert action_plan["next_legal_action"] == "revise_after_failed_independent_qa"
    assert action_plan["next_required_evidence"][0]["id"] == "failed_qa_revision"


@pytest.mark.parametrize(
    "qa_status",
    ["failed", "accepted_with_known_baseline_failure"],
)
def test_runtime_context_session_token_rejoin_reopens_after_contract_runtime_failed_qa(
    conn,
    monkeypatch,
    tmp_path,
    qa_status,
):
    backlog_id = "AC-RUNTIME-TOKEN-REJOIN-CONTRACT-FAILED-QA"
    target_root = tmp_path / "runtime-token-rejoin-contract-failed-qa"
    worker_head_commit = _init_test_git_repo(target_root)
    monkeypatch.setattr(
        server.project_service,
        "resolve_project_root",
        lambda *_args, **_kwargs: target_root,
    )
    successor, runtime_context = _setup_mf_parallel_contract_runtime_worker_dispatch(
        conn,
        backlog_id=backlog_id,
        task_id="contract-failed-qa-parent",
        worker_task_id="contract-revision-worker",
        fence_token="fence-contract-failed-qa",
        token="lost-contract-failed-qa-token",
        worktree_path=str(target_root),
    )
    worker_events = _record_mf_parallel_runtime_context_worker_evidence(
        conn,
        runtime_context,
        backlog_id=backlog_id,
        fence_token="fence-contract-failed-qa",
        graph_trace_id="gqt-contract-failed-qa-worker",
        head_commit=worker_head_commit,
    )
    _record_mf_parallel_contract_runtime_worker_prefix(
        conn,
        contract_execution_id=successor["contract_execution_id"],
        runtime_context=runtime_context,
        parent_task_id=backlog_id,
        graph_trace_id="gqt-contract-failed-qa-worker",
        head_commit=worker_head_commit,
        implementation_event_ref=f"timeline:{worker_events['implementation']}",
    )
    runtime_context = upsert_branch_context(
        conn,
        replace(
            runtime_context,
            status=STATE_VALIDATED,
            attempt=1,
            retry_round=0,
        ),
        now_iso="2026-07-06T02:00:00Z",
    )

    current = server.handle_project_contract_runtime_current_state(
        _ctx_with_role(
            {"project_id": PID, "contract_execution_id": successor["contract_execution_id"]},
            "qa",
        )
    )
    if current["next_legal_action"]["line_id"] == "qa_graph_context":
        qa_graph_trace_id = "gqt-contract-failed-qa-qa"
        bounded_graph_evidence = _insert_exact_qa_graph_query_trace(
            conn,
            trace_id=qa_graph_trace_id,
            snapshot_id="scope-contract-failed-qa-qa",
            candidate_commit_sha=worker_head_commit,
            backlog_id=backlog_id,
            task_id=runtime_context.task_id,
            target_project_root=str(target_root),
            created_at="2026-07-06T02:01:00Z",
        )
        qa_graph = server.handle_project_contract_runtime_line_write(
            _ctx_with_role(
                {
                    "project_id": PID,
                    "contract_execution_id": successor["contract_execution_id"],
                },
                "qa",
                method="POST",
                body={
                    "stage_id": "qa_graph_context",
                    "line_id": "qa_graph_context",
                    "evidence_kind": "graph_trace",
                    "graph_trace_ids": [qa_graph_trace_id],
                    "db_verified": True,
                    "query_source": "qa",
                    "query_purpose": "independent_verification",
                    "payload": {
                        "schema_version": "mf_parallel.qa_graph_context.v1",
                        "graph_trace_ids": [qa_graph_trace_id],
                        "graph_trace_evidence": bounded_graph_evidence,
                    },
                },
            )
        )
        assert qa_graph["ok"] is True
        current = server.handle_project_contract_runtime_current_state(
            _ctx_with_role(
                {
                    "project_id": PID,
                    "contract_execution_id": successor["contract_execution_id"],
                },
                "qa",
            )
        )
    assert current["next_legal_action"]["line_id"] == "qa_independent_verification"

    qa_payload = {
        "status": qa_status,
        "runtime_context_id": runtime_context.runtime_context_id,
        "task_id": runtime_context.task_id,
        "parent_task_id": backlog_id,
        "summary": (
            "Independent QA failed in ContractRuntime without a "
            "failed timeline event."
        ),
    }
    qa_verification = {
        "result": "failed",
        "verdict": "fail",
        "acceptance_failed": ["contract_runtime_failed_qa_revision"],
    }
    if qa_status == "accepted_with_known_baseline_failure":
        qa_payload.update(
            {
                "summary": (
                    "Independent QA accepted the row diff with a known "
                    "baseline failure outside the worker scope."
                ),
                "failed_count": 1,
                "full_suite_green": False,
            }
        )
        qa_verification = {
            "result": qa_status,
            "failed_count": 1,
            "full_suite_green": False,
        }

    qa_result = server.handle_project_contract_runtime_line_write(
        _ctx_with_role(
            {"project_id": PID, "contract_execution_id": successor["contract_execution_id"]},
            "qa",
            method="POST",
            body={
                "stage_id": "qa",
                "line_id": "qa_independent_verification",
                "evidence_kind": "independent_verification",
                "status": qa_status,
                "runtime_context_id": runtime_context.runtime_context_id,
                "task_id": runtime_context.task_id,
                "parent_task_id": backlog_id,
                "worker_role": "mf_sub",
                "payload": qa_payload,
                "verification": qa_verification,
            },
        )
    )
    assert qa_result["ok"] is True
    assert qa_result["contract_runtime_current_state"]["next_legal_action"][
        "line_id"
    ] == "worker_read_runtime_guide"
    assert not task_timeline.list_events(
        conn,
        PID,
        backlog_id=backlog_id,
        event_kind="independent_verification",
    )

    result = server.handle_graph_governance_runtime_context_session_token_rejoin(
        _ctx_with_role(
            {"project_id": PID, "runtime_context_id": runtime_context.runtime_context_id},
            "coordinator",
            method="POST",
            body={
                "task_id": runtime_context.task_id,
                "parent_task_id": backlog_id,
                "target_project_root": str(target_root),
                "reason": "failed ContractRuntime QA requires worker revision after resume",
                "now_iso": "2999-01-01T00:00:00Z",
            },
        )
    )

    assert result["ok"] is True
    assert result["status"] == "session_token_rejoin_issued"
    assert result["reopen_for_revision"] is True
    assert result["contract_runtime_failed_qa_revision"]["contract_execution_id"] == (
        successor["contract_execution_id"]
    )
    assert result["contract_runtime_failed_qa_revision"]["failed_qa_status"] == (
        qa_status
    )
    assert result["previous_status"] == STATE_VALIDATED
    assert result["current_status"] == STATE_WORKTREE_READY
    saved = get_branch_context(conn, PID, runtime_context.task_id)
    assert saved is not None
    assert saved.status == STATE_WORKTREE_READY
    assert saved.last_recovery_action == "mf_subagent_failed_qa_revision_rejoin_issued"

    revision_before_duplicate_read = server._contract_runtime(conn).store.get(
        successor["contract_execution_id"]
    )["execution_state_revision"]
    duplicate_read = server.handle_graph_governance_runtime_context_read_receipt(
        _ctx_with_role(
            {
                "project_id": PID,
                "runtime_context_id": runtime_context.runtime_context_id,
            },
            "mf_sub",
            method="POST",
            body={
                "parent_task_id": backlog_id,
                "fence_token": result["fence_token"],
                "session_token": result["session_token"],
                "target_project_root": str(target_root),
                "read_receipt_hash": "sha256:contract-failed-qa-rejoin-read",
                "actor": runtime_context.worker_slot_id,
            },
        )
    )
    assert duplicate_read["ok"] is True
    assert server._contract_runtime(conn).store.get(
        successor["contract_execution_id"]
    )["execution_state_revision"] == revision_before_duplicate_read

    reissued = server.handle_graph_governance_runtime_context_session_token_reissue(
        _ctx_with_role(
            {
                "project_id": PID,
                "runtime_context_id": runtime_context.runtime_context_id,
            },
            "mf_sub",
            method="POST",
            body={
                "task_id": runtime_context.task_id,
                "parent_task_id": backlog_id,
                "fence_token": result["fence_token"],
                "session_token": result["session_token"],
                "target_project_root": str(target_root),
                "ttl_seconds": 3600,
                "now_iso": "2999-01-01T00:01:00Z",
            },
        )
    )
    assert reissued["ok"] is True
    saved = get_branch_context(conn, PID, runtime_context.task_id)
    assert saved is not None
    assert saved.last_recovery_action == "mf_subagent_session_token_reissued"

    runtime_current = server.handle_graph_governance_parallel_branch_runtime_context_current_state(
        _ctx_with_role(
            {"project_id": PID, "runtime_context_id": runtime_context.runtime_context_id},
            "mf_sub",
            query={
                "parent_task_id": backlog_id,
                "fence_token": result["fence_token"],
                "session_token": reissued["session_token"],
                "target_project_root": str(target_root),
                "view": "all",
            },
        )
    )
    action_plan = runtime_current["executable_contract"]
    assert action_plan["next_legal_action"] == "record_implementation"
    required = action_plan["next_required_evidence"][0]
    assert required["id"] == "implementation_evidence"
    assert required["expected_source"] == "task_timeline.implementation"
    revision = runtime_current["runtime_context_service"]["views"][
        "worker_view"
    ]["action_plan"]["failed_qa_revision_projection"]
    assert revision["status"] == "revision_in_progress"
    assert revision["projected_setup_lines_reused"] is True
    assert revision["duplicate_read_receipt_required"] is False
    assert runtime_current["contract_runtime_next_legal_action"]["line_id"] == (
        "worker_implementation"
    )
    assert runtime_current["contract_runtime_failed_qa_revision"][
        "raw_tokens_exposed"
    ] is False
    worker_guide = server._runtime_context_worker_guide_response(runtime_current)
    assert worker_guide["next_legal_action"] == "record_implementation"
    assert worker_guide["executable_contract"]["next_legal_action"] == (
        "record_implementation"
    )
    assert worker_guide["contract_runtime_next_legal_action"]["line_id"] == (
        "worker_implementation"
    )

    revised_implementation = (
        server.handle_graph_governance_runtime_context_implementation_evidence(
            _ctx_with_role(
                {
                    "project_id": PID,
                    "runtime_context_id": runtime_context.runtime_context_id,
                },
                "mf_sub",
                method="POST",
                body={
                    "parent_task_id": backlog_id,
                    "fence_token": result["fence_token"],
                    "session_token": reissued["session_token"],
                    "target_project_root": str(target_root),
                    "changed_files": ["agent/governance/server.py"],
                    "commit_sha": hashlib.sha1(
                        b"contract-failed-qa-revised-worker-head"
                    ).hexdigest(),
                    "tests": [{"command": "pytest -q", "status": "passed"}],
                    "test_results": {"status": "passed", "passed": True},
                    "payload": {
                        "worker_role": "mf_sub",
                        "summary": "Worker corrected the failed-QA findings.",
                    },
                },
            )
        )
    )
    assert revised_implementation["ok"] is True
    assert revised_implementation["contract_runtime_canonical_line"]["status"] in {
        "completed",
        "already_completed",
    }
    revised_record = server._contract_runtime(conn).store.get(
        successor["contract_execution_id"]
    )
    assert revised_record["execution_state_revision"] > qa_result[
        "contract_runtime_current_state"
    ]["execution_state_revision"]
    assert revised_record["completed_lines"][-1]["line_id"] == (
        "worker_implementation"
    )
    assert revised_record["completed_lines"][-1]["commit_sha"] == hashlib.sha1(
        b"contract-failed-qa-revised-worker-head"
    ).hexdigest()

    revised_head = hashlib.sha1(
        b"contract-failed-qa-revised-worker-head"
    ).hexdigest()
    retry_common = {
        "runtime_context_id": runtime_context.runtime_context_id,
        "task_id": runtime_context.task_id,
        "parent_task_id": backlog_id,
        "line_instance_id": f"runtime_context:{runtime_context.runtime_context_id}",
        "commit_sha": revised_head,
        "status": "passed",
    }
    completed_retry_lines = [
        {
            **retry_common,
            "stage_id": stage_id,
            "line_id": line_id,
            "actor_role": actor_role,
            "evidence_kind": evidence_kind,
            "payload": {**retry_common, "status": "passed"},
        }
        for stage_id, line_id, actor_role, evidence_kind in (
            ("worker_commit", "worker_commit", "mf_sub", "worker_commit"),
            (
                "worker_attestation",
                "worker_finish_time_attestation",
                "mf_sub",
                "record_finish_time_worker_attestation",
            ),
            (
                "worker_finish",
                "worker_finish_gate",
                "mf_sub",
                "mf_subagent_finish_gate",
            ),
            ("qa_graph_context", "qa_graph_context", "qa", "graph_trace"),
            (
                "qa",
                "qa_independent_verification",
                "qa",
                "independent_verification",
            ),
        )
    ]
    retry_record = dict(revised_record)
    retry_record["completed_lines"] = [
        *list(revised_record["completed_lines"]),
        *completed_retry_lines,
    ]
    retry_record["execution_state_revision"] = int(
        revised_record["execution_state_revision"]
    ) + 1
    runtime = server._contract_runtime(conn)
    runtime.store.update(successor["contract_execution_id"], retry_record)

    rejoin_events = task_timeline.list_events(
        conn,
        PID,
        task_id=runtime_context.task_id,
        backlog_id=backlog_id,
        event_kind="observer_command",
    )
    assert any(
        (event.get("payload") or {}).get("action")
        == "runtime_context_session_token_rejoin"
        for event in rejoin_events
    )
    after_retry = runtime.current_guide(
        successor["contract_execution_id"], actor_role="observer"
    )
    assert after_retry["next_legal_action"]["line_id"] == "observer_merge"
    projection = server._runtime_context_contract_runtime_worker_projection(
        conn,
        contract_execution_id=successor["contract_execution_id"],
        runtime_context_id=runtime_context.runtime_context_id,
        task_id=runtime_context.task_id,
        context=get_branch_context(conn, PID, runtime_context.task_id),
    )
    assert projection["contract_runtime_next_legal_action"]["line_id"] == (
        "observer_merge"
    )
    assert projection["contract_runtime_current_state"]["next_legal_action"][
        "line_id"
    ] == "observer_merge"


def test_failed_qa_rework_versions_cumulative_implementation_before_worker_commit(
    conn,
    monkeypatch,
    tmp_path,
):
    backlog_id = "AC-FAILED-QA-CUMULATIVE-IMPLEMENTATION-REVISION"
    target_root = tmp_path / "failed-qa-cumulative-implementation-revision"
    base_commit = _init_test_git_repo(target_root)
    changed_files = [
        "agent/governance/server.py",
        "docs/onboarding.md",
    ]
    rework_changed_files = ["docs/onboarding.md"]
    initial_candidate = target_root / "agent/governance/server.py"
    initial_candidate.parent.mkdir(parents=True, exist_ok=True)
    initial_candidate.write_text("initial candidate\n", encoding="utf-8")
    subprocess.run(
        ["git", "add", "agent/governance/server.py"],
        cwd=target_root,
        check=True,
    )
    subprocess.run(
        ["git", "commit", "-m", "initial failed QA candidate"],
        cwd=target_root,
        check=True,
        capture_output=True,
        text=True,
    )
    initial_head = batch_jobs.git_commit(target_root)
    monkeypatch.setattr(
        server.project_service,
        "resolve_project_root",
        lambda *_args, **_kwargs: target_root,
    )
    successor, runtime_context = _setup_mf_parallel_contract_runtime_worker_dispatch(
        conn,
        backlog_id=backlog_id,
        task_id="failed-qa-cumulative-parent",
        worker_task_id="failed-qa-cumulative-worker",
        fence_token="fence-failed-qa-cumulative-worker",
        token="failed-qa-cumulative-worker-token",
        worktree_path=str(target_root),
        base_commit=base_commit,
        owned_files=tuple(changed_files),
    )
    worker_events = _record_mf_parallel_runtime_context_worker_evidence(
        conn,
        runtime_context,
        backlog_id=backlog_id,
        fence_token="fence-failed-qa-cumulative-worker",
        graph_trace_id="gqt-failed-qa-cumulative-worker",
        head_commit=initial_head,
    )
    _record_mf_parallel_contract_runtime_worker_prefix(
        conn,
        contract_execution_id=successor["contract_execution_id"],
        runtime_context=runtime_context,
        parent_task_id=backlog_id,
        graph_trace_id="gqt-failed-qa-cumulative-worker",
        head_commit=initial_head,
        implementation_event_ref=f"timeline:{worker_events['implementation']}",
    )
    runtime_context = upsert_branch_context(
        conn,
        replace(runtime_context, status=STATE_VALIDATED, attempt=1, retry_round=0),
        now_iso="2026-07-18T04:00:00Z",
    )

    current = server.handle_project_contract_runtime_current_state(
        _ctx_with_role(
            {
                "project_id": PID,
                "contract_execution_id": successor["contract_execution_id"],
            },
            "qa",
        )
    )
    if current["next_legal_action"]["line_id"] == "qa_graph_context":
        qa_trace_id = "gqt-failed-qa-cumulative-qa"
        bounded_graph_evidence = _insert_exact_qa_graph_query_trace(
            conn,
            trace_id=qa_trace_id,
            snapshot_id="scope-failed-qa-cumulative-qa",
            candidate_commit_sha=initial_head,
            backlog_id=backlog_id,
            task_id=runtime_context.task_id,
            target_project_root=str(target_root),
            created_at="2026-07-18T04:01:00Z",
        )
        qa_graph = server.handle_project_contract_runtime_line_write(
            _ctx_with_role(
                {
                    "project_id": PID,
                    "contract_execution_id": successor["contract_execution_id"],
                },
                "qa",
                method="POST",
                body={
                    "stage_id": "qa_graph_context",
                    "line_id": "qa_graph_context",
                    "evidence_kind": "graph_trace",
                    "graph_trace_ids": [qa_trace_id],
                    "db_verified": True,
                    "query_source": "qa",
                    "query_purpose": "independent_verification",
                    "payload": {
                        "graph_trace_ids": [qa_trace_id],
                        "graph_trace_evidence": bounded_graph_evidence,
                    },
                },
            )
        )
        assert qa_graph["ok"] is True

    failed_qa = server.handle_project_contract_runtime_line_write(
        _ctx_with_role(
            {
                "project_id": PID,
                "contract_execution_id": successor["contract_execution_id"],
            },
            "qa",
            method="POST",
            body={
                "stage_id": "qa",
                "line_id": "qa_independent_verification",
                "evidence_kind": "independent_verification",
                "status": "failed",
                "runtime_context_id": runtime_context.runtime_context_id,
                "task_id": runtime_context.task_id,
                "parent_task_id": backlog_id,
                "payload": {
                    "status": "failed",
                    "verdict": "FAIL",
                    "runtime_context_id": runtime_context.runtime_context_id,
                    "task_id": runtime_context.task_id,
                    "parent_task_id": backlog_id,
                    "summary": "The retry needs both runtime and guide files.",
                },
                "verification": {
                    "result": "failed",
                    "verdict": "FAIL",
                    "acceptance_failed": ["cumulative_implementation_lineage"],
                },
            },
        )
    )
    assert failed_qa["ok"] is True

    rejoin = server.handle_graph_governance_runtime_context_session_token_rejoin(
        _ctx_with_role(
            {"project_id": PID, "runtime_context_id": runtime_context.runtime_context_id},
            "coordinator",
            method="POST",
            body={
                "task_id": runtime_context.task_id,
                "parent_task_id": backlog_id,
                "target_project_root": str(target_root),
                "reason": "failed QA requires a cumulative worker revision",
                "now_iso": "2999-01-01T00:00:00Z",
            },
        )
    )
    assert rejoin["reopen_for_revision"] is True
    prior_session_token_ref = runtime_context_session_token_ref(runtime_context)
    assert prior_session_token_ref
    assert rejoin["session_token_ref"] != prior_session_token_ref

    runtime = server._contract_runtime(conn)
    retry_guide = runtime.current_guide(
        successor["contract_execution_id"], actor_role="mf_sub"
    )
    retry_guidance = retry_guide["failed_qa_rework"]
    assert retry_guidance["expected_diff_base_source"] == (
        "runtime_context.base_commit"
    )
    assert retry_guidance["required_submission"] == (
        "changed_files=cumulative_runtime_diff"
    )
    assert retry_guidance["delta_rework_changed_files_allowed"] is False

    rework_file = target_root / rework_changed_files[0]
    rework_file.parent.mkdir(parents=True, exist_ok=True)
    rework_file.write_text("guide revision\n", encoding="utf-8")
    subprocess.run(["git", "add", *rework_changed_files], cwd=target_root, check=True)
    subprocess.run(
        ["git", "commit", "-m", "failed QA child revision"],
        cwd=target_root,
        check=True,
        capture_output=True,
        text=True,
    )
    revised_head = batch_jobs.git_commit(target_root)

    # Reject a delta-only retry before the generic facade can persist a line
    # whose file list merely echoes the worker's incomplete claim.
    before_delta_record = runtime.store.get(successor["contract_execution_id"])
    before_delta_revision = before_delta_record["execution_state_revision"]
    before_delta_events = task_timeline.list_events(
        conn,
        PID,
        task_id=runtime_context.task_id,
        backlog_id=backlog_id,
        limit=1000,
    )
    with pytest.raises(GovernanceError) as delta_error:
        server.handle_graph_governance_runtime_context_implementation_evidence(
            _ctx_with_role(
                {
                    "project_id": PID,
                    "runtime_context_id": runtime_context.runtime_context_id,
                },
                "mf_sub",
                method="POST",
                body={
                    "parent_task_id": backlog_id,
                    "fence_token": rejoin["fence_token"],
                    "session_token": rejoin["session_token"],
                    "target_project_root": str(target_root),
                    "changed_files": rework_changed_files,
                    "graph_trace_ids": ["gqt-failed-qa-cumulative-worker"],
                    "tests": [{"command": "pytest -q", "status": "passed"}],
                },
            )
        )
    assert delta_error.value.code == (
        "contract_runtime_rework_lineage_revision_invalid"
    )
    assert delta_error.value.details["claimed_changed_files"] == (
        rework_changed_files
    )
    assert delta_error.value.details["cumulative_changed_files"] == changed_files
    assert delta_error.value.details["next_legal_action"] == (
        "retry_implementation_evidence_with_cumulative_runtime_diff"
    )
    assert runtime.store.get(successor["contract_execution_id"])[
        "execution_state_revision"
    ] == before_delta_revision
    assert len(
        task_timeline.list_events(
            conn,
            PID,
            task_id=runtime_context.task_id,
            backlog_id=backlog_id,
            limit=1000,
        )
    ) == len(before_delta_events)

    # Seed the already-accepted bad retry line that this regression repairs.
    # The production correction and subsequent worker_commit still run through
    # their protected facades below.
    partial_record = runtime.store.get(successor["contract_execution_id"])
    partial_payload, _unused_commit = _mf_parallel_worker_proof_payloads(
        runtime_context,
        parent_task_id=backlog_id,
        graph_trace_id="gqt-failed-qa-cumulative-worker",
        head_commit=initial_head,
        implementation_event_ref=f"timeline:{worker_events['implementation']}",
    )
    partial_payload["changed_files"] = rework_changed_files
    partial_payload["session_token_ref"] = prior_session_token_ref
    partial_payload["graph_trace_db_evidence"] = {
        "db_verified": True,
        "verified_trace_ids": ["gqt-failed-qa-cumulative-worker"],
    }
    partial_record["completed_lines"].append(
        {
            "stage_id": "worker_implementation",
            "line_id": "worker_implementation",
            "actor_role": "mf_sub",
            "evidence_kind": "implementation",
            "line_instance_id": (
                f"runtime_context:{runtime_context.runtime_context_id}"
            ),
            "runtime_context_id": runtime_context.runtime_context_id,
            "task_id": runtime_context.task_id,
            "parent_task_id": backlog_id,
            "worker_id": runtime_context.worker_id,
            "worker_slot_id": runtime_context.worker_slot_id,
            "session_token_ref": prior_session_token_ref,
            "changed_files": rework_changed_files,
            "graph_trace_ids": ["gqt-failed-qa-cumulative-worker"],
            "payload": partial_payload,
        }
    )
    partial_record["execution_state_revision"] = int(
        partial_record["execution_state_revision"]
    ) + 1
    runtime.store.update(successor["contract_execution_id"], partial_record)
    runtime.current_guide(successor["contract_execution_id"], actor_role="mf_sub")

    saved_context = get_branch_context(conn, PID, runtime_context.task_id)
    assert saved_context is not None
    revision_marker = server._runtime_context_failed_qa_revision_rejoin_marker(
        conn=conn,
        context=saved_context,
        runtime_context_id=saved_context.runtime_context_id,
        timeline_events=task_timeline.list_events(
            conn,
            PID,
            task_id=saved_context.task_id,
            backlog_id=saved_context.backlog_id,
            limit=1000,
        ),
    )
    assert revision_marker["session_token_ref_rotation"][
        "contract_execution_id"
    ] == successor["contract_execution_id"]
    assert revision_marker["session_token_ref_rotation"][
        "active_session_token_ref"
    ] == rejoin["session_token_ref"]

    negative_payload = {
        **partial_payload,
        "runtime_context_id": runtime_context.runtime_context_id,
        "task_id": runtime_context.task_id,
        "parent_task_id": backlog_id,
        "worker_id": runtime_context.worker_id,
        "worker_slot_id": runtime_context.worker_slot_id,
        "target_project_root": str(target_root),
        "session_token_ref": rejoin["session_token_ref"],
        "fence_token_hash": runtime_context_secret_hash(rejoin["fence_token"]),
        "changed_files": changed_files,
        "graph_trace_ids": ["gqt-failed-qa-cumulative-worker"],
        "graph_trace_db_evidence": {
            "db_verified": True,
            "verified_trace_ids": ["gqt-failed-qa-cumulative-worker"],
        },
        "failed_qa_revision_rejoin_marker": revision_marker,
        "canonical_rework_lineage_revision_authority": {
            "source": "runtime_context_clean_cumulative_git_revision",
            "server_derived": True,
            "actual_head_commit": revised_head,
            "clean_worktree": True,
            "cumulative_changed_files": changed_files,
            "owned_files": changed_files,
            "revision_event_ref": revision_marker["revision_event_ref"],
        },
    }
    negative_write = {
        "stage_id": "worker_implementation",
        "line_id": "worker_implementation",
        "actor_role": "mf_sub",
        "evidence_kind": "implementation",
        "commit_sha": revised_head,
        "changed_files": changed_files,
        "graph_trace_ids": ["gqt-failed-qa-cumulative-worker"],
        "payload": negative_payload,
    }
    negative_rotation_cases = {
        "missing_contract_execution": {"contract_execution_id": ""},
        "cross_contract": {"contract_execution_id": "cex-cross-contract"},
        "stale_session_ref": {
            "active_session_token_ref": prior_session_token_ref,
        },
        "forged_source": {"source": "client_claimed_rejoin"},
        "not_server_derived": {"server_derived": False},
        "cross_runtime": {"runtime_context_id": "mfrctx-cross-runtime"},
        "cross_task": {"task_id": "worker-cross-task"},
        "cross_worker": {"worker_id": "worker-cross-owner"},
        "cross_fence": {"fence_token_hash": _fake_sha("cross-fence")},
    }
    revision_before_negative_matrix = runtime.store.get(
        successor["contract_execution_id"]
    )["execution_state_revision"]
    for case_name, rotation_override in negative_rotation_cases.items():
        case_marker = copy.deepcopy(revision_marker)
        case_marker["session_token_ref_rotation"].update(rotation_override)
        case_write = copy.deepcopy(negative_write)
        case_write["payload"]["failed_qa_revision_rejoin_marker"] = case_marker
        rejected = runtime.revise_failed_qa_worker_implementation(
            successor["contract_execution_id"],
            case_write,
            actor_role="mf_sub",
        )
        assert rejected["ok"] is False, case_name
        assert any(
            "audited same-worker rejoin" in error
            for error in rejected["decision"]["errors"]
        ), case_name
        assert runtime.store.get(successor["contract_execution_id"])[
            "execution_state_revision"
        ] == revision_before_negative_matrix

    corrected = server.handle_graph_governance_runtime_context_implementation_evidence(
        _ctx_with_role(
            {"project_id": PID, "runtime_context_id": runtime_context.runtime_context_id},
            "mf_sub",
            method="POST",
            body={
                "parent_task_id": backlog_id,
                "fence_token": rejoin["fence_token"],
                "session_token": rejoin["session_token"],
                "target_project_root": str(target_root),
                "changed_files": changed_files,
                "graph_trace_ids": ["gqt-failed-qa-cumulative-worker"],
                "tests": [{"command": "pytest -q", "status": "passed"}],
                "payload": {"summary": "Cumulative retry lineage after clean commit."},
            },
        )
    )
    canonical = corrected["contract_runtime_canonical_line"]
    assert canonical["status"] == "revised"
    assert canonical["commit_sha"] == revised_head
    assert canonical["append_only_history_preserved"] is True
    assert canonical["supersedes_implementation_lineage_ref"]

    revised_record = runtime.store.get(successor["contract_execution_id"])
    failed_index = next(
        index
        for index, line in enumerate(revised_record["completed_lines"])
        if line.get("line_id") == "qa_independent_verification"
        and line.get("payload", {}).get("status") == "failed"
    )
    retry_implementations = [
        line
        for line in revised_record["completed_lines"][failed_index + 1 :]
        if line.get("line_id") == "worker_implementation"
    ]
    assert len(retry_implementations) == 2
    assert retry_implementations[0]["changed_files"] == rework_changed_files
    assert retry_implementations[-1]["changed_files"] == changed_files
    revision_audit = retry_implementations[-1]["payload"][
        "canonical_rework_lineage_revision"
    ]
    assert revision_audit["append_only_history_preserved"] is True
    assert revision_audit["revision_event_ref"].startswith("timeline:")
    assert revision_audit["session_token_ref_rotation"] == {
        "applied": True,
        "source": "accepted_runtime_context_rejoin_event",
        "revision_event_ref": revision_audit["revision_event_ref"],
        "raw_session_tokens_persisted": False,
    }
    assert retry_implementations[-1]["session_token_ref"] == (
        rejoin["session_token_ref"]
    )
    canonical_authority = retry_implementations[-1]["payload"][
        "canonical_rework_lineage_revision_authority"
    ]
    assert canonical_authority["server_derived"] is True
    assert canonical_authority["diff_base_commit"] == base_commit
    assert canonical_authority["cumulative_changed_files"] == changed_files

    revision_before_idempotent_retry = revised_record["execution_state_revision"]
    idempotent_retry = (
        server.handle_graph_governance_runtime_context_implementation_evidence(
            _ctx_with_role(
                {
                    "project_id": PID,
                    "runtime_context_id": runtime_context.runtime_context_id,
                },
                "mf_sub",
                method="POST",
                body={
                    "parent_task_id": backlog_id,
                    "fence_token": rejoin["fence_token"],
                    "session_token": rejoin["session_token"],
                    "target_project_root": str(target_root),
                    "changed_files": changed_files,
                    "graph_trace_ids": ["gqt-failed-qa-cumulative-worker"],
                    "tests": [{"command": "pytest -q", "status": "passed"}],
                    "payload": {"summary": "Idempotent cumulative retry."},
                },
            )
        )
    )
    assert idempotent_retry["contract_runtime_canonical_line"]["status"] == (
        "already_completed"
    )
    assert runtime.store.get(successor["contract_execution_id"])[
        "execution_state_revision"
    ] == revision_before_idempotent_retry

    latest_lineage = _worker_implementation_lineage(
        revised_record,
        retry_implementations[-1],
    )
    worker_commit = server.handle_graph_governance_runtime_context_worker_commit(
        _ctx_with_role(
            {"project_id": PID, "runtime_context_id": runtime_context.runtime_context_id},
            "mf_sub",
            method="POST",
            body={
                "contract_execution_id": successor["contract_execution_id"],
                "runtime_context_id": runtime_context.runtime_context_id,
                "task_id": runtime_context.task_id,
                "parent_task_id": backlog_id,
                "fence_token": rejoin["fence_token"],
                "session_token": rejoin["session_token"],
                "target_project_root": str(target_root),
                "worker_commit_sha": revised_head,
                "worker_session_id": runtime_context.worker_slot_id,
                "filer_principal": runtime_context.worker_slot_id,
                "implementation_lineage_ref": latest_lineage[
                    "implementation_lineage_ref"
                ],
                "owned_files": changed_files,
                "changed_files": changed_files,
                "graph_trace_ids": latest_lineage["graph_trace_ids"],
            },
        )
    )
    assert worker_commit["ok"] is True
    assert worker_commit["contract_runtime_close_evidence_gate"]["accepted"] is True
    assert worker_commit["next_legal_action"] == (
        "record_finish_time_worker_attestation"
    )

    # Drive the same runtime context through a second independent-QA failure.
    # The cumulative file set is intentionally unchanged; the new clean HEAD
    # and later accepted rejoin boundary are the revision identity.
    second_cycle_record = runtime.store.get(successor["contract_execution_id"])
    second_cycle_common = {
        "runtime_context_id": runtime_context.runtime_context_id,
        "task_id": runtime_context.task_id,
        "parent_task_id": backlog_id,
        "line_instance_id": f"runtime_context:{runtime_context.runtime_context_id}",
        "commit_sha": revised_head,
    }
    second_cycle_record["completed_lines"].extend(
        [
            {
                **second_cycle_common,
                "stage_id": "worker_attestation",
                "line_id": "worker_finish_time_attestation",
                "actor_role": "mf_sub",
                "evidence_kind": "record_finish_time_worker_attestation",
                "status": "passed",
                "payload": {**second_cycle_common, "status": "passed"},
            },
            {
                **second_cycle_common,
                "stage_id": "worker_finish",
                "line_id": "worker_finish_gate",
                "actor_role": "mf_sub",
                "evidence_kind": "mf_subagent_finish_gate",
                "status": "passed",
                "payload": {**second_cycle_common, "status": "passed"},
            },
            {
                **second_cycle_common,
                "stage_id": "qa_graph_context",
                "line_id": "qa_graph_context",
                "actor_role": "qa",
                "evidence_kind": "graph_trace",
                "status": "passed",
                "payload": {**second_cycle_common, "status": "passed"},
            },
            {
                **second_cycle_common,
                "stage_id": "qa",
                "line_id": "qa_independent_verification",
                "actor_role": "qa",
                "evidence_kind": "independent_verification",
                "status": "failed",
                "verification": {
                    "result": "failed",
                    "verdict": "FAIL",
                    "acceptance_failed": ["second_failed_qa_revision"],
                },
                "payload": {
                    **second_cycle_common,
                    "status": "failed",
                    "verdict": "FAIL",
                    "summary": "A second revision is required in the same files.",
                },
            },
        ]
    )
    second_cycle_record["execution_state_revision"] = int(
        second_cycle_record["execution_state_revision"]
    ) + 1
    runtime.store.update(successor["contract_execution_id"], second_cycle_record)
    current_context = get_branch_context(conn, PID, runtime_context.task_id)
    assert current_context is not None
    current_context = upsert_branch_context(
        conn,
        replace(current_context, status=STATE_VALIDATED),
        now_iso="2026-07-18T04:30:00Z",
    )

    second_failed_record = runtime.store.get(successor["contract_execution_id"])
    stale_boundary_payload = {
        "runtime_context_id": runtime_context.runtime_context_id,
        "task_id": runtime_context.task_id,
        "parent_task_id": backlog_id,
        "session_token_ref": rejoin["session_token_ref"],
        "changed_files": changed_files,
        "graph_trace_ids": ["gqt-failed-qa-cumulative-worker"],
        "graph_trace_db_evidence": {
            "db_verified": True,
            "verified_trace_ids": ["gqt-failed-qa-cumulative-worker"],
        },
    }
    for case_name, stale_marker in {
        "stale_prior_rejoin": revision_marker,
        "missing_later_rejoin": {},
    }.items():
        with pytest.raises(GovernanceError) as boundary_error:
            server._runtime_context_revise_failed_qa_implementation_lineage(
                conn,
                project_id=PID,
                context=current_context,
                runtime=runtime,
                record=second_failed_record,
                payload=stale_boundary_payload,
                revision_marker=stale_marker,
            )
        assert boundary_error.value.code == (
            "contract_runtime_rework_lineage_revision_invalid"
        ), case_name
        assert "active failed-QA boundary" in str(
            boundary_error.value
        ), case_name

    second_rejoin = (
        server.handle_graph_governance_runtime_context_session_token_rejoin(
            _ctx_with_role(
                {
                    "project_id": PID,
                    "runtime_context_id": runtime_context.runtime_context_id,
                },
                "coordinator",
                method="POST",
                body={
                    "task_id": runtime_context.task_id,
                    "parent_task_id": backlog_id,
                    "target_project_root": str(target_root),
                    "reason": "second failed QA requires another bounded revision",
                    "now_iso": "2999-01-02T00:00:00Z",
                },
            )
        )
    )
    assert second_rejoin["reopen_for_revision"] is True
    assert second_rejoin["session_token_ref"] != rejoin["session_token_ref"]

    initial_candidate.write_text(
        "second failed QA revision\n",
        encoding="utf-8",
    )
    subprocess.run(
        ["git", "add", "agent/governance/server.py"],
        cwd=target_root,
        check=True,
    )
    subprocess.run(
        ["git", "commit", "-m", "second failed QA child revision"],
        cwd=target_root,
        check=True,
        capture_output=True,
        text=True,
    )
    second_revised_head = batch_jobs.git_commit(target_root)
    history_before_second_revision = copy.deepcopy(
        runtime.store.get(successor["contract_execution_id"])["completed_lines"]
    )
    prior_second_lineage = _worker_implementation_lineage(
        second_failed_record,
        retry_implementations[-1],
    )

    second_corrected = (
        server.handle_graph_governance_runtime_context_implementation_evidence(
            _ctx_with_role(
                {
                    "project_id": PID,
                    "runtime_context_id": runtime_context.runtime_context_id,
                },
                "mf_sub",
                method="POST",
                body={
                    "parent_task_id": backlog_id,
                    "fence_token": second_rejoin["fence_token"],
                    "session_token": second_rejoin["session_token"],
                    "target_project_root": str(target_root),
                    "changed_files": changed_files,
                    "graph_trace_ids": ["gqt-failed-qa-cumulative-worker"],
                    "tests": [{"command": "pytest -q", "status": "passed"}],
                    "payload": {"summary": "Second cumulative failed-QA revision."},
                },
            )
        )
    )
    second_canonical = second_corrected["contract_runtime_canonical_line"]
    assert second_canonical["status"] == "revised"
    assert second_canonical["append_only_history_preserved"] is True
    assert second_canonical["supersedes_implementation_lineage_ref"]

    twice_revised_record = runtime.store.get(successor["contract_execution_id"])
    assert twice_revised_record["completed_lines"][
        : len(history_before_second_revision)
    ] == history_before_second_revision
    second_latest = next(
        (
            line
            for line in reversed(twice_revised_record["completed_lines"])
            if line.get("line_id") == "worker_implementation"
            and line.get("runtime_context_id") == runtime_context.runtime_context_id
            and line.get("task_id") == runtime_context.task_id
        ),
        None,
    )
    assert second_latest is not None
    assert second_latest["commit_sha"] == second_revised_head
    assert second_latest["changed_files"] == changed_files
    second_revision_audit = second_latest["payload"][
        "canonical_rework_lineage_revision"
    ]
    assert second_revision_audit["append_only_history_preserved"] is True
    assert second_revision_audit["supersedes_implementation_lineage_ref"] == (
        prior_second_lineage["implementation_lineage_ref"]
    )
    assert second_revision_audit["revision_event_ref"] == (
        second_rejoin["audit_event_ref"]
    )
    second_marker = second_latest["payload"][
        "failed_qa_revision_rejoin_marker"
    ]
    second_failed_index = max(
        index
        for index, line in enumerate(history_before_second_revision)
        if line.get("line_id") == "qa_independent_verification"
        and line.get("status") == "failed"
    )
    assert second_marker["failed_qa_source_ref"] == (
        f"contract_runtime:{successor['contract_execution_id']}:"
        f"completed_lines:{second_failed_index}"
    )


def test_timeline_failed_qa_rejoin_starts_fresh_contract_route_revision_without_backfill(
    conn,
    tmp_path,
):
    backlog_id = "AC-TIMELINE-FAILED-QA-ROUTE-REVISION"
    target_root = tmp_path / "timeline-failed-qa-route-revision"
    worker_head_commit = _init_test_git_repo(target_root)
    successor, runtime_context = _setup_mf_parallel_contract_runtime_worker_dispatch(
        conn,
        backlog_id=backlog_id,
        task_id="timeline-failed-qa-route-parent",
        worker_task_id="timeline-failed-qa-route-worker",
        fence_token="fence-timeline-failed-qa-route",
        token="lost-timeline-failed-qa-route-token",
        worktree_path=str(target_root),
    )
    worker_events = _record_mf_parallel_runtime_context_worker_evidence(
        conn,
        runtime_context,
        backlog_id=backlog_id,
        fence_token="fence-timeline-failed-qa-route",
        graph_trace_id="gqt-timeline-failed-qa-route-worker",
        head_commit=worker_head_commit,
    )
    _record_mf_parallel_contract_runtime_worker_prefix(
        conn,
        contract_execution_id=successor["contract_execution_id"],
        runtime_context=runtime_context,
        parent_task_id=backlog_id,
        graph_trace_id="gqt-timeline-failed-qa-route-worker",
        head_commit=worker_head_commit,
        implementation_event_ref=f"timeline:{worker_events['implementation']}",
        route_token_ref="rtok-prior-revision",
    )
    runtime_context = upsert_branch_context(
        conn,
        replace(
            runtime_context,
            status=STATE_VALIDATED,
            attempt=1,
            retry_round=0,
        ),
        now_iso="2026-07-13T14:00:00Z",
    )
    failed_qa = task_timeline.record_event(
        conn,
        project_id=PID,
        task_id=runtime_context.task_id,
        backlog_id=backlog_id,
        event_type="independent_verification.completed",
        event_kind="independent_verification",
        phase="verification",
        status="failed",
        actor="qa:independent-route-revision",
        payload={
            "runtime_context_id": runtime_context.runtime_context_id,
            "task_id": runtime_context.task_id,
            "reviewer_role": "independent_qa",
            "requirement_id": "independent_verification_lane",
            "verdict": "FAIL",
        },
        verification={"verdict": "FAIL", "acceptance_failed": [3]},
    )
    conn.commit()

    rejoin = server.handle_graph_governance_runtime_context_session_token_rejoin(
        _ctx_with_role(
            {"project_id": PID, "runtime_context_id": runtime_context.runtime_context_id},
            "coordinator",
            method="POST",
            body={
                "task_id": runtime_context.task_id,
                "parent_task_id": backlog_id,
                "target_project_root": str(target_root),
                "reason": f"Revise after failed QA timeline:{failed_qa['id']}",
                "now_iso": "2999-01-01T00:00:00Z",
            },
        )
    )
    assert rejoin["reopen_for_revision"] is True

    projection_gate = server._contract_runtime_completed_line_projection_preflight_gate(
        conn,
        body={
            "project_id": PID,
            "backlog_id": backlog_id,
            "task_id": runtime_context.task_id,
            "contract_execution_id": successor["contract_execution_id"],
            "route_token_ref": "rtok-active-revision",
            "contract_runtime_line": {
                "stage_id": "worker_implementation",
                "line_id": "worker_implementation",
                "evidence_kind": "implementation",
            },
        },
        event_kind="implementation",
        trusted_actor_role="mf_sub",
    )
    assert projection_gate == {}

    saved = get_branch_context(conn, PID, runtime_context.task_id)
    canonical = server._runtime_context_submit_canonical_contract_line(
        conn,
        project_id=PID,
        context=saved,
        contract_execution_id=successor["contract_execution_id"],
        stage_id="worker_implementation",
        line_id="worker_implementation",
        evidence_kind="implementation",
        payload={
            "runtime_context_id": runtime_context.runtime_context_id,
            "task_id": runtime_context.task_id,
            "parent_task_id": backlog_id,
            "worker_role": "mf_sub",
            "route_token_ref": "rtok-active-revision",
            "failed_qa_revision_rejoin_marker": {
                "revision_event_ref": "timeline:forged-by-worker",
            },
            "changed_files": ["agent/governance/server.py"],
            "tests": [{"command": "pytest -q", "status": "passed"}],
        },
    )
    assert canonical["status"] == "completed"

    record = server._contract_runtime(conn).store.get(
        successor["contract_execution_id"]
    )
    latest = record["completed_lines"][-1]
    assert latest["line_id"] == "worker_implementation"
    marker = latest["payload"]["failed_qa_revision_rejoin_marker"]
    assert marker["revision_event_ref"].startswith("timeline:")
    assert marker["revision_event_ref"] != "timeline:forged-by-worker"
    assert marker["evidence_backfill"] is False
    assert marker["route_token_ref"] == ""
    assert not any(
        line.get("line_id") == "qa_independent_verification"
        for line in record["completed_lines"]
    )

    current = server._contract_runtime_read(
        conn,
        contract_execution_id=successor["contract_execution_id"],
        actor_role="mf_sub",
    )
    assert current["runtime_guide"]["next_legal_action"]["line_id"] == (
        "worker_commit"
    )


def test_timeline_only_authenticated_failed_qa_revises_stored_observer_merge(
    conn,
    monkeypatch,
    tmp_path,
):
    backlog_id = "AC-TIMELINE-ONLY-FAILED-QA-STORED-OBSERVER-MERGE"
    target_root = tmp_path / "timeline-only-failed-qa-observer-merge"
    base_commit = _init_test_git_repo(target_root)
    candidate = target_root / "agent/governance/server.py"
    candidate.parent.mkdir(parents=True, exist_ok=True)
    candidate.write_text("initial candidate\n", encoding="utf-8")
    subprocess.run(
        ["git", "add", "agent/governance/server.py"],
        cwd=target_root,
        check=True,
    )
    subprocess.run(
        ["git", "commit", "-m", "initial timeline-only QA candidate"],
        cwd=target_root,
        check=True,
        capture_output=True,
        text=True,
    )
    initial_head = batch_jobs.git_commit(target_root)
    monkeypatch.setattr(
        server.project_service,
        "resolve_project_root",
        lambda *_args, **_kwargs: target_root,
    )
    successor, runtime_context = _setup_mf_parallel_contract_runtime_worker_dispatch(
        conn,
        backlog_id=backlog_id,
        task_id="timeline-only-failed-qa-parent",
        worker_task_id="timeline-only-failed-qa-worker",
        fence_token="fence-timeline-only-failed-qa",
        token="timeline-only-failed-qa-token",
        worktree_path=str(target_root),
        base_commit=base_commit,
        owned_files=("agent/governance/server.py",),
    )
    graph_trace_id = "gqt-timeline-only-failed-qa-worker"
    worker_events = _record_mf_parallel_runtime_context_worker_evidence(
        conn,
        runtime_context,
        backlog_id=backlog_id,
        fence_token="fence-timeline-only-failed-qa",
        graph_trace_id=graph_trace_id,
        head_commit=initial_head,
    )
    _record_mf_parallel_contract_runtime_worker_prefix(
        conn,
        contract_execution_id=successor["contract_execution_id"],
        runtime_context=runtime_context,
        parent_task_id=backlog_id,
        graph_trace_id=graph_trace_id,
        head_commit=initial_head,
        implementation_event_ref=f"timeline:{worker_events['implementation']}",
    )

    runtime = server._contract_runtime(conn)
    stored = runtime.store.get(successor["contract_execution_id"])
    # Reproduce the frozen live ContractRuntime shape: the legacy canonical
    # worker_implementation line has no commit fields, while its immediately
    # following source-backed worker_commit carries the exact immutable commit
    # and canonical implementation lineage.
    prior_implementation_index = next(
        index
        for index, line in enumerate(stored["completed_lines"])
        if line.get("line_id") == "worker_implementation"
        and line.get("runtime_context_id") == runtime_context.runtime_context_id
        and line.get("task_id") == runtime_context.task_id
    )
    prior_implementation = stored["completed_lines"][
        prior_implementation_index
    ]
    prior_lineage = _worker_implementation_lineage(
        stored,
        prior_implementation,
    )
    prior_implementation.pop("commit_sha", None)
    prior_implementation_payload = prior_implementation.get("payload")
    assert isinstance(prior_implementation_payload, dict)
    for field in (
        "commit_sha",
        "head_commit",
        "immutable_head_commit",
        "validated_head_commit",
        "worker_commit_sha",
    ):
        prior_implementation_payload.pop(field, None)
    prior_worker_commit_index = prior_implementation_index + 1
    prior_worker_commit = stored["completed_lines"][prior_worker_commit_index]
    assert prior_worker_commit["line_id"] == "worker_commit"
    assert prior_worker_commit["commit_sha"] == initial_head
    prior_worker_commit.pop("implementation_lineage_ref", None)
    prior_worker_commit_payload = prior_worker_commit.get("payload")
    assert isinstance(prior_worker_commit_payload, dict)
    prior_worker_commit_payload["implementation_lineage_ref"] = prior_lineage[
        "implementation_lineage_ref"
    ]
    prior_worker_commit_payload["worker_implementation_lineage"] = {
        "implementation_lineage_ref": prior_lineage[
            "implementation_lineage_ref"
        ]
    }
    assert not prior_worker_commit.get("implementation_lineage_ref")
    assert prior_worker_commit_payload["implementation_lineage_ref"] == (
        prior_lineage["implementation_lineage_ref"]
    )
    assert prior_worker_commit_payload["worker_implementation_lineage"][
        "implementation_lineage_ref"
    ] == prior_lineage["implementation_lineage_ref"]
    passed_common = {
        "runtime_context_id": runtime_context.runtime_context_id,
        "task_id": runtime_context.task_id,
        "parent_task_id": backlog_id,
        "line_instance_id": f"runtime_context:{runtime_context.runtime_context_id}",
        "commit_sha": initial_head,
        "status": "passed",
    }
    stored["completed_lines"].extend(
        [
            {
                **passed_common,
                "stage_id": "worker_attestation",
                "line_id": "worker_finish_time_attestation",
                "actor_role": "mf_sub",
                "evidence_kind": "record_finish_time_worker_attestation",
                "payload": dict(passed_common),
            },
            {
                **passed_common,
                "stage_id": "worker_finish",
                "line_id": "worker_finish_gate",
                "actor_role": "mf_sub",
                "evidence_kind": "mf_subagent_finish_gate",
                "payload": dict(passed_common),
            },
            {
                **passed_common,
                "stage_id": "qa_graph_context",
                "line_id": "qa_graph_context",
                "actor_role": "qa",
                "evidence_kind": "graph_trace",
                "payload": dict(passed_common),
            },
            {
                **passed_common,
                "stage_id": "qa",
                "line_id": "qa_independent_verification",
                "actor_role": "qa",
                "evidence_kind": "independent_verification",
                "authorization_source": "qa_session_token_ref",
                "evidence_owner_role": "qa",
                "observer_impersonation": False,
                "parent_materialization_authorized": False,
                "qa_evidence_provenance": {
                    "schema_version": "qa_evidence_provenance.v1",
                    "authorization_source": "qa_session_token_ref",
                    "evidence_owner_role": "qa",
                    "observer_impersonation": False,
                    "parent_materialization_authorized": False,
                },
                "payload": dict(passed_common),
            },
        ]
    )
    stored["execution_state_revision"] = int(stored["execution_state_revision"]) + 1
    runtime.store.update(successor["contract_execution_id"], stored)
    stored_guide = runtime.current_guide(
        successor["contract_execution_id"],
        actor_role="mf_sub",
    )
    assert stored_guide["next_legal_action"]["line_id"] == "observer_merge"

    runtime_context = upsert_branch_context(
        conn,
        replace(runtime_context, status=STATE_VALIDATED, attempt=1, retry_round=0),
        now_iso="2026-07-19T11:00:00Z",
    )
    qa_principal = "qa:timeline-only-failed-qa"
    snapshot_id = "full-timeline-only-failed-qa"
    _activate_basic_graph(conn, snapshot_id, commit_sha=initial_head)
    qa_scope_binding_ref = server._qa_scope_binding_ref(
        project_id=PID,
        backlog_id=backlog_id,
        task_id=runtime_context.task_id,
        commit_sha=initial_head,
    )
    qa_scope = [
        f"backlog:{backlog_id}",
        f"task:{runtime_context.task_id}",
        f"commit:{initial_head}",
        qa_scope_binding_ref,
    ]
    qa_session = server.role_service.register(
        conn,
        qa_principal,
        PID,
        "qa",
        scope=qa_scope,
    )
    conn.commit()
    qa_graph_ctx = _ctx_with_role(
        {"project_id": PID},
        "qa",
        method="POST",
        body={
            "snapshot_id": "active",
            "tool": "query_schema",
            "query_source": "qa",
            "query_purpose": "independent_verification",
            "backlog_id": backlog_id,
            "task_id": runtime_context.task_id,
            "commit_sha": initial_head,
            "project_root": str(target_root),
        },
    )
    qa_graph_ctx._session.update(
        {
            "session_id": qa_session["session_id"],
            "principal_id": qa_principal,
            "scope": qa_scope,
        }
    )
    qa_graph = server.handle_graph_governance_query(qa_graph_ctx)
    qa_timeline_ctx = _ctx_with_role(
        {"project_id": PID},
        "qa",
        method="POST",
        body={
            "backlog_id": backlog_id,
            "task_id": runtime_context.task_id,
            "event_type": "qa.independent_verification",
            "event_kind": "independent_verification",
            "phase": "verification",
            "status": "failed",
            "actor": qa_principal,
            "commit_sha": initial_head,
            "verification": {
                "result": "failed",
                "verdict": "FAIL",
                "requirement_id": "independent_verification_lane",
            },
            "payload": {
                "runtime_context_id": runtime_context.runtime_context_id,
                "parent_task_id": backlog_id,
                "reviewer_role": "independent_qa",
                "requirement_id": "independent_verification_lane",
                "candidate_new_failures": 0,
                "graph_trace_ids": [qa_graph["trace_id"]],
                "observer_impersonation": False,
            },
        },
    )
    qa_timeline_ctx._session = dict(qa_graph_ctx._session)
    failed_qa = server.handle_task_timeline_append(qa_timeline_ctx)

    passed_qa_body = json.loads(json.dumps(qa_timeline_ctx.body))
    passed_qa_body["status"] = "passed"
    passed_qa_body["verification"].update(
        {
            "result": "passed",
            "verdict": "PASS",
        }
    )
    passed_qa_ctx = _ctx_with_role(
        {"project_id": PID},
        "qa",
        method="POST",
        body=passed_qa_body,
    )
    passed_qa_ctx._session = dict(qa_graph_ctx._session)
    passed_qa = server.handle_task_timeline_append(passed_qa_ctx)
    assert passed_qa["status"] == "passed"
    events_after_pass = task_timeline.list_events(
        conn,
        PID,
        task_id=runtime_context.task_id,
        backlog_id=backlog_id,
        limit=1000,
    )
    assert server._runtime_context_authenticated_failed_qa_timeline_boundary(
        conn=conn,
        context=runtime_context,
        runtime_context_id=runtime_context.runtime_context_id,
        timeline_events=events_after_pass,
    ) == {}
    with pytest.raises(GovernanceError) as closed_after_pass:
        server.handle_graph_governance_runtime_context_session_token_rejoin(
            _ctx_with_role(
                {
                    "project_id": PID,
                    "runtime_context_id": runtime_context.runtime_context_id,
                },
                "coordinator",
                method="POST",
                body={
                    "task_id": runtime_context.task_id,
                    "parent_task_id": backlog_id,
                    "target_project_root": str(target_root),
                    "reason": "Later authenticated QA PASS closes failed-QA recovery",
                    "now_iso": "2999-01-02T23:59:00Z",
                },
            )
        )
    assert closed_after_pass.value.code == "fence_invalidated_or_unknown"
    assert closed_after_pass.value.details["timeline_reopen_for_revision"] is False

    # Only a new authenticated failure can reopen the revision boundary.
    renewed_qa_graph_ctx = _ctx_with_role(
        {"project_id": PID},
        "qa",
        method="POST",
        body=json.loads(json.dumps(qa_graph_ctx.body)),
    )
    renewed_qa_graph_ctx._session = dict(qa_graph_ctx._session)
    qa_graph = server.handle_graph_governance_query(renewed_qa_graph_ctx)
    renewed_failed_qa_body = json.loads(json.dumps(qa_timeline_ctx.body))
    renewed_failed_qa_body["payload"].pop("runtime_context_id", None)
    renewed_failed_qa_body["verification"].pop("runtime_context_id", None)
    renewed_failed_qa_body["payload"]["graph_trace_ids"] = [
        qa_graph["trace_id"]
    ]
    renewed_failed_qa_ctx = _ctx_with_role(
        {"project_id": PID},
        "qa",
        method="POST",
        body=renewed_failed_qa_body,
    )
    renewed_failed_qa_ctx._session = dict(qa_graph_ctx._session)
    failed_qa = server.handle_task_timeline_append(renewed_failed_qa_ctx)
    failed_authority = failed_qa["payload"][
        "source_backed_contract_gate_authority"
    ]
    assert task_timeline._source_backed_qa_session_authority_valid(
        failed_authority,
        conn=conn,
    ) is True
    assert failed_authority["qa_session_proof"]["commit_sha"] == initial_head
    assert "runtime_context_id" not in failed_authority["qa_session_proof"]
    assert "runtime_context_id" not in failed_qa["payload"]
    assert "runtime_context_id" not in failed_qa["verification"]

    before_rejoin_record = runtime.store.get(successor["contract_execution_id"])
    initial_payload = {
        "runtime_context_id": runtime_context.runtime_context_id,
        "task_id": runtime_context.task_id,
        "parent_task_id": backlog_id,
        "worker_id": runtime_context.worker_id,
        "worker_slot_id": runtime_context.worker_slot_id,
        "target_project_root": str(target_root),
        "session_token_ref": runtime_context_session_token_ref(runtime_context),
        "fence_token_hash": runtime_context_secret_hash(
            runtime_context.fence_token
        ),
        "changed_files": ["agent/governance/server.py"],
        "graph_trace_ids": [graph_trace_id],
        "graph_trace_db_evidence": {
            "db_verified": True,
            "verified_trace_ids": [graph_trace_id],
        },
    }

    def assert_invalid_qa_authority_does_not_mutate_runtime():
        before = runtime.store.get(successor["contract_execution_id"])
        events = task_timeline.list_events(
            conn,
            PID,
            task_id=runtime_context.task_id,
            backlog_id=backlog_id,
            limit=1000,
        )
        assert server._runtime_context_authenticated_failed_qa_timeline_boundary(
            conn=conn,
            context=runtime_context,
            runtime_context_id=runtime_context.runtime_context_id,
            timeline_events=events,
        ) == {}
        assert server._runtime_context_revise_failed_qa_implementation_lineage(
            conn,
            project_id=PID,
            context=runtime_context,
            runtime=runtime,
            record=before,
            payload=initial_payload,
            revision_marker={},
        ) == {}
        after = runtime.store.get(successor["contract_execution_id"])
        assert after["execution_state_revision"] == before["execution_state_revision"]
        assert after["completed_lines"] == before["completed_lines"]

    original_failed_payload = json.loads(json.dumps(failed_qa["payload"]))
    explicitly_wrong_runtime_payload = json.loads(
        json.dumps(original_failed_payload)
    )
    explicitly_wrong_runtime_payload["runtime_context_id"] = (
        "mfrctx-explicitly-wrong-runtime"
    )
    conn.execute(
        "UPDATE task_timeline_events SET payload_json = ? WHERE id = ?",
        (json.dumps(explicitly_wrong_runtime_payload), int(failed_qa["id"])),
    )
    conn.commit()
    assert_invalid_qa_authority_does_not_mutate_runtime()
    conn.execute(
        "UPDATE task_timeline_events SET payload_json = ? WHERE id = ?",
        (json.dumps(original_failed_payload), int(failed_qa["id"])),
    )
    conn.commit()

    persisted_runtime_rows = (
        server._runtime_context_project_task_branch_runtime_rows(
            conn,
            project_id=PID,
            task_id=runtime_context.task_id,
        )
    )
    assert len(persisted_runtime_rows) == 1
    persisted_runtime_row = persisted_runtime_rows[0]

    self_reported_runtime_payload = json.loads(json.dumps(original_failed_payload))
    self_reported_runtime_authority = self_reported_runtime_payload[
        "source_backed_contract_gate_authority"
    ]
    self_reported_runtime_authority["qa_session_proof"][
        "runtime_context_id"
    ] = runtime_context.runtime_context_id
    self_reported_runtime_authority["authority_hash"] = (
        task_timeline._canonical_contract_hash(
            {
                key: value
                for key, value in self_reported_runtime_authority.items()
                if key != "authority_hash"
            }
        )
    )
    assert task_timeline._source_backed_qa_session_authority_valid(
        self_reported_runtime_authority,
        conn=conn,
    ) is True
    conn.execute(
        "UPDATE task_timeline_events SET payload_json = ? WHERE id = ?",
        (json.dumps(self_reported_runtime_payload), int(failed_qa["id"])),
    )
    conn.commit()
    with monkeypatch.context() as missing_server_db_binding:
        missing_server_db_binding.setattr(
            server,
            "_runtime_context_project_task_branch_runtime_rows",
            lambda *_args, **_kwargs: [],
        )
        assert_invalid_qa_authority_does_not_mutate_runtime()
    conn.execute(
        "UPDATE task_timeline_events SET payload_json = ? WHERE id = ?",
        (json.dumps(original_failed_payload), int(failed_qa["id"])),
    )
    conn.commit()

    rejected_server_db_bindings = {
        "missing": [],
        "ambiguous": [
            dict(persisted_runtime_row),
            {
                **persisted_runtime_row,
                "runtime_context_id": "mfrctx-ambiguous-runtime",
            },
        ],
        "cross_runtime": [
            {
                **persisted_runtime_row,
                "runtime_context_id": "mfrctx-cross-runtime",
            }
        ],
        "backlog_mismatch": [
            {
                **persisted_runtime_row,
                "backlog_id": "AC-DIFFERENT-BACKLOG",
            }
        ],
        "worktree_mismatch": [
            {
                **persisted_runtime_row,
                "target_project_root": str(target_root / "different-worktree"),
                "worktree_path": str(target_root / "different-worktree"),
            }
        ],
    }
    for case_name, server_db_rows in rejected_server_db_bindings.items():
        with monkeypatch.context() as mismatched_runtime_binding:
            mismatched_runtime_binding.setattr(
                server,
                "_runtime_context_project_task_branch_runtime_rows",
                lambda *_args, _rows=server_db_rows, **_kwargs: json.loads(
                    json.dumps(_rows)
                ),
            )
            assert_invalid_qa_authority_does_not_mutate_runtime()

    tampered_failed_payload = json.loads(json.dumps(original_failed_payload))
    tampered_failed_payload["source_backed_contract_gate_authority"][
        "authority_hash"
    ] = _fake_sha("tampered-timeline-only-qa-authority")
    conn.execute(
        "UPDATE task_timeline_events SET payload_json = ? WHERE id = ?",
        (json.dumps(tampered_failed_payload), int(failed_qa["id"])),
    )
    conn.commit()
    assert_invalid_qa_authority_does_not_mutate_runtime()
    conn.execute(
        "UPDATE task_timeline_events SET payload_json = ? WHERE id = ?",
        (json.dumps(original_failed_payload), int(failed_qa["id"])),
    )
    conn.execute(
        "UPDATE graph_query_traces SET qa_session_id = '' WHERE trace_id = ?",
        (qa_graph["trace_id"],),
    )
    conn.commit()
    assert_invalid_qa_authority_does_not_mutate_runtime()
    conn.execute(
        "UPDATE graph_query_traces SET qa_session_id = ? WHERE trace_id = ?",
        (qa_session["session_id"], qa_graph["trace_id"]),
    )
    conn.commit()
    restored_events = task_timeline.list_events(
        conn,
        PID,
        task_id=runtime_context.task_id,
        backlog_id=backlog_id,
        limit=1000,
    )
    restored_boundary = (
        server._runtime_context_authenticated_failed_qa_timeline_boundary(
            conn=conn,
            context=runtime_context,
            runtime_context_id=runtime_context.runtime_context_id,
            timeline_events=restored_events,
        )
    )
    assert restored_boundary["event_id"] == int(failed_qa["id"])
    assert restored_boundary["runtime_context_binding_server_derived"] is True
    assert restored_boundary["runtime_context_binding_source"] == (
        "server_db_unique_project_task_branch_runtime_context"
    )
    assert restored_boundary["runtime_context_binding"] == {
        "schema_version": "runtime_context.timeline_runtime_binding.v1",
        "source": "server_db_unique_project_task_branch_runtime_context",
        "server_derived": True,
        "runtime_context_id": runtime_context.runtime_context_id,
        "project_id": PID,
        "task_id": runtime_context.task_id,
        "backlog_id": backlog_id,
        "target_project_root": str(target_root.resolve()),
        "qa_scope_binding_ref": qa_scope_binding_ref,
    }

    with pytest.raises(GovernanceError) as missing_rejoin:
        server._runtime_context_revise_failed_qa_implementation_lineage(
            conn,
            project_id=PID,
            context=runtime_context,
            runtime=runtime,
            record=before_rejoin_record,
            payload=initial_payload,
            revision_marker={},
        )
    assert missing_rejoin.value.code == (
        "contract_runtime_rework_lineage_revision_invalid"
    )
    assert "active failed-QA boundary" in str(missing_rejoin.value)

    first_rejoin = server.handle_graph_governance_runtime_context_session_token_rejoin(
        _ctx_with_role(
            {"project_id": PID, "runtime_context_id": runtime_context.runtime_context_id},
            "coordinator",
            method="POST",
            body={
                "task_id": runtime_context.task_id,
                "parent_task_id": backlog_id,
                "target_project_root": str(target_root),
                "reason": f"Revise authenticated timeline failure timeline:{failed_qa['id']}",
                "now_iso": "2999-01-03T00:00:00Z",
            },
        )
    )
    assert first_rejoin["reopen_for_revision"] is True
    assert first_rejoin["timeline_reopen_for_revision"] is True
    assert first_rejoin["attempt"] == 2
    assert first_rejoin["retry_round"] == 1

    first_rejoin_context = get_branch_context(conn, PID, runtime_context.task_id)
    assert first_rejoin_context is not None
    first_rejoin_events = task_timeline.list_events(
        conn,
        PID,
        task_id=runtime_context.task_id,
        backlog_id=backlog_id,
        limit=1000,
    )
    active_failed_qa = (
        server._runtime_context_authenticated_failed_qa_timeline_boundary(
            conn=conn,
            context=first_rejoin_context,
            runtime_context_id=first_rejoin_context.runtime_context_id,
            timeline_events=first_rejoin_events,
        )
    )
    continuity = (
        server._runtime_context_authenticated_failed_qa_rejoin_continuity(
            context=first_rejoin_context,
            runtime_context_id=first_rejoin_context.runtime_context_id,
            timeline_events=first_rejoin_events,
            active_failed_qa=active_failed_qa,
        )
    )
    assert continuity["authoritative_rejoin_event_ref"] == (
        first_rejoin["audit_event_ref"]
    )
    assert continuity["latest_rotation_event_ref"] == (
        first_rejoin["audit_event_ref"]
    )

    latest_event_id = max(int(event.get("id") or 0) for event in first_rejoin_events)
    later_worker_commit = {
        "id": latest_event_id + 1,
        "project_id": PID,
        "backlog_id": backlog_id,
        "task_id": runtime_context.task_id,
        "event_type": "mf_subagent.worker_commit",
        "event_kind": "worker_commit",
        "status": "accepted",
        "payload": {
            "runtime_context_id": runtime_context.runtime_context_id,
            "task_id": runtime_context.task_id,
        },
    }
    assert not server._runtime_context_failed_qa_revision_rejoin_allowed(
        conn=conn,
        context=first_rejoin_context,
        runtime_context_id=first_rejoin_context.runtime_context_id,
        timeline_events=[*first_rejoin_events, later_worker_commit],
    )
    for changed_identity in (
        replace(first_rejoin_context, worker_id="different-worker"),
        replace(first_rejoin_context, fence_token="different-fence"),
        replace(first_rejoin_context, attempt=first_rejoin_context.attempt + 1),
        replace(
            first_rejoin_context,
            target_project_root=str(target_root / "different-worktree"),
        ),
    ):
        assert not server._runtime_context_failed_qa_revision_rejoin_allowed(
            conn=conn,
            context=changed_identity,
            runtime_context_id=changed_identity.runtime_context_id,
            timeline_events=first_rejoin_events,
        )

    projected_contract_failed_qa = {
        "schema_version": (
            "runtime_context.contract_runtime_failed_qa_revision_evidence.v1"
        ),
        "source": "contract_runtime_completed_lines",
        "status": "revision_required",
        "project_id": PID,
        "backlog_id": backlog_id,
        "contract_execution_id": successor["contract_execution_id"],
        "runtime_context_id": runtime_context.runtime_context_id,
        "task_id": runtime_context.task_id,
        "parent_task_id": backlog_id,
        "failed_qa_source_ref": (
            f"contract_runtime:{successor['contract_execution_id']}:"
            "completed_lines:legacy-failed-qa"
        ),
    }

    # Reproduce the frozen live chain: an authoritative timeline rejoin is
    # followed by multiple accepted auth-only rotations from an older server
    # that preserved overall CR reopen but lost timeline reopen authority.
    legacy_rotations = []
    with monkeypatch.context() as legacy_runtime:
        legacy_runtime.setattr(
            server,
            "_runtime_context_failed_qa_revision_rejoin_allowed",
            lambda **_kwargs: False,
        )
        legacy_runtime.setattr(
            server,
            "_runtime_context_failed_qa_revision_contract_runtime_evidence",
            lambda *_args, **_kwargs: dict(projected_contract_failed_qa),
        )
        for index in range(2):
            legacy_rotations.append(
                server.handle_graph_governance_runtime_context_session_token_rejoin(
                    _ctx_with_role(
                        {
                            "project_id": PID,
                            "runtime_context_id": runtime_context.runtime_context_id,
                        },
                        "coordinator",
                        method="POST",
                        body={
                            "task_id": runtime_context.task_id,
                            "parent_task_id": backlog_id,
                            "target_project_root": str(target_root),
                            "reason": f"Legacy auth-only rotation #{index + 1}",
                            "now_iso": f"2999-01-03T00:0{index + 1}:00Z",
                        },
                    )
                )
            )
    assert all(item["reopen_for_revision"] is True for item in legacy_rotations)
    assert all(
        item["timeline_reopen_for_revision"] is False
        for item in legacy_rotations
    )
    assert all(item["attempt"] == 2 for item in legacy_rotations)
    assert all(item["retry_round"] == 1 for item in legacy_rotations)

    # The next server revision continues the historical timeline authority,
    # while the newly accepted event becomes the strict current-session marker.
    with monkeypatch.context() as projected_runtime:
        projected_runtime.setattr(
            server,
            "_runtime_context_failed_qa_revision_contract_runtime_evidence",
            lambda *_args, **_kwargs: dict(projected_contract_failed_qa),
        )
        rejoin = server.handle_graph_governance_runtime_context_session_token_rejoin(
            _ctx_with_role(
                {
                    "project_id": PID,
                    "runtime_context_id": runtime_context.runtime_context_id,
                },
                "coordinator",
                method="POST",
                body={
                    "task_id": runtime_context.task_id,
                    "parent_task_id": backlog_id,
                    "target_project_root": str(target_root),
                    "reason": "Continue frozen authenticated failed-QA revision",
                    "now_iso": "2999-01-03T00:03:00Z",
                },
            )
        )
    assert rejoin["reopen_for_revision"] is True
    assert rejoin["timeline_reopen_for_revision"] is True
    assert rejoin["previous_status"] == STATE_WORKTREE_READY
    assert rejoin["current_status"] == STATE_WORKTREE_READY
    assert rejoin["attempt"] == first_rejoin["attempt"] == 2
    assert rejoin["retry_round"] == first_rejoin["retry_round"] == 1
    assert rejoin["worker_id"] == first_rejoin["worker_id"]
    assert rejoin["worker_slot_id"] == first_rejoin["worker_slot_id"]
    assert rejoin["fence_token_hash"] == first_rejoin["fence_token_hash"]
    assert rejoin["session_token_ref"] != legacy_rotations[-1]["session_token_ref"]
    second_rejoin_event_id = int(rejoin["audit_event_id"])
    second_rejoin_row = conn.execute(
        "SELECT payload_json FROM task_timeline_events WHERE id = ?",
        (second_rejoin_event_id,),
    ).fetchone()
    second_rejoin_audit = json.loads(second_rejoin_row["payload_json"])
    assert second_rejoin_audit["reopen_for_revision"] is True
    assert second_rejoin_audit["timeline_reopen_for_revision"] is True
    assert second_rejoin_audit["attempt"] == 2
    assert second_rejoin_audit["retry_round"] == 1

    auth_rotated_context = get_branch_context(conn, PID, runtime_context.task_id)
    assert auth_rotated_context is not None
    auth_rotated_marker = server._runtime_context_failed_qa_revision_rejoin_marker(
        conn=conn,
        context=auth_rotated_context,
        runtime_context_id=auth_rotated_context.runtime_context_id,
        timeline_events=task_timeline.list_events(
            conn,
            PID,
            task_id=auth_rotated_context.task_id,
            backlog_id=backlog_id,
            limit=1000,
        ),
    )
    assert auth_rotated_marker["revision_event_ref"] == (
        f"timeline:{second_rejoin_event_id}"
    )
    assert auth_rotated_marker["reopen_authority_source"] == (
        "failed_qa_timeline_event"
    )
    assert auth_rotated_marker["failed_qa_source_ref"] == (
        f"timeline:{failed_qa['id']}"
    )
    assert auth_rotated_marker["failed_qa_source"] == (
        "server_qa_session_verification"
    )
    assert auth_rotated_marker["session_token_ref_rotation"][
        "active_session_token_ref"
    ] == rejoin["session_token_ref"]

    candidate.write_text("timeline-only failed QA revision\n", encoding="utf-8")
    subprocess.run(
        ["git", "add", "agent/governance/server.py"],
        cwd=target_root,
        check=True,
    )
    subprocess.run(
        ["git", "commit", "-m", "timeline-only failed QA revision"],
        cwd=target_root,
        check=True,
        capture_output=True,
        text=True,
    )
    revised_head = batch_jobs.git_commit(target_root)
    saved_context = get_branch_context(conn, PID, runtime_context.task_id)
    assert saved_context is not None
    revision_marker = server._runtime_context_failed_qa_revision_rejoin_marker(
        conn=conn,
        context=saved_context,
        runtime_context_id=saved_context.runtime_context_id,
        timeline_events=task_timeline.list_events(
            conn,
            PID,
            task_id=saved_context.task_id,
            backlog_id=backlog_id,
            limit=1000,
        ),
    )
    assert revision_marker["failed_qa_source_ref"] == f"timeline:{failed_qa['id']}"
    assert revision_marker["failed_qa_source"] == "server_qa_session_verification"

    revision_payload = {
        **initial_payload,
        "session_token_ref": rejoin["session_token_ref"],
        "fence_token_hash": runtime_context_secret_hash(rejoin["fence_token"]),
        "head_commit": revised_head,
    }
    revision_before_negative_cases = runtime.store.get(
        successor["contract_execution_id"]
    )["execution_state_revision"]
    commit_mismatch_record = json.loads(
        json.dumps(runtime.store.get(successor["contract_execution_id"]))
    )
    prior_canonical_implementation = server._worker_commit_completed_implementation(
        commit_mismatch_record,
        runtime_context_id=runtime_context.runtime_context_id,
        task_id=runtime_context.task_id,
    )
    assert prior_canonical_implementation is not None
    assert initial_head != base_commit
    prior_canonical_implementation["commit_sha"] = base_commit
    with pytest.raises(GovernanceError) as mismatched_qa_commit:
        server._runtime_context_revise_failed_qa_implementation_lineage(
            conn,
            project_id=PID,
            context=saved_context,
            runtime=runtime,
            record=commit_mismatch_record,
            payload=revision_payload,
            revision_marker=revision_marker,
        )
    assert mismatched_qa_commit.value.code == (
        "contract_runtime_rework_lineage_revision_invalid"
    )
    assert "superseded canonical worker implementation commit" in str(
        mismatched_qa_commit.value
    )
    assert runtime.store.get(successor["contract_execution_id"])[
        "execution_state_revision"
    ] == revision_before_negative_cases

    fallback_negative_cases = {}
    for case_name in (
        "missing_worker_commit",
        "lineage_missing",
        "lineage_mismatch",
        "lineage_conflicting_canonical_first_value",
        "runtime_mismatch",
        "task_mismatch",
        "multiple_different_commits",
        "non_full_commit",
        "nested_commit_only",
        "top_level_commit_missing",
    ):
        case_record = json.loads(
            json.dumps(runtime.store.get(successor["contract_execution_id"]))
        )
        case_implementation = server._worker_commit_completed_implementation(
            case_record,
            runtime_context_id=runtime_context.runtime_context_id,
            task_id=runtime_context.task_id,
        )
        assert case_implementation is not None
        assert not case_implementation.get("commit_sha")
        case_implementation_index = next(
            index
            for index, line in enumerate(case_record["completed_lines"])
            if line is case_implementation or line == case_implementation
        )
        case_worker_commit_index = next(
            index
            for index in range(
                case_implementation_index + 1,
                len(case_record["completed_lines"]),
            )
            if case_record["completed_lines"][index].get("line_id")
            == "worker_commit"
        )
        case_worker_commit = case_record["completed_lines"][
            case_worker_commit_index
        ]
        if case_name == "missing_worker_commit":
            # Even matching nested implementation/client/timeline/runtime-head
            # values are not a substitute for the canonical worker_commit line.
            case_implementation["payload"]["commit_sha"] = initial_head
            case_implementation["payload"]["head_commit"] = initial_head
            case_record["completed_lines"].pop(case_worker_commit_index)
        elif case_name == "lineage_missing":
            case_worker_commit.pop("implementation_lineage_ref", None)
            case_worker_commit["payload"].pop(
                "implementation_lineage_ref",
                None,
            )
            case_worker_commit["payload"].pop(
                "worker_implementation_lineage",
                None,
            )
        elif case_name == "lineage_mismatch":
            wrong_lineage_ref = (
                "contract-runtime:worker-implementation:"
                + _fake_sha(case_name)
            )
            case_worker_commit["payload"][
                "implementation_lineage_ref"
            ] = wrong_lineage_ref
            case_worker_commit["payload"][
                "worker_implementation_lineage"
            ]["implementation_lineage_ref"] = wrong_lineage_ref
        elif case_name == "lineage_conflicting_canonical_first_value":
            case_worker_commit["payload"][
                "implementation_lineage_ref"
            ] = (
                "contract-runtime:worker-implementation:"
                + _fake_sha(case_name)
            )
        elif case_name == "runtime_mismatch":
            case_worker_commit["runtime_context_id"] = "mfrctx-other-runtime"
        elif case_name == "task_mismatch":
            case_worker_commit["task_id"] = "other-worker-task"
        elif case_name == "multiple_different_commits":
            conflicting_worker_commit = json.loads(
                json.dumps(case_worker_commit)
            )
            conflicting_worker_commit["commit_sha"] = base_commit
            case_record["completed_lines"].append(conflicting_worker_commit)
        elif case_name == "non_full_commit":
            case_worker_commit["commit_sha"] = initial_head[:12]
        elif case_name == "nested_commit_only":
            case_worker_commit.pop("commit_sha", None)
            case_worker_commit["payload"]["commit_sha"] = initial_head
        elif case_name == "top_level_commit_missing":
            case_worker_commit.pop("commit_sha", None)
            case_worker_commit["payload"].pop("commit_sha", None)
        fallback_negative_cases[case_name] = case_record

    for case_name, case_record in fallback_negative_cases.items():
        with pytest.raises(GovernanceError) as rejected:
            server._runtime_context_revise_failed_qa_implementation_lineage(
                conn,
                project_id=PID,
                context=saved_context,
                runtime=runtime,
                record=case_record,
                payload={
                    **revision_payload,
                    "prior_implementation_commit": initial_head,
                },
                revision_marker=revision_marker,
            )
        assert rejected.value.code == (
            "contract_runtime_rework_lineage_revision_invalid"
        ), case_name
        assert "superseded canonical worker implementation commit" in str(
            rejected.value
        ), case_name
        assert runtime.store.get(successor["contract_execution_id"])[
            "execution_state_revision"
        ] == revision_before_negative_cases

    negative_cases = {
        "wrong_source": ({**revision_marker, "failed_qa_source": "caller_claim"}, revision_payload),
        "stale_session": (
            {
                **revision_marker,
                "session_token_ref_rotation": {
                    **revision_marker["session_token_ref_rotation"],
                    "active_session_token_ref": initial_payload["session_token_ref"],
                },
            },
            revision_payload,
        ),
        "wrong_fence": (
            {
                **revision_marker,
                "session_token_ref_rotation": {
                    **revision_marker["session_token_ref_rotation"],
                    "fence_token_hash": _fake_sha("wrong-timeline-only-fence"),
                },
            },
            revision_payload,
        ),
        "wrong_head": (
            revision_marker,
            {**revision_payload, "head_commit": initial_head},
        ),
    }
    for case_name, (case_marker, case_payload) in negative_cases.items():
        with pytest.raises(GovernanceError) as rejected:
            server._runtime_context_revise_failed_qa_implementation_lineage(
                conn,
                project_id=PID,
                context=saved_context,
                runtime=runtime,
                record=runtime.store.get(successor["contract_execution_id"]),
                payload=case_payload,
                revision_marker=case_marker,
            )
        assert rejected.value.code == (
            "contract_runtime_rework_lineage_revision_invalid"
        ), case_name
        assert runtime.store.get(successor["contract_execution_id"])[
            "execution_state_revision"
        ] == revision_before_negative_cases

    def mutation_state():
        record = runtime.store.get(successor["contract_execution_id"])
        events = task_timeline.list_events(
            conn,
            PID,
            task_id=runtime_context.task_id,
            backlog_id=backlog_id,
            limit=1000,
        )
        return {
            "execution_state_revision": record["execution_state_revision"],
            "completed_lines": json.loads(
                json.dumps(record["completed_lines"])
            ),
            "timeline_event_ids": [int(event["id"]) for event in events],
        }

    prevalidation_before = mutation_state()
    prevalidation = (
        server._runtime_context_revise_failed_qa_implementation_lineage(
            conn,
            project_id=PID,
            context=saved_context,
            runtime=runtime,
            record=runtime.store.get(successor["contract_execution_id"]),
            payload=revision_payload,
            revision_marker={},
        )
    )
    assert prevalidation["status"] == (
        "validated_timeline_boundary_submission"
    )
    prevalidated_marker = prevalidation["canonical_payload"][
        "failed_qa_revision_rejoin_marker"
    ]
    assert prevalidated_marker == revision_marker
    assert mutation_state() == prevalidation_before

    original_projection = (
        server._contract_runtime_apply_mf_parallel_context_projection
    )
    original_revision_helper = (
        server._runtime_context_revise_failed_qa_implementation_lineage
    )

    def projection_without_runtime_rejoin(*args, **kwargs):
        projected, projection = original_projection(*args, **kwargs)
        projection = json.loads(json.dumps(projection))
        projection["failed_qa_revision_rejoin_contexts"] = []
        return projected, projection

    def corrected_implementation_request():
        return server.handle_graph_governance_runtime_context_implementation_evidence(
            _ctx_with_role(
                {
                    "project_id": PID,
                    "runtime_context_id": runtime_context.runtime_context_id,
                },
                "mf_sub",
                method="POST",
                body={
                    "parent_task_id": backlog_id,
                    "fence_token": rejoin["fence_token"],
                    "session_token": rejoin["session_token"],
                    "target_project_root": str(target_root),
                    "changed_files": ["agent/governance/server.py"],
                    "graph_trace_ids": [graph_trace_id],
                    "tests": [
                        {"command": "pytest -q", "status": "passed"}
                    ],
                    "payload": {
                        "failed_qa_event_ref": f"timeline:{failed_qa['id']}",
                        "candidate_new_failures": 0,
                    },
                },
            )
        )

    replaced_marker_replays = []

    def replace_second_stage_marker(*args, **kwargs):
        supplied_marker = dict(kwargs.get("revision_marker") or {})
        if supplied_marker:
            replaced_marker_replays.append(dict(supplied_marker))
            kwargs = dict(kwargs)
            kwargs["revision_marker"] = {
                **supplied_marker,
                "revision_event_ref": "timeline:replaced-marker",
            }
        return original_revision_helper(*args, **kwargs)

    before_replaced_marker = mutation_state()
    with monkeypatch.context() as replaced_marker:
        replaced_marker.setattr(
            server,
            "_contract_runtime_apply_mf_parallel_context_projection",
            projection_without_runtime_rejoin,
        )
        replaced_marker.setattr(
            server,
            "_runtime_context_revise_failed_qa_implementation_lineage",
            replace_second_stage_marker,
        )
        with pytest.raises(GovernanceError) as invalid_replay_marker:
            corrected_implementation_request()
    assert invalid_replay_marker.value.code == (
        "contract_runtime_rework_lineage_revision_invalid"
    )
    assert replaced_marker_replays == [revision_marker]
    assert mutation_state() == before_replaced_marker

    replay_rejections = []

    def reject_second_stage_after_cas(*args, **kwargs):
        supplied_marker = dict(kwargs.get("revision_marker") or {})
        result = original_revision_helper(*args, **kwargs)
        if supplied_marker and result.get("status") == "revised":
            replay_rejections.append(dict(supplied_marker))
            return {**result, "status": "rejected", "canonical": False}
        return result

    before_second_stage_rejection = mutation_state()
    with monkeypatch.context() as rejected_replay:
        rejected_replay.setattr(
            server,
            "_contract_runtime_apply_mf_parallel_context_projection",
            projection_without_runtime_rejoin,
        )
        rejected_replay.setattr(
            server,
            "_runtime_context_revise_failed_qa_implementation_lineage",
            reject_second_stage_after_cas,
        )
        with pytest.raises(GovernanceError) as second_stage_rejected:
            corrected_implementation_request()
    assert second_stage_rejected.value.code == (
        "contract_runtime_rework_lineage_revision_replay_rejected"
    )
    assert replay_rejections == [revision_marker]
    assert mutation_state() == before_second_stage_rejection

    replay_markers = {"derived": [], "supplied": []}

    def record_exact_marker_replay(*args, **kwargs):
        supplied_marker = dict(kwargs.get("revision_marker") or {})
        result = original_revision_helper(*args, **kwargs)
        if supplied_marker:
            replay_markers["supplied"].append(supplied_marker)
        elif result.get("status") == (
            "validated_timeline_boundary_submission"
        ):
            replay_markers["derived"].append(
                dict(
                    result["canonical_payload"][
                        "failed_qa_revision_rejoin_marker"
                    ]
                )
            )
        return result

    before_corrected = mutation_state()
    with monkeypatch.context() as projection_gap:
        projection_gap.setattr(
            server,
            "_contract_runtime_apply_mf_parallel_context_projection",
            projection_without_runtime_rejoin,
        )
        projection_gap.setattr(
            server,
            "_runtime_context_revise_failed_qa_implementation_lineage",
            record_exact_marker_replay,
        )
        corrected = corrected_implementation_request()
    assert replay_markers["derived"] == [revision_marker, revision_marker]
    assert replay_markers["supplied"] == [revision_marker]
    canonical = corrected["contract_runtime_canonical_line"]
    assert canonical["status"] == "revised"
    assert canonical["commit_sha"] == revised_head
    assert canonical["failed_qa_source_ref"] == f"timeline:{failed_qa['id']}"
    assert canonical["append_only_history_preserved"] is True
    assert canonical["supersedes_implementation_lineage_ref"]
    assert canonical["next_legal_action"]["line_id"] == "worker_commit"
    superseded_commit_authority = canonical[
        "superseded_implementation_commit_authority"
    ]
    assert superseded_commit_authority["commit_sha"] == initial_head
    assert superseded_commit_authority["source"] == (
        "ContractRuntime.completed_lines.worker_commit.commit_sha"
    )
    assert superseded_commit_authority[
        "implementation_completed_line_index"
    ] == prior_implementation_index
    assert superseded_commit_authority[
        "worker_commit_completed_line_indices"
    ] == [prior_worker_commit_index]
    assert superseded_commit_authority["errors"] == []

    revised_record = runtime.store.get(successor["contract_execution_id"])
    assert revised_record["execution_state_revision"] == (
        before_corrected["execution_state_revision"] + 1
    )
    assert len(revised_record["completed_lines"]) == (
        len(before_corrected["completed_lines"]) + 2
    )
    boundary_line, implementation_line = revised_record["completed_lines"][-2:]
    assert boundary_line["line_id"] == "qa_independent_verification"
    assert boundary_line["status"] == "failed"
    assert boundary_line["payload"]["source_ref"] == f"timeline:{failed_qa['id']}"
    assert boundary_line["qa_evidence_provenance"]["schema_version"] == (
        "qa_evidence_provenance.v1"
    )
    assert implementation_line["line_id"] == "worker_implementation"
    assert implementation_line["commit_sha"] == revised_head

    lineage = _worker_implementation_lineage(revised_record, implementation_line)
    worker_commit = server.handle_graph_governance_runtime_context_worker_commit(
        _ctx_with_role(
            {"project_id": PID, "runtime_context_id": runtime_context.runtime_context_id},
            "mf_sub",
            method="POST",
            body={
                "contract_execution_id": successor["contract_execution_id"],
                "runtime_context_id": runtime_context.runtime_context_id,
                "task_id": runtime_context.task_id,
                "parent_task_id": backlog_id,
                "fence_token": rejoin["fence_token"],
                "session_token": rejoin["session_token"],
                "target_project_root": str(target_root),
                "worker_commit_sha": revised_head,
                "worker_session_id": runtime_context.worker_slot_id,
                "filer_principal": runtime_context.worker_slot_id,
                "implementation_lineage_ref": lineage["implementation_lineage_ref"],
                "owned_files": ["agent/governance/server.py"],
                "changed_files": ["agent/governance/server.py"],
                "graph_trace_ids": [graph_trace_id],
            },
        )
    )
    assert worker_commit["ok"] is True
    assert worker_commit["contract_runtime_close_evidence_gate"]["accepted"] is True
    assert worker_commit["next_legal_action"] == (
        "record_finish_time_worker_attestation"
    )


def test_runtime_context_session_token_rejoin_keeps_validated_worker_closed_without_failed_qa(
    conn,
    tmp_path,
):
    target_root = tmp_path / "runtime-token-rejoin-no-failed-qa"
    target_root.mkdir()
    context = upsert_branch_context(
        conn,
        BranchTaskRuntimeContext(
            project_id=PID,
            governance_project_id=PID,
            target_project_id=PID,
            target_project_root=str(target_root),
            task_id="worker-runtime-rejoin-no-failed-qa",
            root_task_id="parent-runtime-rejoin-no-failed-qa",
            backlog_id="AC-RUNTIME-TOKEN-REJOIN-NO-FAILED-QA",
            stage_task_id="worker-runtime-rejoin-no-failed-qa",
            worker_id="worker-runtime-rejoin-no-failed-qa",
            worker_slot_id="slot-runtime-rejoin-no-failed-review",
            branch_ref="refs/heads/codex/worker-runtime-rejoin-no-failed-qa",
            status=STATE_VALIDATED,
            fence_token="fence-runtime-rejoin-no-failed-qa",
            session_token_hash=mf_subagent_session_token_hash("lost-runtime-token"),
        ),
    )
    for event_kind, event_type, phase in (
        ("mf_subagent_read_receipt", "mf_subagent.read_receipt", "read_receipt"),
        ("mf_subagent_startup", "mf_subagent.startup", "startup"),
    ):
        task_timeline.record_event(
            conn,
            project_id=PID,
            task_id=context.task_id,
            backlog_id=context.backlog_id,
            event_type=event_type,
            event_kind=event_kind,
            phase=phase,
            status="accepted",
            actor=context.worker_slot_id,
            payload={
                "runtime_context_id": context.runtime_context_id,
                "task_id": context.task_id,
                "parent_task_id": context.root_task_id,
                "worker_role": "mf_sub",
                "worker_slot_id": context.worker_slot_id,
                "worker_session_id": context.worker_slot_id,
                "read_receipt_hash": "sha256:runtime-rejoin-no-failed-qa-read",
            },
        )
    conn.commit()

    with pytest.raises(GovernanceError) as blocked:
        server.handle_graph_governance_runtime_context_session_token_rejoin(
            _ctx_with_role(
                {"project_id": PID, "runtime_context_id": context.runtime_context_id},
                "coordinator",
                method="POST",
                body={
                    "task_id": context.task_id,
                    "parent_task_id": context.root_task_id,
                    "target_project_root": str(target_root),
                    "reason": "host worker session lost raw auth env after resume",
                },
            )
        )

    assert blocked.value.code == "fence_invalidated_or_unknown"
    assert blocked.value.details["context_status"] == STATE_VALIDATED
    assert blocked.value.details["reopen_for_revision"] is False

    ready_context = upsert_branch_context(
        conn,
        replace(
            context,
            status=STATE_WORKTREE_READY,
            attempt=2,
            retry_round=1,
            last_recovery_action="mf_subagent_failed_qa_revision_rejoin_issued",
        ),
        now_iso="2026-07-20T11:50:00Z",
    )
    auth_rotations = []
    for index in range(2):
        auth_rotations.append(
            server.handle_graph_governance_runtime_context_session_token_rejoin(
                _ctx_with_role(
                    {
                        "project_id": PID,
                        "runtime_context_id": ready_context.runtime_context_id,
                    },
                    "coordinator",
                    method="POST",
                    body={
                        "task_id": ready_context.task_id,
                        "parent_task_id": ready_context.root_task_id,
                        "target_project_root": str(target_root),
                        "reason": (
                            "auth-only rotation without active authenticated "
                            f"failed QA #{index + 1}"
                        ),
                        "now_iso": f"2999-01-04T00:0{index}:00Z",
                    },
                )
            )
        )
    first_rotation, second_rotation = auth_rotations
    assert first_rotation["reopen_for_revision"] is False
    assert first_rotation["timeline_reopen_for_revision"] is False
    assert second_rotation["reopen_for_revision"] is False
    assert second_rotation["timeline_reopen_for_revision"] is False
    assert second_rotation["attempt"] == first_rotation["attempt"] == 2
    assert second_rotation["retry_round"] == first_rotation["retry_round"] == 1
    assert second_rotation["session_token_ref"] != first_rotation["session_token_ref"]
    second_rotation_row = conn.execute(
        "SELECT payload_json FROM task_timeline_events WHERE id = ?",
        (int(second_rotation["audit_event_id"]),),
    ).fetchone()
    second_rotation_audit = json.loads(second_rotation_row["payload_json"])
    assert second_rotation_audit["reopen_for_revision"] is False
    assert second_rotation_audit["timeline_reopen_for_revision"] is False


