def test_mf_parallel_close_authority_selects_current_recovery_before_stale_last_record(
):
    close_commit = "a149e8bdf9b100f28fb5843f61ef83ed82618f18"
    worker_commit = "b149e8bdf9b100f28fb5843f61ef83ed82618f18"
