def test_contract_update_blocked_precheck_continues_with_audited_bypass(conn):
    backlog_id = "AC-CONTRACT-UPDATE-BLOCKED-DIRECT-FIX"
    _insert_source_backed_onboarding_backlog(conn, backlog_id)
    onboard = server.handle_project_onboard_contract_start(
        _ctx_with_role(
            {"project_id": PID},
            "observer",
            method="POST",
            body={
                "backlog_id": backlog_id,
                "route_token_ref": "rtok-contract-update-direct-onboard",
            },
        )
    )
    _complete_source_backed_onboarding(
        conn,
        onboard["contract_execution_id"],
    )
    started = server.handle_project_contract_update_start(
        _ctx_with_role(
            {"project_id": PID},
            "observer",
            method="POST",
            body={
                "backlog_id": backlog_id,
                "route_token_ref": "rtok-contract-update-direct",
            },
        )
    )
    execution_id = started["contract_execution_id"]

    for actor_role, stage_id, line_id, evidence_kind in [
        (
            "observer",
            "observer_request",
            "observer_request_contract_update",
            "contract_update_request",
        ),
        (
            "mf_sub",
            "worker_previous_source",
            "worker_previous_source_proof",
            "contract_previous_source_proof",
        ),
    ]:
        result = server.handle_project_contract_update_line_write(
            _ctx_with_role(
                {"project_id": PID, "contract_execution_id": execution_id},
                actor_role,
                method="POST",
                body={
                    "stage_id": stage_id,
                    "line_id": line_id,
                    "evidence_kind": evidence_kind,
                },
            )
        )
        assert result["ok"] is True

    blocked_precheck = server.handle_project_contract_update_line_write(
        _ctx_with_role(
            {"project_id": PID, "contract_execution_id": execution_id},
            "mf_sub",
            method="POST",
            body={
                "stage_id": "worker_precheck",
                "line_id": "worker_revision_precheck",
                "evidence_kind": "contract_revision_precheck",
                "payload": {
                    "status": "blocked",
                    "recommended_next_action": "direct_fix_successor",
                    "blocker_class": (
                        "runtime_merge_queue_requires_raw_fence_after_worker_finish"
                    ),
                    "block_reason": "merge queue raw fence needs runtime repair",
                },
            },
        )
    )
    assert blocked_precheck["ok"] is True

    current = server.handle_project_contract_update_current_state(
        _ctx_with_role(
            {"project_id": PID, "contract_execution_id": execution_id},
            "mf_sub",
            method="GET",
        )
    )
    next_action = current["next_legal_action"]
    assert next_action["id"] == "worker_revision_source_proof"
    assert next_action["action"] == "continue_with_audited_bypass"
    assert next_action["mode"] == "resume_original_contract"
    assert next_action["status"] == "proceeded_with_exception"
    assert next_action["line_id"] == "worker_revision_source_proof"
    assert next_action["original_contract_action"] == (
        "record_contract_revision_source_proof"
    )
    assert next_action["blocked_by_line"]["line_id"] == "worker_revision_precheck"
    assert next_action["blocked_by_line"]["payload"]["status"] == "blocked"
    assert next_action["diagnostic_required"] is True
    assert next_action["no_pass_claim"] is True
    assert next_action["source_row_must_remain_open"] is True
    assert next_action["direct_fix_required"] is False
    assert next_action["current_line_blocker_policy"]["action"] == (
        "contract_runtime_bypass_line"
    )
    assert next_action["endpoint"].endswith(f"/{execution_id}/line-writes")
    assert next_action["body"]["stage_id"] == "worker_source"
    assert next_action["body"]["line_id"] == "worker_revision_source_proof"
    assert next_action["body"]["evidence_kind"] == (
        "contract_revision_source_proof"
    )
    assert next_action["body"]["runtime_guide_hash"] == next_action[
        "writer_role_safe_copy_payload"
    ]["copy_payload"]["runtime_guide_hash"]
    assert "recommended_successor_contract_id" not in next_action
    assert "successor_contract_template_id" not in next_action

    continued = server.handle_project_contract_update_line_write(
        _ctx_with_role(
            {"project_id": PID, "contract_execution_id": execution_id},
            "mf_sub",
            method="POST",
            body={
                "stage_id": "worker_source",
                "line_id": "worker_revision_source_proof",
                "evidence_kind": "contract_revision_source_proof",
            },
        )
    )
    assert continued["ok"] is True
    assert continued["next_legal_action"]["id"] == (
        "worker_runtime_visibility_proof"
    )


def test_direct_fix_enter_accepts_mf_parallel_failed_qa_parent(conn):
    backlog_id = "AC-MF-PARALLEL-FAILED-QA-DIRECT-FIX"
    _insert_source_backed_onboarding_backlog(conn, backlog_id)
    onboard = server.handle_project_onboard_contract_start(
        _ctx_with_role(
            {"project_id": PID},
            "observer",
            method="POST",
            body={
                "backlog_id": backlog_id,
                "route_token_ref": "rtok-mf-parallel-failed-qa-direct-fix",
            },
        )
    )
    _complete_source_backed_onboarding(
        conn,
        onboard["contract_execution_id"],
    )
    successor = server.handle_project_mf_parallel_enter(
        _ctx_with_role(
            {"project_id": PID},
            "observer",
            method="POST",
            body={
                "actor": "operator",
                "reason": "Start mf_parallel lane for failed QA direct-fix test.",
                "backlog_id": backlog_id,
                "task_id": "mf-parallel-failed-qa-parent",
                "route_token_ref": "rtok-mf-parallel-failed-qa-direct-fix",
                "worker_fence": {
                    "fence_token": "fence-mf-parallel-failed-qa-direct-fix",
                    "owned_files": ["agent/governance/server.py"],
                },
                "owned_files": ["agent/governance/server.py"],
            },
        )
    )
    runtime = server._contract_runtime(conn)
    execution_id = successor["contract_execution_id"]
    implementation_payload, worker_commit_payload = (
        _mf_parallel_worker_proof_payloads(
            SimpleNamespace(
                runtime_context_id="mfrctx-mf-parallel-failed-qa-direct-fix",
                task_id="worker-mf-parallel-failed-qa-direct-fix",
                worker_id="worker-mf-parallel-failed-qa-direct-fix",
                worker_slot_id="worker-mf-parallel-failed-qa-direct-fix",
                target_project_root="/tmp/mf-parallel-failed-qa-direct-fix",
                fence_token="fence-mf-parallel-failed-qa-direct-fix",
            ),
            parent_task_id=backlog_id,
            graph_trace_id="gqt-mf-parallel-failed-qa-direct-fix",
            head_commit="c" * 40,
            implementation_event_ref="contract_runtime:worker_implementation",
        )
    )

    def submit_line(actor_role, stage_id, line_id, evidence_kind, payload=None):
        runtime.current_guide(execution_id, actor_role=actor_role)
        record = runtime.store.get(execution_id)
        write = server._contract_runtime_write_from_record(
            record,
            actor_role=actor_role,
            stage_id=stage_id,
            line_id=line_id,
            evidence_kind=evidence_kind,
        )
        effective_payload = payload
        if line_id == "worker_implementation":
            effective_payload = implementation_payload
        elif line_id == "worker_commit":
            effective_payload = worker_commit_payload
            write["commit_sha"] = "c" * 40
        if effective_payload is not None:
            write["payload"] = effective_payload
            write.update(effective_payload)
        result = runtime.submit_line_write(execution_id, write, actor_role=actor_role)
        assert result["ok"] is True
        return result["record"]

    for actor_role, stage_id, line_id, evidence_kind in [
        (
            "observer",
            "orchestration",
            "observer_prefill_child_contracts",
            "contract_binding",
        ),
        (
            "observer",
            "dispatch",
            "observer_dispatch_bounded_workers",
            "dispatch_bounded_worker",
        ),
        ("mf_sub", "worker_read", "worker_read_runtime_guide", "read_receipt"),
        ("mf_sub", "worker_startup", "worker_startup", "mf_subagent_startup"),
        ("mf_sub", "worker_context", "worker_graph_context", "graph_trace"),
            ("mf_sub", "worker_implementation", "worker_implementation", "implementation"),
            ("mf_sub", "worker_commit", "worker_commit", "worker_commit"),
            (
            "mf_sub",
            "worker_attestation",
            "worker_finish_time_attestation",
            "record_finish_time_worker_attestation",
        ),
        ("mf_sub", "worker_finish", "worker_finish_gate", "mf_subagent_finish_gate"),
        ("mf_sub", "qa_handoff", "worker_review_ready_handoff", "review_ready"),
    ]:
        if not runtime.pinned_definition_has_line(execution_id, line_id):
            continue
        submit_line(actor_role, stage_id, line_id, evidence_kind)

    submit_line(
        "qa",
        "qa",
        "qa_independent_verification",
        "independent_verification",
        payload={
            "summary": (
                "Independent QA failed the worker commit because route-token "
                "refs minted before scope persistence cannot renew."
            )
        },
    )

    current = runtime.current_guide(execution_id, actor_role="observer")
    assert current["next_legal_action"]["line_id"] == "worker_read_runtime_guide"

    entered = server.handle_project_direct_fix_enter(
        _ctx_with_role(
            {"project_id": PID},
            "observer",
            method="POST",
            body={
                "actor": "operator",
                "reason": "Repair failed QA blocker in mf_parallel parent.",
                "backlog_id": backlog_id,
                "task_id": "mf-parallel-failed-qa-direct-fix",
                "parent_contract_execution_id": execution_id,
                "route_token_ref": "rtok-mf-parallel-failed-qa-direct-fix",
            },
        )
    )

    assert entered["contract_id"] == server.DIRECT_FIX_CONTRACT_ID
    assert entered["parent_contract_execution_id"] == execution_id
    assert entered["next_legal_action"]["line_id"] == "direct_fix_operator_approval"
    assert entered["return_to_parent"]["return_to_line_id"] == (
        "qa_independent_verification"
    )
    assert entered["return_to_parent"]["blocked_gate"] == "independent_verification"


