def test_runtime_context_read_receipt_rolls_back_contract_when_timeline_write_fails(
    conn,
    tmp_path,
    monkeypatch,
):
    backlog_id = "AC-CONTRACT-CANONICAL-READ-ROLLBACK"
    worker_task_id = "contract-canonical-read-rollback-worker"
