def test_contract_runtime_mf_sub_missing_worker_proof_reports_required_fields(conn):
    backlog_id = "AC-CONTRACT-RUNTIME-MISSING-WORKER-PROOF"
    successor, _runtime_context = _setup_mf_parallel_contract_runtime_worker_dispatch(
        conn,
        backlog_id=backlog_id,
        task_id="missing-worker-proof-parent",
        worker_task_id="missing-worker-proof-worker",
        fence_token="fence-missing-worker-proof",
        token="missing-worker-proof-token",
    )

    with pytest.raises(PermissionDeniedError) as exc:
        server.handle_project_contract_runtime_current_state(
            _ctx_with_role(
                {
                    "project_id": PID,
                    "contract_execution_id": successor["contract_execution_id"],
                },
                "mf_sub",
            )
        )

    details = exc.value.details
    assert details["proof_error"] == "missing_worker_proof_fields"
    assert set(details["missing_required_fields"]) == {
        "runtime_context_id",
        "session_token_ref",
        "parent_task_id",
        "target_project_root",
    }
    assert details["required_role"] == "mf_sub"
    bridge_guidance = details["mf_sub_host_bridge_guidance"]
    assert bridge_guidance["blocked_action"] == "contract_runtime_current"
    assert bridge_guidance["next_action"]["action"] == (
        "allocate_or_read_worker_runtime_context_before_submit_line"
    )
    assert "parallel_branch_allocate" in bridge_guidance["next_action"]["tools"]
    assert "runtime_context_worker_guide" in bridge_guidance["next_action"]["tools"]
    assert "runtime_context_session_token_initial_join" in bridge_guidance[
        "next_action"
    ]["tools"]
    assert "runtime_context_session_token_reissue" in bridge_guidance["next_action"][
        "tools"
    ]
    assert "runtime_context_session_token_rejoin" in bridge_guidance["next_action"][
        "tools"
    ]
    assert bridge_guidance["observer_body_actor_role_policy"][
        "body_actor_role_is_authorization"
    ] is False
    assert bridge_guidance["host_subagent_identity_policy"][
        "requires_runtime_context_bridge"
    ] is True
    assert bridge_guidance["host_subagent_identity_policy"][
        "session_token_ref_alone_authorizes_writes"
    ] is False
    host_envelope = bridge_guidance["worker_host_envelope_handoff"]
    assert host_envelope["delivery"] == "worker_host_envelope"
    assert host_envelope["initial_join"]["tool"] == (
        "runtime_context_session_token_initial_join"
    )
    assert host_envelope["rejoin"]["tool"] == "runtime_context_session_token_rejoin"
    capacity_guidance = bridge_guidance["capacity_fallback_guidance"]
    assert capacity_guidance == host_envelope["capacity_fallback_guidance"]
    assert capacity_guidance["official_fallback_options"] == [
        "reuse_existing_idle_subagent_same_runtime_envelope",
        "queue_dispatch_until_capacity_available",
        "stop_and_record_capacity_blocker",
    ]
    assert "change_runtime_identity_to_work_around_capacity" in capacity_guidance[
        "forbidden_shortcuts"
    ]


def test_contract_runtime_worker_line_attaches_verified_mf_sub_provenance(conn):
    backlog_id = "AC-CONTRACT-RUNTIME-WORKER-LINE-PROVENANCE"
    fence_token = "fence-worker-line-provenance"
    worker_token = "worker-line-provenance-token"
    successor, runtime_context = _setup_mf_parallel_contract_runtime_worker_dispatch(
        conn,
        backlog_id=backlog_id,
        task_id="worker-line-provenance-parent",
        worker_task_id="worker-line-provenance-worker",
        fence_token=fence_token,
        token=worker_token,
    )
    session_ref = runtime_context_session_token_ref(runtime_context)

    worker_read = server.handle_project_contract_runtime_line_write(
        _ctx(
            {"project_id": PID, "contract_execution_id": successor["contract_execution_id"]},
            method="POST",
            body={
                "runtime_context_id": runtime_context.runtime_context_id,
                "task_id": runtime_context.task_id,
                "parent_task_id": backlog_id,
                "worker_role": "mf_sub",
                "fence_token": fence_token,
                "session_token_ref": session_ref,
                "target_project_root": runtime_context.target_project_root,
                "stage_id": "worker_read",
                "line_id": "worker_read_runtime_guide",
                "evidence_kind": "read_receipt",
                "payload": {
                    "schema_version": "mf_parallel.worker_read_receipt.v1",
                    "runtime_context_id": runtime_context.runtime_context_id,
                    "task_id": runtime_context.task_id,
                },
            },
        )
    )

    assert worker_read["ok"] is True
    assert worker_read["actor_role"] == "mf_sub"
    stored = server._contract_runtime_store(conn).get(successor["contract_execution_id"])
    worker_line = stored["completed_lines"][-1]
    assert worker_line["actor_role"] == "mf_sub"
    assert worker_line["observer_impersonation"] is False
    assert worker_line["authorization_source"] == (
        "runtime_context_copy_safe_worker_proof"
    )
    assert worker_line["evidence_owner_role"] == "mf_sub"
    provenance = worker_line["payload"]["worker_evidence_provenance"]
    assert provenance["source"] == "runtime_context_copy_safe_worker_proof"
    assert provenance["runtime_context_id"] == runtime_context.runtime_context_id
    assert provenance["session_token_ref"] == session_ref
    assert provenance["worker_owned"] is True
    assert provenance["observer_impersonation"] is False
    stored_json = json.dumps(worker_line, sort_keys=True)
    assert fence_token not in stored_json
    assert worker_token not in stored_json


def test_mf_parallel_enter_source_backed_returns_successor_runtime_shape(conn):
    backlog_id = "AC-MF-PARALLEL-SOURCE-BACKED-SUCCESSOR"
    task_id = "parallel-source-backed-task"
    _insert_simple_mf_close_backlog(conn, backlog_id)
    started = server.handle_project_onboard_contract_start(
        _ctx_with_role(
            {"project_id": PID},
            "observer",
            method="POST",
            body={
                "backlog_id": backlog_id,
                "route_token_ref": "rtok-mf-parallel-root",
            },
        )
    )
    parent_record = _complete_source_backed_onboarding(
        conn,
        started["contract_execution_id"],
    )

    result = server.handle_project_mf_parallel_enter(
        _ctx_with_role(
            {"project_id": PID},
            "observer",
            method="POST",
            body={
                "actor": "operator",
                "actor_role": "qa",
                "reason": "Human approved parallel worker repair.",
                "backlog_id": backlog_id,
                "task_id": task_id,
                "route_token_ref": "rtok-mf-parallel-root",
                "worker_fence": {
                    "fence_token": "fence-parallel-source-backed",
                    "owned_files": ["agent/governance/server.py"],
                },
                "owned_files": ["agent/governance/server.py"],
            },
        )
    )

    assert result["ok"] is True
    assert result["schema_version"] == "mf_parallel_enter.runtime_contract_response.v1"
    assert result["successor_contract_execution_id"] == result["contract_execution_id"]
    assert result["parent_contract_execution_id"] == parent_record["contract_execution_id"]
    assert result["root_contract_execution_id"] == parent_record["root_contract_execution_id"]
    assert result["contract_chain_id"] == parent_record["contract_chain_id"]
    assert (
        result["runtime_guide"]["contract"]["contract_id"]
        == server.MF_PARALLEL_CONTRACT_ID
    )
    assert (
        result["contract_runtime_current_state"]["contract_id"]
        == server.MF_PARALLEL_CONTRACT_ID
    )
    assert result["execution_state_revision"] == 1
    assert result["route_token_ref"] == "rtok-mf-parallel-root"
    merge_route_scope = result["merge_route_scope_guidance"]
    assert merge_route_scope["successor_contract_execution_id"] == (
        result["successor_contract_execution_id"]
    )
    assert merge_route_scope["root_contract_execution_id"] == (
        result["root_contract_execution_id"]
    )
    assert merge_route_scope["worker_task_id"] == task_id
    assert merge_route_scope["worker_task_id_role"] == (
        "primary merge materialize/apply close_or_merge_after_evidence "
        "route authorization"
    )
    assert merge_route_scope["successor_contract_execution_id_role"] == (
        "current child mf_parallel contract runtime writes only"
    )
    current_contract_issue_shape = merge_route_scope[
        "close_or_merge_after_evidence_route_issue_shape"
    ]
    assert current_contract_issue_shape["task_id"] == task_id
    assert current_contract_issue_shape["allowed_actions"] == [
        "close_or_merge_after_evidence"
    ]
    assert current_contract_issue_shape["raw_route_token_required"] is False
    assert current_contract_issue_shape["raw_route_token_exposed"] is False
    assert merge_route_scope["primary_close_or_merge_route_scope"] == (
        "worker_task_id"
    )
    assert merge_route_scope["accepted_route_scope_order"] == [
        "worker_task_id",
        "runtime_context_root_task_id_fallback",
    ]
    fallback_issue_shape = merge_route_scope[
        "fallback_close_or_merge_after_evidence_route_issue_shape"
    ]
    assert fallback_issue_shape["task_id"] == result["root_contract_execution_id"]
    assert merge_route_scope["copy_safe_route_token_ref_only"] is True
    assert merge_route_scope["copy_safe_primary_route_token_ref_field"] == (
        "route_token_ref"
    )
    assert merge_route_scope["raw_route_token_copy_allowed"] is False
    assert merge_route_scope["raw_route_token_persisted"] is False
    assert merge_route_scope["merge_materialize_apply_route_scope_source"] == (
        "runtime_context.current_values.task_id"
    )
    assert merge_route_scope[
        "merge_materialize_apply_merge_queue_id_source"
    ] == "runtime_context.current_values.merge_queue_id"
    assert (
        merge_route_scope["newly_issued_route_token_merge_queue_id_allowed"]
        is False
    )
    assert (
        merge_route_scope["do_not_copy_merge_queue_id_from_route_token_issue_payload"]
        is True
    )
    assert merge_route_scope["root_contract_scope_fallback_only"] is True
    assert (
        merge_route_scope["successor_contract_scope_for_merge_materialize_apply"]
        is False
    )
    assert merge_route_scope["copy_safe_route_token_scope"]["scope"]["task_id"] == task_id
    assert (
        merge_route_scope["copy_safe_route_token_scope"][
            "raw_route_token_copy_allowed"
        ]
        is False
    )
    assert merge_route_scope["copy_safe_route_token_scope"][
        "observer_route_context_issue_payload"
    ]["task_id"] == task_id
    assert result["event"]["payload"]["successor_contract"][
        "merge_route_scope_guidance"
    ] == merge_route_scope
    assert result["route_token_ref_guidance"]["merge_route_scope_guidance"] == (
        merge_route_scope
    )
    assert result["next_legal_action"]["id"] == "observer_prefill_child_contracts"
    assert result["next_legal_action"]["source"] == "contract_runtime"
    assert result["next_legal_action"]["evidence_kind"] == "contract_binding"
