    def count_key(value, key):
        if isinstance(value, dict):
            return sum(
                (1 if item_key == key else 0) + count_key(child, key)
                for item_key, child in value.items()
            )
        if isinstance(value, list):
            return sum(count_key(item, key) for item in value)
        return 0

