def test_mf_parallel_enter_accepts_onboard_service_waiver_parent(conn):
    backlog_id = "AC-MF-PARALLEL-ONBOARD-SERVICE-WAIVER"
    _insert_simple_mf_close_backlog(conn, backlog_id)
    conn.execute(
        "UPDATE backlog_bugs SET test_files = ? WHERE bug_id = ?",
        (json.dumps(["agent/tests/test_graph_governance_api.py"]), backlog_id),
    )
    conn.commit()
    observer_session_id = _insert_active_observer_session_ref(
        conn,
        session_id="obs-mf-parallel-onboard-service",
    )
    service_parent = server._onboard_service_execution_id(PID, backlog_id)
    parent_issue = observer_route_context.issue_observer_write_route_context(
        project_id=PID,
        backlog_id=backlog_id,
        task_id=service_parent,
        target_files=["agent/governance/server.py"],
        allowed_actions=["mf_parallel_enter", "onboard_route_guide"],
    )
    route_token_ref = parent_issue["route_token_ref"]
    observer_route_context.persist_route_token_ref(
        conn,
        project_id=PID,
        route_token_ref=route_token_ref,
        token=parent_issue["route_token"],
    )

    result = server.handle_project_mf_parallel_enter(
        _ctx(
            {"project_id": PID},
            method="POST",
            body={
                "backlog_id": backlog_id,
                "reason": "Human approved row-scoped parallel work through onboard service.",
                "task_id": "parallel-onboard-service-task",
                "observer_session_id": observer_session_id,
                "observer_route_token_ref": route_token_ref,
                "onboard_service_waiver": True,
                "owned_files": ["agent/governance/server.py"],
            },
        )
    )

    assert result["ok"] is True
    assert result["parent_contract_execution_id"] == service_parent
    assert result["root_contract_execution_id"] == service_parent
    assert result["event"]["payload"]["owned_files"] == [
        "agent/governance/server.py",
        "agent/tests/test_graph_governance_api.py",
    ]
    assert result["event"]["payload"]["target_files"] == [
        "agent/governance/server.py",
        "agent/tests/test_graph_governance_api.py",
    ]
    assert result["event"]["payload"]["legacy_onboard_contract_waived"] is True
    assert result["next_legal_action"]["id"] == "observer_prefill_child_contracts"
    child_ref = result["route_token_ref"]
    assert child_ref.startswith("rtok-")
    assert child_ref != route_token_ref
    assert result["route_token_ref_guidance"]["child_route_token_ref"] == child_ref
    assert result["route_token_ref_guidance"]["parent_route_token_ref"] == route_token_ref
    assert result["route_token_ref_guidance"]["pass_ref_to_next_runtime_write"] is True
    assert result["next_legal_action"]["route_token_ref"] == child_ref

    resolved_child = observer_route_context.resolve_route_token_ref(
        conn,
        project_id=PID,
        route_token_ref=child_ref,
        backlog_id=backlog_id,
        task_id=result["contract_execution_id"],
    )
    assert resolved_child is not None
    assert "contract_runtime_submit_line" in resolved_child["allowed_actions"]
    assert resolved_child["scope"]["task_id"] == result["contract_execution_id"]
    assert resolved_child["parent_route_lineage"]["route_token_ref"] == route_token_ref

    guide = server.handle_project_onboard_route_guide(
        _ctx(
            {"project_id": PID},
            method="POST",
            body={
                "backlog_id": backlog_id,
                "role": "worker",
                "work_type": "parallel_worker",
                "route_token_ref": route_token_ref,
            },
        )
    )
    guide_next = guide["next_legal_action"]
    guide_ref = guide["agent_onboard_guidance"]["route_token_ref_guidance"]
    assert guide_next["contract_execution_id"] == result["contract_execution_id"]
    assert guide_next["route_token_ref"] == child_ref
    assert guide_next["route_token_ref_status"] == "current_contract_scope_verified"
    assert guide_next["source_of_authority"] == "contract_runtime"
    assert guide_next["authority_decision_source"] == "backlog_contract_chain_current"
    assert guide_next["legacy_route_action_precheck_advisory"]["required"] is False
    assert guide_next["legacy_route_action_precheck_advisory"][
        "ignored_as_next_legal_action"
    ] is True
    assert guide_ref["current_route_token_ref"] == child_ref
    assert guide_ref["target_contract_execution_id"] == result["contract_execution_id"]
    assert guide_ref["pass_to_next_runtime_writes_as"] == [
        "observer_route_token_ref",
        "route_token_ref",
    ]
    assert guide_ref["observer_session_route_token_checklist"]["ordered_steps"][1][
        "heartbeat_interval_sec"
    ] == 300
    assert (
        guide_ref["observer_session_route_token_checklist"]["identity_boundaries"][
            "route_token_ref"
        ]
        != guide_ref["observer_session_route_token_checklist"]["identity_boundaries"][
            "observer_session_id"
        ]
    )
    current = guide["contract_chain_current"]
    assert current["source_of_authority"] == "contract_runtime"
    assert current["authority_projection"]["required_next_action_id"] == (
        "observer_prefill_child_contracts"
    )
    assert current["legacy_route_action_precheck_advisory"]["advisory_only"] is True
    assert current["legacy_route_action_precheck_advisory"][
        "authorization_blocker"
    ] is False

    root = server._observer_root_route_context_state(
        conn,
        PID,
        backlog_id=backlog_id,
        task_id=result["contract_execution_id"],
        work_mode=observer_session.WORK_MODE_EXECUTION_SUPERVISOR,
        route_token_ref=child_ref,
        caller_graph_query_schema_trace_id="gqt-20260630-currentchild",
    )
    root_next = root["next_legal_action"]
    assert root_next["id"] == "observer_prefill_child_contracts"
    assert root_next["source"] == "backlog_contract_chain_current"
    assert root_next["source_of_authority"] == "contract_runtime"
    assert root_next["authority_decision_source"] == "backlog_contract_chain_current"
    assert root["contract_runtime_authority_projection"][
        "required_next_action_id"
    ] == "observer_prefill_child_contracts"
    legacy = root["legacy_route_action_precheck_advisory"]
    assert legacy["id"] == "route_action_precheck"
    assert legacy["advisory_only"] is True
    assert legacy["required"] is False
    assert legacy["authorization_blocker"] is False
    assert root["next_legal_action_deferred_by_contract_runtime_current"]["id"] != (
        "route_action_precheck"
    )
    assert guide["runtime_resume"]["authority_preference"]["stale_compact_ledger_authoritative"] is False


def test_onboard_route_guide_marks_onboard_service_ref_enter_only_for_mf_parallel_current(
    conn,
):
    backlog_id = "AC-ONBOARD-ROUTE-GUIDE-MF-PARENT-REF-ENTER-ONLY"
    _insert_simple_mf_close_backlog(conn, backlog_id)
    parent_execution_id = server._onboard_service_execution_id(PID, backlog_id)
    parent_issue = observer_route_context.issue_observer_write_route_context(
        project_id=PID,
        backlog_id=backlog_id,
        task_id=parent_execution_id,
        target_files=["agent/governance/server.py"],
        allowed_actions=["onboard_route_guide", "mf_parallel_enter"],
    )
    parent_ref = parent_issue["route_token_ref"]
    observer_route_context.persist_route_token_ref(
        conn,
        project_id=PID,
        route_token_ref=parent_ref,
        token=parent_issue["route_token"],
    )
    parent_record = server._onboard_service_materialize_parent_record(
        conn,
        project_id=PID,
        backlog_id=backlog_id,
        route_token_ref=parent_ref,
    )
    child_execution_id = server._mf_parallel_execution_id(
        PID,
        backlog_id,
        parent_execution_id,
        "parallel-route-token-scope-gap",
    )
    runtime = server._contract_runtime(conn)
    runtime.start_execution(
        server.MF_PARALLEL_CONTRACT_ID,
        project_id=PID,
        backlog_id=backlog_id,
        actor_role="observer",
        contract_execution_id=child_execution_id,
        parent_contract_execution_id=parent_execution_id,
        root_contract_execution_id=parent_execution_id,
        contract_chain_id=parent_record["contract_chain_id"],
        route_token_ref=parent_ref,
        role_binding={
            "observer": "observer",
            "mf_sub": "mf_sub",
            "qa": "qa",
            "binding_source": "test_unsafe_parent_ref_projection",
        },
        backlog_lineage={
            "project_id": PID,
            "backlog_id": backlog_id,
            "task_id": "parallel-route-token-scope-gap",
        },
    )
    runtime.current_guide(child_execution_id, actor_role="observer")
    child_record = runtime.store.get(child_execution_id)
    server.upsert_contract_chain_successor_binding(
        conn,
        parent_record=parent_record,
        child_record=child_record,
        edge_kind="mf_parallel_child",
        binding_kind="mf_parallel_child_current",
    )

    response = server.handle_project_onboard_route_guide(
        _ctx(
            {"project_id": PID},
            method="POST",
            body={
                "backlog_id": backlog_id,
                "role": "worker",
                "work_type": "parallel_worker",
                "route_token_ref": parent_ref,
            },
        )
    )

    next_action = response["next_legal_action"]
    guidance = response["agent_onboard_guidance"]["route_token_ref_guidance"]
    issue_payload = guidance["observer_route_context_issue_payload"]
    assert next_action["contract_execution_id"] == child_execution_id
    assert next_action["route_token_ref"] == ""
    assert next_action["route_token_ref_status"] == (
        "issue_required_for_current_contract_runtime"
    )
    assert next_action["enter_only_route_token_ref"] == parent_ref
    assert guidance["current_route_token_ref"] == ""
    assert guidance["current_ref_present"] is False
    assert guidance["enter_only_route_token_ref"] == parent_ref
    assert guidance["target_contract_execution_id"] == child_execution_id
    assert guidance["pass_to_next_runtime_writes_as"] == []
    assert issue_payload["task_id"] == child_execution_id
    assert issue_payload["parent_route_token_ref"] == parent_ref
    assert "contract_runtime_submit_line" in issue_payload["allowed_actions"]
    assert response["runtime_resume"]["next_legal_action"]["route_token_ref"] == ""
    assert response["onboard_route_guide"]["backlog_chain_binding"]["continue"][
        "next_legal_action"
    ]["route_token_ref"] == ""


def test_mf_batch_parallel_enter_returns_row_scoped_fanout_plan(
    conn,
    monkeypatch,
):
    backlog_id = "AC-MF-BATCH-PARALLEL-ROUTE"
    child_a = "AC-MF-BATCH-PARALLEL-ROW-A"
    child_b = "AC-MF-BATCH-PARALLEL-ROW-B"
    for row_id in (backlog_id, child_a, child_b):
        _insert_simple_mf_close_backlog(conn, row_id)
    conn.execute(
        "UPDATE backlog_bugs SET target_files = ?, test_files = ?, priority = ? WHERE bug_id = ?",
        (
            json.dumps(["agent/governance/server.py"]),
            json.dumps(["agent/tests/test_graph_governance_api.py"]),
            "P1",
            child_a,
        ),
    )
    conn.execute(
        "UPDATE backlog_bugs SET target_files = ?, test_files = ?, priority = ? WHERE bug_id = ?",
        (
            json.dumps(["agent/governance/parallel_branch_runtime.py"]),
            json.dumps(["agent/tests/test_parallel_branch_read_model.py"]),
            "P0",
            child_b,
        ),
    )
    conn.commit()
    observer_session_id = _insert_active_observer_session_ref(
        conn,
        session_id="obs-mf-batch-parallel",
    )
    route_token_ref = "rtok-mf-batch-parallel"
    _persist_contract_runtime_observer_route_ref(
        conn,
        backlog_id=backlog_id,
        contract_execution_id="",
        route_token_ref=route_token_ref,
        allowed_actions=["mf_batch_parallel_enter"],
    )

    result = server.handle_project_mf_batch_parallel_enter(
        _ctx(
            {"project_id": PID},
            method="POST",
            body={
                "backlog_id": backlog_id,
                "backlog_ids": [child_a, child_b],
                "reason": "Human approved multi-row fan-out through onboard service.",
                "task_id": "batch-parallel-onboard-service",
                "observer_session_id": observer_session_id,
                "observer_route_token_ref": route_token_ref,
                "onboard_service_waiver": True,
                "target_head_commit": "target-head-1",
                "graph_snapshot_id": "scope-target-head-1",
            },
        )
    )

    service_parent = server._onboard_service_execution_id(PID, backlog_id)
    assert result["ok"] is True
    assert result["contract_template_id"] == "mf_batch_parallel.v1"
    assert result["parent_contract_execution_id"] == service_parent
    assert result["root_contract_execution_id"] == service_parent
    assert result["preflight_gate"]["status"] == "passed"
    assert result["preflight_gate"]["fanout_ready"] is True
    assert result["preflight_gate"]["target_head_commit"] == "target-head-1"
    assert result["merge_queue_plan"]["planner_only"] is False
    assert result["merge_queue_plan"]["durable_queue_write"] is True
    assert result["merge_queue_plan"]["durable_queue_item_count"] == 2
    assert [item["backlog_id"] for item in result["merge_queue_plan"]["planned_items"]] == [
        child_b,
        child_a,
    ]
    assert result["merge_queue_plan"]["planned_items"][0]["owned_files"] == [
        "agent/governance/parallel_branch_runtime.py",
        "agent/tests/test_parallel_branch_read_model.py",
    ]
    assert result["merge_queue_plan"]["planned_items"][1]["owned_files"] == [
        "agent/governance/server.py",
        "agent/tests/test_graph_governance_api.py",
    ]
    persisted_items = list_merge_queue_items(
        conn,
        PID,
        result["merge_queue_plan"]["merge_queue_id"],
    )
    assert [item.task_id for item in persisted_items] == [
        result["merge_queue_plan"]["planned_items"][0]["task_id"],
        result["merge_queue_plan"]["planned_items"][1]["task_id"],
    ]
    assert [item.backlog_id for item in persisted_items] == [child_b, child_a]
    assert [item.current_target_head for item in persisted_items] == [
        "target-head-1",
        "target-head-1",
    ]
    assert [item["backlog_id"] for item in result["per_row_successors"]] == [
        child_a,
        child_b,
    ]
    assert all(
        item["requires_distinct_route_token_ref"]
        and item["route_token_task_id_policy"] == "mf_parallel_successor_execution_id"
        and item["merge_queue"]["merge_queue_id"] == result["merge_queue_plan"]["merge_queue_id"]
        and item["merge_queue"]["queue_item_id"]
        for item in result["per_row_successors"]
    )
    payload = result["event"]["payload"]
    assert payload["legacy_onboard_contract_waived"] is True
    assert payload["preflight_gate"]["preflight_hash"] == result["preflight_gate"][
        "preflight_hash"
    ]
    assert payload["fanout_policy"]["preflight_gate_required"] is True
    assert payload["fanout_policy"]["fanout_ready"] is True
    assert payload["fanout_policy"]["shared_backlog_close_token_allowed"] is False
    assert payload["fanout_policy"]["successor_contract_template_id"] == "mf_parallel.v2"

    # A materialized batch runtime context remains on the existing batch
    # authority path.  The stricter mf_parallel durable-merge projection must
    # not be applied merely because both lanes share branch runtime storage.
    batch_item = result["merge_queue_plan"]["planned_items"][0]
    batch_context = upsert_branch_context(
        conn,
        BranchTaskRuntimeContext(
            project_id=PID,
            task_id=batch_item["task_id"],
            backlog_id=batch_item["backlog_id"],
            parent_task_id=result["batch_id"],
            branch_ref=f"refs/heads/codex/{batch_item['task_id']}",
            status=STATE_WORKTREE_READY,
            worktree_path=f"/tmp/{batch_item['task_id']}",
            base_commit="a" * 40,
            target_head_commit="a" * 40,
            merge_queue_id=result["merge_queue_plan"]["merge_queue_id"],
        ),
    )
    append_branch_contract_revision(
        conn,
        batch_context,
        revision_id="crev-mf-batch-current-full-non-regression",
        contract_version=server.MF_BATCH_PARALLEL_CONTRACT_ID,
        payload={
            "contract_id": server.MF_BATCH_PARALLEL_RECORD_CONTRACT_ID,
            "batch_id": result["batch_id"],
        },
        actor="observer",
    )
    conn.commit()
    monkeypatch.setattr(
        server,
        "_current_full_reconcile_contract_merge_authority",
        lambda *_args, **_kwargs: (_ for _ in ()).throw(
            AssertionError(
                "mf_batch_parallel must retain its existing batch authority path"
            )
        ),
    )

    assert server._current_full_reconcile_runtime_successor_contract_kind(
        conn,
        project_id=PID,
        context=batch_context,
    ) == "mf_batch_parallel"
    batch_scope = server._current_full_reconcile_runtime_context_scope(
        conn,
        project_id=PID,
        body={
            "backlog_id": batch_context.backlog_id,
            "task_id": batch_context.task_id,
            "merge_queue_id": batch_context.merge_queue_id,
        },
        auth={
            "role_source": "observer_session_route_token_ref",
            "route_token_scope": {
                "project_id": PID,
                "backlog_id": batch_context.backlog_id,
                "task_id": batch_context.task_id,
            },
            "route_token_allowed_actions": [
                "graph_current_full_reconcile"
            ],
        },
        target_commit_sha="a" * 40,
    )

    assert batch_scope["runtime_context_id"] == (
        runtime_context_id_for_branch_context(batch_context)
    )
    assert "contract_merge_authority" not in batch_scope


def test_observer_route_context_issue_blocks_multi_backlog_task_mismatch(conn):
    expected_backlog_id = "AC-MULTI-BINDING-EXPECTED"
    wrong_backlog_id = "AC-MULTI-BINDING-WRONG"
    task_id = "mf-batch-parallel-test:row:4"
    upsert_merge_queue_items(
        conn,
        [
            MergeQueueItem(
                project_id=PID,
                merge_queue_id="mq-multi-binding",
                queue_item_id="mqitem-row-4",
                backlog_id=expected_backlog_id,
                task_id=task_id,
                branch_ref="",
                queue_index=4,
                status="planned",
                target_ref="refs/heads/main",
                base_commit="base",
                validated_target_head="base",
                current_target_head="base",
            )
        ],
    )

    status, payload = server.handle_observer_route_context_issue(
        _ctx(
            {"project_id": PID},
            method="POST",
            body={
                "caller_role": "observer",
                "backlog_id": wrong_backlog_id,
                "task_id": task_id,
                "target_files": ["agent/governance/server.py"],
                "allowed_actions": ["task_timeline_append"],
            },
        )
    )

    assert status == 409
    assert payload["error"] == "task_backlog_binding_mismatch"
    assert payload["expected_backlog_id"] == expected_backlog_id
    assert payload["received_backlog_id"] == wrong_backlog_id
    assert payload["task_id"] == task_id
    assert payload["merge_queue_id"] == "mq-multi-binding"
    assert payload["queue_index"] == 4


def test_task_timeline_append_blocks_multi_backlog_task_mismatch(conn):
    expected_backlog_id = "AC-MULTI-TIMELINE-EXPECTED"
    wrong_backlog_id = "AC-MULTI-TIMELINE-WRONG"
